import { EquipmentItem } from '../types/inventory';
import { Equipment, EquipmentRarity, EquipmentType, EquipmentStats } from '../models/Equipment';
import { MASTERY_THRESHOLDS } from '../config/mastery-config';

const mapSubCategoryToType = (subCat: string): EquipmentType => {
    return subCat as EquipmentType; 
};

/**
 * 상향 조정된 레벨별 누적 경험치 테이블
 * 아이템 품질(약 100)이 그대로 경험치가 되므로 요구량을 대폭 늘림
 */
export const LEVEL_EXP_TABLE = [
    0,      // Lv 1
    500,    // Lv 2 (약 5번 제작)
    1200,   // Lv 3
    2200,   // Lv 4
    3500,   // Lv 5 (Tier 2 Unlock)
    5200,   // Lv 6
    7500,   // Lv 7
    10500,  // Lv 8
    14500,  // Lv 9
    20000,  // Lv 10 (Tier 3 Unlock)
    27000,  // Lv 11
    36000,  // Lv 12
    47000,  // Lv 13
    60000,  // Lv 14
    75000,  // Lv 15
    95000   // Lv 16 (Tier 4 Unlock)
];

export function getSmithingLevel(exp: number): number {
  let level = 1;
  for (let i = 0; i < LEVEL_EXP_TABLE.length; i++) {
    if (exp >= LEVEL_EXP_TABLE[i]) level = i + 1;
  }
  return level;
}

export function getUnlockedTier(level: number): number {
  if (level >= 16) return 4;
  if (level >= 10) return 3;
  if (level >= 5) return 2;
  return 1;
}

export function calcCraftExp(args: {
  tier: number;
  quality01: number;      // 0~1 (Internal multiplier, will use quality value instead)
  isQuickCraft: boolean;
  isFirstCraft: boolean;
  quality?: number;       // The actual quality value (0-120)
}): number {
  const { quality = 0, isQuickCraft } = args;

  // 제작된 아이템의 퀄리티를 그대로 경험치로 반환
  // 퀵 크래프트(간이 제작)시에는 효율이 50%로 감소
  const baseExp = quality;
  const quickMult = isQuickCraft ? 0.5 : 1.0;

  return Math.round(baseExp * quickMult);
}

export const getEnergyCost = (item: EquipmentItem, masteryCount: number): number => {
    let cost = 20; 
    if (masteryCount >= MASTERY_THRESHOLDS.ARTISAN) {
        cost -= MASTERY_THRESHOLDS.ARTISAN_BONUS.energyDiscount;
    }
    return Math.max(5, cost);
};

export const generateEquipment = (recipe: EquipmentItem, quality: number, masteryCount: number, enhancementCount: number = 0): Equipment => {
    let statMultiplier = 1.0;
    let priceMultiplier = 1.0;
    let namePrefix = '';

    if (masteryCount >= MASTERY_THRESHOLDS.ARTISAN) {
        statMultiplier = MASTERY_THRESHOLDS.ARTISAN_BONUS.stats;
        priceMultiplier = MASTERY_THRESHOLDS.ARTISAN_BONUS.price;
        namePrefix = MASTERY_THRESHOLDS.ARTISAN_BONUS.prefix;
    } else if (masteryCount >= MASTERY_THRESHOLDS.ADEPT) {
        statMultiplier = MASTERY_THRESHOLDS.ADEPT_BONUS.stats;
        priceMultiplier = MASTERY_THRESHOLDS.ADEPT_BONUS.price;
        namePrefix = MASTERY_THRESHOLDS.ADEPT_BONUS.prefix;
    }

    const qualityMultiplier = Math.max(0.2, quality / 100); 
    const finalMultiplier = qualityMultiplier * statMultiplier;

    const base = recipe.baseStats || { physicalAttack: 0, physicalDefense: 0, magicalAttack: 0, magicalDefense: 0 };

    const stats: EquipmentStats = {
        physicalAttack: Math.round(base.physicalAttack * finalMultiplier),
        physicalDefense: Math.round(base.physicalDefense * finalMultiplier),
        magicalAttack: Math.round(base.magicalAttack * finalMultiplier),
        magicalDefense: Math.round(base.magicalDefense * finalMultiplier),
        // 주능력치 보너스 매핑 (템플릿 수치 고정 적용)
        ...(base.str !== undefined && { str: base.str }),
        ...(base.vit !== undefined && { vit: base.vit }),
        ...(base.dex !== undefined && { dex: base.dex }),
        ...(base.int !== undefined && { int: base.int }),
        ...(base.luk !== undefined && { luk: base.luk }),
    };

    const statKeys = ['physicalAttack', 'physicalDefense', 'magicalAttack', 'magicalDefense'] as const;
    for (let i = 0; i < enhancementCount; i++) {
        const randomKey = statKeys[Math.floor(Math.random() * statKeys.length)];
        const currentVal = stats[randomKey];
        if (currentVal !== undefined) {
            stats[randomKey] = Math.round(currentVal * 1.02);
        }
    }

    const rarityScore = quality + (enhancementCount * 2);

    let rarity = EquipmentRarity.COMMON;
    if (rarityScore >= 125) rarity = EquipmentRarity.LEGENDARY; 
    else if (rarityScore >= 110) rarity = EquipmentRarity.EPIC;  
    else if (rarityScore >= 95) rarity = EquipmentRarity.RARE;
    else if (rarityScore >= 75) rarity = EquipmentRarity.UNCOMMON;

    const price = Math.round(recipe.baseValue * finalMultiplier * priceMultiplier * (1 + enhancementCount * 0.05));

    return {
        id: `${recipe.id}_${Date.now()}_${Math.floor(Math.random() * 1000)}`,
        recipeId: recipe.id,
        name: namePrefix ? `${namePrefix} ${recipe.name}` : recipe.name,
        type: mapSubCategoryToType(recipe.subCategoryId),
        quality: quality,
        rarity: rarity,
        price: price,
        icon: recipe.icon,
        image: recipe.image,
        description: recipe.description,
        stats: stats,
        enhancementCount,
        specialAbilities: [], 
        durability: recipe.maxDurability, 
        maxDurability: recipe.maxDurability,
        isRepairable: recipe.isRepairable,
        minLevel: recipe.minLevel,
        craftedDate: Date.now(),
        crafterName: 'Lockhart',
        previousOwners: [], 
        slotType: recipe.slotType,
        isTwoHanded: recipe.isTwoHanded
    };
};

import { GameState } from '../../types/index';
import { Equipment, EquipmentSlotType } from '../../models/Equipment';
import { mergePrimaryStats } from '../../models/Stats';

export const handleEquipItem = (state: GameState, payload: { mercenaryId: string; inventoryItemId: string }): GameState => {
    const { mercenaryId, inventoryItemId } = payload;

    const mercIndex = state.knownMercenaries.findIndex(m => m.id === mercenaryId);
    if (mercIndex === -1) return state;
    const mercenary = { ...state.knownMercenaries[mercIndex] };
    const newEquipment = { ...mercenary.equipment };

    const invItemIndex = state.inventory.findIndex(i => i.id === inventoryItemId);
    if (invItemIndex === -1) return state;
    const invItem = state.inventory[invItemIndex];

    if (invItem.type !== 'EQUIPMENT' || !invItem.equipmentData) return state;

    const equipData: Equipment = { ...invItem.equipmentData };

    // --- 요구 레벨 검증 로직 ---
    if (equipData.minLevel && mercenary.level < equipData.minLevel) {
        return {
            ...state,
            logs: [`${mercenary.name} cannot equip ${equipData.name}. Required Level: ${equipData.minLevel}`, ...state.logs]
        };
    }

    const targetSlot: EquipmentSlotType = equipData.slotType;

    let newInventory = [...state.inventory];
    let itemsReturnedToInventory: Equipment[] = [];

    // 장착 슬롯 스왑 로직
    if (targetSlot === 'MAIN_HAND') {
        if (equipData.isTwoHanded) {
            if (newEquipment.OFF_HAND) {
                itemsReturnedToInventory.push(newEquipment.OFF_HAND);
                newEquipment.OFF_HAND = null;
            }
        }
        if (newEquipment.MAIN_HAND) {
            itemsReturnedToInventory.push(newEquipment.MAIN_HAND);
        }
        newEquipment.MAIN_HAND = equipData;
    }
    else if (targetSlot === 'OFF_HAND') {
        if (newEquipment.MAIN_HAND && newEquipment.MAIN_HAND.isTwoHanded) {
             itemsReturnedToInventory.push(newEquipment.MAIN_HAND);
             newEquipment.MAIN_HAND = null;
        }
        if (newEquipment.OFF_HAND) {
            itemsReturnedToInventory.push(newEquipment.OFF_HAND);
        }
        newEquipment.OFF_HAND = equipData;
    }
    else {
        if (newEquipment[targetSlot]) {
            itemsReturnedToInventory.push(newEquipment[targetSlot]!);
        }
        newEquipment[targetSlot] = equipData;
    }

    newInventory.splice(invItemIndex, 1);

    itemsReturnedToInventory.forEach(returnedItem => {
        newInventory.push({
            id: returnedItem.id,
            name: returnedItem.name,
            type: 'EQUIPMENT',
            description: returnedItem.description || 'Returned equipment',
            baseValue: returnedItem.price,
            icon: returnedItem.icon || '📦',
            quantity: 1,
            equipmentData: returnedItem
        });
    });

    const previousOwners = equipData.previousOwners || [];
    let affinityGain = 0;
    let logMessage = `Equipped ${equipData.name} to ${mercenary.name}.`;

    if (!previousOwners.includes(mercenaryId)) {
        switch (equipData.rarity) {
            case 'Legendary': affinityGain = 5; break;
            case 'Epic': affinityGain = 4; break;
            case 'Rare': affinityGain = 3; break;
            case 'Uncommon': affinityGain = 2; break;
            case 'Common': affinityGain = 1; break;
            default: affinityGain = 1;
        }

        mercenary.affinity = Math.min(100, (mercenary.affinity || 0) + affinityGain);
        equipData.previousOwners = [...previousOwners, mercenaryId];
        logMessage += ` Affinity +${affinityGain}.`;
    }

    const newMercenaries = [...state.knownMercenaries];
    newMercenaries[mercIndex] = { ...mercenary, equipment: newEquipment };

    return {
        ...state,
        inventory: newInventory,
        knownMercenaries: newMercenaries,
        logs: [logMessage, ...state.logs]
    };
};

export const handleUnequipItem = (state: GameState, payload: { mercenaryId: string; slot: EquipmentSlotType }): GameState => {
    const { mercenaryId, slot } = payload;

    const mercIndex = state.knownMercenaries.findIndex(m => m.id === mercenaryId);
    if (mercIndex === -1) return state;
    const mercenary = { ...state.knownMercenaries[mercIndex] };
    const newEquipment = { ...mercenary.equipment };

    const itemToUnequip = newEquipment[slot];
    if (!itemToUnequip) return state;

    const newInventory = [...state.inventory];
    newInventory.push({
        id: itemToUnequip.id,
        name: itemToUnequip.name,
        type: 'EQUIPMENT',
        description: itemToUnequip.description || 'Unequipped item',
        baseValue: itemToUnequip.price,
        icon: itemToUnequip.icon || '📦',
        quantity: 1,
        equipmentData: itemToUnequip
    });

    newEquipment[slot] = null;

    const newMercenaries = [...state.knownMercenaries];
    newMercenaries[mercIndex] = { ...mercenary, equipment: newEquipment };

    return {
        ...state,
        inventory: newInventory,
        knownMercenaries: newMercenaries,
        logs: [`Unequipped ${itemToUnequip.name} from ${mercenary.name}.`, ...state.logs]
    };
};

import React, { useState, useMemo } from 'react';
import { 
  Box, Sword, Shield, Sparkles, FlaskConical, Package, 
  ChevronRight, AlertCircle, Check, X 
} from 'lucide-react';
import { InventoryItem, EquipmentSlotType } from '../../types/inventory';
import { Mercenary } from '../../models/Mercenary';
import { PrimaryStats, mergePrimaryStats } from '../../models/Stats';
import { getAssetUrl } from '../../utils';

type CategoryFilter = 'ALL' | 'WEAPON' | 'ARMOR' | 'ACCESSORY' | 'CONSUMABLE';

interface EquipmentInventoryListProps {
  inventory: InventoryItem[];
  selectedItemId: string | null;
  onSelect: (itemId: string) => void;
  onEquip: (itemId: string) => void;
  onConsume: (itemId: string) => void;
  selectedSlotFilter: EquipmentSlotType | null;
  mercenary: Mercenary;
  isReadOnly?: boolean;
  onToggleInventory: () => void;
}

const getRarityClasses = (rarity?: string) => {
  switch (rarity) {
    case 'Legendary':
      return 'text-amber-400 border-amber-500/50 bg-amber-950/40';
    case 'Epic':
      return 'text-purple-400 border-purple-500/50 bg-purple-950/40';
    case 'Rare':
      return 'text-blue-400 border-blue-500/50 bg-blue-950/40';
    case 'Uncommon':
      return 'text-emerald-400 border-emerald-500/50 bg-emerald-950/40';
    default:
      return 'text-stone-400 border-stone-700/50 bg-stone-900/40';
  }
};

const getQualityLabel = (q: number): string => {
  if (q >= 110) return 'MASTERWORK';
  if (q >= 100) return 'PRISTINE';
  if (q >= 90) return 'SUPERIOR';
  if (q >= 80) return 'FINE';
  if (q >= 70) return 'STANDARD';
  if (q >= 60) return 'RUSTIC';
  return 'CRUDE';
};

export const EquipmentInventoryList: React.FC<EquipmentInventoryListProps> = ({
  inventory,
  selectedItemId,
  onSelect,
  onEquip,
  onConsume,
  selectedSlotFilter,
  mercenary,
  isReadOnly,
  onToggleInventory,
}) => {
  const [activeFilter, setActiveFilter] = useState<CategoryFilter>('ALL');

  const pureMercStats = useMemo(() => {
    return mergePrimaryStats(mercenary.stats, mercenary.allocatedStats);
  }, [mercenary.stats, mercenary.allocatedStats]);

  const displayInventory = useMemo(() => {
    let filtered = inventory;

    if (selectedSlotFilter) {
      return filtered.filter((item) => item.equipmentData?.slotType === selectedSlotFilter);
    }

    if (activeFilter === 'WEAPON') {
      return filtered.filter((item) => item.equipmentData?.slotType === 'MAIN_HAND');
    }
    if (activeFilter === 'ARMOR') {
      return filtered.filter((item) => 
        ['HEAD', 'BODY', 'HANDS', 'FEET', 'OFF_HAND'].includes(item.equipmentData?.slotType || '')
      );
    }
    if (activeFilter === 'ACCESSORY') {
      return filtered.filter((item) => item.equipmentData?.slotType === 'ACCESSORY');
    }
    if (activeFilter === 'CONSUMABLE') {
      return filtered.filter((item) => item.type === 'CONSUMABLE');
    }

    return filtered;
  }, [inventory, selectedSlotFilter, activeFilter]);

  const filterChips: { id: CategoryFilter; label: string; icon: React.ReactNode }[] = [
    { id: 'ALL', label: 'All', icon: <Box className="w-3 h-3" /> },
    { id: 'WEAPON', label: 'Weapons', icon: <Sword className="w-3 h-3" /> },
    { id: 'ARMOR', label: 'Armor', icon: <Shield className="w-3 h-3" /> },
    { id: 'ACCESSORY', label: 'Accessory', icon: <Sparkles className="w-3 h-3" /> },
    { id: 'CONSUMABLE', label: 'Items', icon: <FlaskConical className="w-3 h-3" /> },
  ];

  return (
    <div className="flex-1 flex flex-col min-h-0">
      <div 
        onClick={onToggleInventory}
        className="p-4 md:p-6 bg-stone-950 border-b border-white/5 flex justify-between items-center shrink-0 z-10 backdrop-blur-md cursor-pointer hover:bg-stone-900 transition-colors group"
      >
        <div className="flex flex-col">
            <h3 className="text-[10px] md:text-sm font-black text-stone-100 uppercase tracking-widest flex items-center gap-2 group-hover:text-amber-500 transition-colors">
            <Package className="w-4 h-4 text-amber-600" />
            <span>{selectedSlotFilter ? `Filtering: ${selectedSlotFilter}` : 'Squad Inventory'}</span>
            </h3>
            <span className="text-[7px] md:text-[10px] text-stone-500 font-mono mt-0.5 uppercase">Click Header to Close</span>
        </div>
        <div className="flex items-center gap-3">
          <span className="text-[8px] md:text-xs text-stone-600 font-mono bg-stone-900 px-2 py-0.5 rounded border border-stone-800">{displayInventory.length} ITEMS</span>
          <ChevronRight className="w-4 h-4 text-stone-700 group-hover:text-amber-500 group-hover:translate-x-0.5 transition-all" />
        </div>
      </div>

      {!selectedSlotFilter && (
        <div className="px-3 md:px-6 py-2 md:py-3 bg-stone-950/40 border-b border-white/5 flex gap-2 overflow-x-auto no-scrollbar shrink-0">
          {filterChips.map((chip) => (
            <button
              key={chip.id}
              onClick={() => setActiveFilter(chip.id)}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full border text-[9px] md:text-[10px] font-black uppercase tracking-tighter transition-all whitespace-nowrap ${
                activeFilter === chip.id
                  ? 'bg-amber-600 border-amber-400 text-white shadow-glow-sm'
                  : 'bg-stone-800 border-stone-700 text-stone-500 hover:text-stone-300'
              }`}
            >
              {chip.icon}
              {chip.label}
            </button>
          ))}
        </div>
      )}

      <div className="flex-1 overflow-y-auto custom-scrollbar p-3 md:p-6 space-y-2 md:space-y-3">
        {displayInventory.length === 0 ? (
          <div className="h-full flex flex-col items-center justify-center text-stone-800 italic p-12 text-center">
            <Box className="w-12 h-12 opacity-10 mb-2" />
            <p className="text-xs">No suitable gear found.</p>
            {selectedSlotFilter && (
              <button 
                onClick={onToggleInventory}
                className="mt-4 px-4 py-2 bg-stone-800 text-stone-400 rounded-lg text-[10px] uppercase font-bold hover:text-stone-200"
              >
                Back to View All
              </button>
            )}
          </div>
        ) : (
          displayInventory.map((item) => {
            const isConsumable = item.type === 'CONSUMABLE';
            const isSelected = selectedItemId === item.id;

            const minLevel = item.equipmentData?.minLevel || 1;
            const canEquip = isConsumable || (mercenary.level >= minLevel);

            const rarityClasses = isConsumable ? 'text-stone-400 border-stone-700 bg-stone-900/40' : getRarityClasses(item.equipmentData?.rarity);
            const imageUrl = item.type === 'EQUIPMENT' && item.equipmentData
              ? (item.equipmentData.image
                  ? getAssetUrl(item.equipmentData.image)
                  : item.equipmentData.recipeId
                    ? getAssetUrl(`${item.equipmentData.recipeId}.png`)
                    : getAssetUrl(`${item.id.split('_')[0]}.png`))
              : getAssetUrl(`${item.id}.png`);

            return (
              <div
                key={item.id}
                onClick={() => !isSelected && onSelect(item.id)}
                className={`flex flex-col gap-2 p-3 md:p-5 rounded-xl border transition-all ${
                  isSelected ? 'border-amber-500 bg-stone-900/80 shadow-inner' : 'border-stone-800 bg-stone-900/30'
                } cursor-pointer group relative overflow-hidden ${!isConsumable && !canEquip ? 'opacity-60' : ''}`}
              >
                <div className="flex items-center gap-3 md:gap-4">
                  <div className={`w-10 h-10 md:w-16 md:h-16 bg-stone-950 rounded-lg border-2 flex items-center justify-center shrink-0 ${rarityClasses}`}>
                    <img src={imageUrl} className="w-8 h-8 md:w-12 md:h-12 object-contain" alt={item.name} />
                  </div>

                  <div className="flex-1 min-w-0">
                    <div className="text-[11px] md:text-lg font-black truncate text-stone-200">{item.name}</div>
                    <div className="flex wrap items-center gap-2 mt-1">
                      <span className={`text-[7px] md:text-[9px] px-1.5 py-0.5 rounded font-black uppercase border leading-none ${rarityClasses}`}>
                        {isConsumable ? 'CONSUMABLE' : item.equipmentData?.rarity}
                      </span>
                      {item.quantity > 1 && (
                        <span className="text-[7px] md:text-[9px] text-stone-500 font-mono font-bold">
                          QTY: {item.quantity}
                        </span>
                      )}
                    </div>
                  </div>

                  {!isReadOnly && isSelected && !isConsumable && canEquip && (
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        onEquip(item.id);
                      }}
                      className="shrink-0 px-3 md:px-8 py-1.5 md:py-3 bg-amber-700 hover:bg-amber-600 text-white text-[9px] md:text-xs font-black uppercase rounded shadow-lg transition-all"
                    >
                      Equip
                    </button>
                  )}

                  {!isReadOnly && isSelected && isConsumable && (
                    <div className="absolute top-0 right-0 h-full w-24 md:w-32 bg-stone-900/95 border-l border-amber-600/30 flex flex-col animate-in slide-in-from-right-full duration-200 z-30">
                        <button 
                            onClick={(e) => { e.stopPropagation(); onConsume(item.id); }}
                            className="flex-1 flex flex-col items-center justify-center gap-1 hover:bg-emerald-900/40 text-emerald-400 transition-colors"
                        >
                            <Check className="w-4 h-4" />
                            <span className="text-[8px] md:text-[10px] font-black uppercase">Consume</span>
                        </button>
                        <div className="h-px w-full bg-amber-600/10" />
                        <button 
                            onClick={(e) => { e.stopPropagation(); onSelect(""); }}
                            className="flex-1 flex flex-col items-center justify-center gap-1 hover:bg-red-900/40 text-stone-500 hover:text-red-400 transition-colors"
                        >
                            <X className="w-4 h-4" />
                            <span className="text-[8px] md:text-[10px] font-black uppercase">Cancel</span>
                        </button>
                    </div>
                  )}
                </div>

                {!isConsumable && !canEquip && isSelected && (
                  <div className="bg-red-950/20 border border-red-900/30 rounded-lg p-2 flex items-center gap-2 text-[8px] md:text-[10px] text-red-400 font-bold uppercase tracking-tight">
                    <AlertCircle className="w-3 h-3 shrink-0" />
