// Helper to generate the dungeon grid for manual assault mode
const generateManualGrid = (width: number, height: number, dungeonId: string, floor: number, maxFloors: number, forceNPC: boolean = false): RoomType[][] => {
    const grid: RoomType[][] = Array.from({ length: height }, () => Array(width).fill('EMPTY'));
    // Entry point is always at the top-left
    grid[0][0] = 'ENTRANCE';

    // Boss or Stairs?
    if (floor === maxFloors) {
        grid[height - 1][width - 1] = 'BOSS';
    } else {
        grid[height - 1][width - 1] = 'STAIRS';
    }

    // Randomly place exactly one key required for some dungeons (only on final floor or specific logic)
    let keyPlaced = false;
    if (floor === maxFloors) {
        let attempts = 0;
        while (!keyPlaced && attempts < 100) {
            let kx = Math.floor(Math.random() * width);
            let ky = Math.floor(Math.random() * height);
            if (grid[ky][kx] === 'EMPTY') {
                grid[ky][kx] = 'KEY';
                keyPlaced = true;
            }
            attempts++;
        }
    }

    // Populate the rest of the grid
    let npcPlaced = false;
    for (let y = 0; y < height; y++) {
        for (let x = 0; x < width; x++) {
            if (grid[y][x] === 'EMPTY') {
                const r = Math.random();
                if (r < 0.18) grid[y][x] = 'ENEMY'; // 적 타일 비중 상향
                else if (r < 0.25) grid[y][x] = 'GOLD';
                else if (r < 0.35) grid[y][x] = 'TRAP';
                else if (r < 0.38 && !npcPlaced) {
                    grid[y][x] = 'NPC';
                    npcPlaced = true;
                }
            }
        }
    }

    // Force NPC logic (only on specific floors)
    if (forceNPC && !npcPlaced && floor === 1) {
        let attempts = 0;
        while (!npcPlaced && attempts < 10) {
            const rx = Math.floor(Math.random() * width);
            const ry = Math.floor(Math.random() * height);
            if (grid[ry][rx] === 'EMPTY') {
                grid[ry][rx] = 'NPC';
                npcPlaced = true;
            }
            attempts++;
        }
    }

    return grid;
};

export const handleStartManualDungeon = (state: GameState, payload: { dungeonId: string; partyIds: string[] }): GameState => {
    const dungeon = DUNGEONS.find(d => d.id === payload.dungeonId);
    if (!dungeon) return state;

    const party = state.knownMercenaries.filter(m => payload.partyIds.includes(m.id));
    if (party.some(m => (m.expeditionEnergy || 0) < dungeon.energyCost)) {
        return { ...state, logs: [`Your squad is too exhausted to enter ${dungeon.name}.`, ...state.logs] };
    }

    const isTillyRescued = state.knownMercenaries.some(m => m.id === 'tilly_footloose');
    const shouldForceNPC = payload.dungeonId === 'dungeon_t1_sewers' && !isTillyRescued;

    const updatedMercs = state.knownMercenaries.map(m => {
        if (payload.partyIds.includes(m.id)) {
            return { 
                ...m, 
                expeditionEnergy: Math.max(0, (m.expeditionEnergy || 0) - dungeon.energyCost), 
                status: 'ON_EXPEDITION' as const 
            };
        }
        return m;
    });

    const maxFloors = dungeon.id === 'dungeon_t1_sewers' ? 5 : 1;
    const grid = generateManualGrid(dungeon.gridWidth, dungeon.gridHeight, dungeon.id, 1, maxFloors, shouldForceNPC);
    const visited = Array.from({ length: dungeon.gridHeight }, () => Array(dungeon.gridWidth).fill(false));
    visited[0][0] = true;

    const session: ManualDungeonSession = {
        dungeonId: dungeon.id,
        partyIds: payload.partyIds,
        grid,
        visited,
        playerPos: { x: 0, y: 0 },
        pathHistory: [{ x: 0, y: 0 }],
        hasKey: false,
        isBossLocked: dungeon.isBossLocked ?? true,
        goldCollected: 0,
        encounterStatus: 'NONE',
        lastActionMessage: `Scanning sector... Floor 1 initialized.`,
        currentFloor: 1,
        maxFloors
    };

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: session,
        showManualDungeonOverlay: true,
        logs: [`Direct assault initiated: ${dungeon.name}.`, ...state.logs]
    };
};

export const handleMoveManualDungeon = (state: GameState, payload: { x: number, y: number }): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus === 'ENCOUNTERED' || session.encounterStatus === 'BATTLE') return state;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return state;

    const newX = session.playerPos.x + payload.x;
    const newY = session.playerPos.y + payload.y;

    if (newX < 0 || newX >= dungeon.gridWidth || newY < 0 || newY >= dungeon.gridHeight) {
        return { 
            ...state, 
            activeManualDungeon: { ...session, lastActionMessage: "Structural barrier detected." }
        };
    }

    const targetRoom = session.grid[newY][newX];
    if (targetRoom === 'WALL') return state;

    const isAlreadyVisited = session.visited[newY][newX];
    const cost = isAlreadyVisited ? -1 : (targetRoom === 'BOSS' || targetRoom === 'STAIRS' ? dungeon.bossEnergy : dungeon.moveEnergy);

    const party = state.knownMercenaries.filter(m => session.partyIds.includes(m.id));
    if (cost > 0 && party.some(m => (m.expeditionEnergy || 0) < cost)) {
        return { 
            ...state, 
            activeManualDungeon: { ...session, lastActionMessage: "SQUAD ALERT: Energy critically low." }
        };
    }

    let updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextEnergy = Math.max(0, (m.expeditionEnergy || 0) - cost);
            let nextHp = m.currentHp;
            if (targetRoom === 'TRAP' && !isAlreadyVisited) nextHp = Math.max(0, m.currentHp - 15);
            return { ...m, expeditionEnergy: nextEnergy, currentHp: nextHp };
        }
        return m;
    });

    const isWipedOut = updatedMercs.filter(m => session.partyIds.includes(m.id)).every(m => m.currentHp <= 0);
    if (isWipedOut) return handleRetreatManualDungeon({ ...state, knownMercenaries: updatedMercs });

    const newVisited = [...session.visited.map(row => [...row])];
    newVisited[newY][newX] = true;

    let extraGold = 0;
    let newGrid = [...session.grid.map(row => [...row])];
    let logMsg = '';
    let actionMsg = session.lastActionMessage;
    let encounterStatus: ManualDungeonSession['encounterStatus'] = 'NONE';

    if (targetRoom === 'GOLD' && !isAlreadyVisited) {
        extraGold = (dungeon.tier || 1) * 30;
        newGrid[newY][newX] = 'EMPTY';
        actionMsg = `Credits recovered. (+${extraGold} G)`;
    } else if (targetRoom === 'TRAP' && !isAlreadyVisited) {
        actionMsg = `Structural hazard triggered. Integrity drop.`;
    } else if (targetRoom === 'KEY' && !isAlreadyVisited) {
        logMsg = `Area key recovered.`;
        actionMsg = `Sector key identified. Decrypting...`;
        newGrid[newY][newX] = 'EMPTY';
    } else if (targetRoom === 'ENEMY' && !isAlreadyVisited) {
        encounterStatus = 'ENCOUNTERED';
        actionMsg = `Hostile lifeforms detected. Combat protocol engaged.`;
    } else if (targetRoom === 'BOSS' && !session.isBossDefeated) {
        encounterStatus = 'ENCOUNTERED';
        actionMsg = `COMMANDER ALERT: Primary target identified.`;
    } else if (targetRoom === 'STAIRS') {
        // Floor transition logic
        const nextFloor = session.currentFloor + 1;
        const nextGrid = generateManualGrid(dungeon.gridWidth, dungeon.gridHeight, dungeon.id, nextFloor, session.maxFloors);
        const nextVisited = Array.from({ length: dungeon.gridHeight }, () => Array(dungeon.gridWidth).fill(false));
        nextVisited[0][0] = true;

        return {
            ...state,
            knownMercenaries: updatedMercs,
            activeManualDungeon: {
                ...session,
                grid: nextGrid,
                visited: nextVisited,
                playerPos: { x: 0, y: 0 },
                currentFloor: nextFloor,
                lastActionMessage: `Floor transition complete. Sector ${nextFloor} analysis in progress.`
            },
            logs: [`Proceeded to Floor ${nextFloor}.`, ...state.logs]
        };
    }

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: {
            ...session,
            grid: newGrid,
            playerPos: { x: newX, y: newY },
            pathHistory: [{ x: newX, y: newY }, ...session.pathHistory].slice(0, 50),
            visited: newVisited,
            hasKey: targetRoom === 'KEY' ? true : session.hasKey,
            encounterStatus,
            goldCollected: session.goldCollected + extraGold,
            lastActionMessage: actionMsg
        },
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleStartCombatManual = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus !== 'ENCOUNTERED') return state;

    const currentRoom = session.grid[session.playerPos.y][session.playerPos.x];
    let monsterId = 'giant_rat';

    if (currentRoom === 'BOSS') {
        const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
        monsterId = dungeon?.bossVariantId || 'plague_rat_king';
    } else {
        // Band 1 Random Mob
        const mobs = ['giant_rat', 'sewer_slime', 'mold_sporeling', 'carrion_beetle', 'sewer_thief'];
        monsterId = mobs[Math.floor(Math.random() * mobs.length)];
    }

    const monsterBase = MONSTERS[monsterId] || MONSTERS['giant_rat'];
    const bossEntity = { ...monsterBase, currentHp: monsterBase.stats.maxHp };

    return {
        ...state,
        activeManualDungeon: {
            ...session,
            encounterStatus: 'BATTLE',
            bossEntity
        }
    };
};

export const handleResolveCombatManual = (state: GameState, payload: { win: boolean, flee: boolean, finalParty: any[] }): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const currentRoom = session.grid[session.playerPos.y][session.playerPos.x];
    let logMsg = '';

    const livingMembers = payload.finalParty.filter(p => p.currentHp > 0);
    const xpPerMember = (payload.win && session.bossEntity && livingMembers.length > 0) 
        ? Math.floor(session.bossEntity.rewardXp / livingMembers.length) 
        : 0;

    if (payload.win) {
        logMsg = `Neutralized target: ${session.bossEntity?.name}. XP awarded.`;
    }

    const newKnownMercenaries = state.knownMercenaries.map(m => {
        const combatant = payload.finalParty.find(p => p.id === m.id);
        if (combatant) {
            let nextXp = m.currentXp;
            let nextLevel = m.level;
            let nextMaxHp = m.maxHp;
            let nextMaxMp = m.maxMp;
            let nextCurrentHp = combatant.currentHp;
            let bonusStatPoints = m.bonusStatPoints || 0;

            if (payload.win && combatant.currentHp > 0) {
                nextXp += xpPerMember;
                while (nextXp >= m.xpToNextLevel) {
                    nextXp -= m.xpToNextLevel;
                    nextLevel++;
                    const merged = mergePrimaryStats(m.stats, m.allocatedStats);
                    nextMaxHp = calculateMaxHp(merged, nextLevel);
                    nextMaxMp = calculateMaxMp(merged, nextLevel);
                    nextCurrentHp = nextMaxHp;
                    bonusStatPoints += 3;
                }
            }

            return { 
                ...m, 
                currentHp: nextCurrentHp, 
                currentMp: combatant.currentMp,
                currentXp: nextXp,
                level: nextLevel,
                bonusStatPoints,
                maxHp: nextMaxHp,
                maxMp: nextMaxMp,
                xpToNextLevel: nextLevel * 100
            };
        }
        return m;
    });

    const isBossDefeated = (currentRoom === 'BOSS' && payload.win) || session.isBossDefeated;
    let nextGrid = [...session.grid.map(row => [...row])];
    if (payload.win && currentRoom === 'ENEMY') {
        nextGrid[session.playerPos.y][session.playerPos.x] = 'EMPTY';
    }

    return {
        ...state,
        knownMercenaries: newKnownMercenaries,
        activeManualDungeon: {
            ...session,
            grid: nextGrid,
            encounterStatus: payload.win ? 'VICTORY' : (payload.flee ? 'NONE' : 'DEFEAT'),
            isBossDefeated,
            lastActionMessage: payload.win 
                ? `Area neutralized. Combat systems on standby.`
                : (payload.flee ? `Withdrawal confirmed.` : `CRITICAL STATUS: Rescue required.`)
        },
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleRetreatManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const isDefeat = session.encounterStatus === 'DEFEAT' || 
                    state.knownMercenaries.filter(m => session.partyIds.includes(m.id)).every(m => m.currentHp <= 0);

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    const mercResults: DungeonResult['mercenaryResults'] = [];

    const updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextStatus: any = 'HIRED';
            let statusChange: 'NONE' | 'INJURED' | 'DEAD' = 'NONE';

            if (isDefeat) {
                const roll = Math.random();
                if (roll < 0.1) { nextStatus = 'DEAD'; statusChange = 'DEAD'; }
                else { 
                    nextStatus = 'INJURED'; statusChange = 'INJURED'; 
                    m.recoveryUntilDay = state.stats.day + 2; 
                }
            } else if (m.currentHp <= 0) {
                nextStatus = 'INJURED'; statusChange = 'INJURED';
                m.recoveryUntilDay = state.stats.day + 1;
            }

            mercResults.push({
                id: m.id, name: m.name, job: m.job, levelBefore: m.level, levelAfter: m.level,
                xpGained: 0, currentXp: m.currentXp, xpToNext: m.xpToNextLevel, statusChange
            });

            return { ...m, status: nextStatus, assignedExpeditionId: undefined };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercs,
        dungeonResult: isDefeat ? {
            dungeonName: dungeon?.name || 'Unknown',
            rewards: [],
            mercenaryResults: mercResults,
            isDefeat: true
        } : state.dungeonResult,
        activeManualDungeon: null,
        showManualDungeonOverlay: false,
        logs: [isDefeat ? 'CRITICAL FAILURE: Squad neutralized.' : 'Squad retreated.', ...state.logs]
    };
};

export const handleRescueNPC = (state: GameState, payload: { npcId: string }): GameState => {
    const currentSession = state.activeManualDungeon;
    if (!currentSession) return state;

    let newGrid = [...currentSession.grid.map(row => [...row])];
    newGrid[currentSession.playerPos.y][currentSession.playerPos.x] = 'EMPTY';

    return {
        ...state,
        activeManualDungeon: { 
            ...currentSession, 
            grid: newGrid, 
            npcFound: true, 
            rescuedNpcId: payload.npcId,
            lastActionMessage: `Survivor secured! Initiating extraction protocol.`
        },
        logs: [`Survivor secured! Initiating extraction.`, ...state.logs]
    };
};

export const handleFinishManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const tempExpId = `temp_manual_${Date.now()}`;
    const tempExp = {
        id: tempExpId,
        dungeonId: session.dungeonId,
        partyIds: session.partyIds,
        startTime: 0,
        endTime: 0,
        status: 'COMPLETED' as const
    };

    const stateWithTempExp = {
        ...state,
        activeExpeditions: [...state.activeExpeditions, tempExp]
    };

    const claimedState = handleClaimExpedition(stateWithTempExp, { 
        expeditionId: tempExpId, 
        rescuedNpcId: session.rescuedNpcId 
    });

    if (session.goldCollected > 0) {
        claimedState.stats.gold += session.goldCollected;
        if (claimedState.dungeonResult) {
            claimedState.dungeonResult.goldGained = (claimedState.dungeonResult.goldGained || 0) + session.goldCollected;
        }
    }

    return {
        ...claimedState,
        activeManualDungeon: null,
        showManualDungeonOverlay: false
    };
};

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';
import { ManualDungeonSession, RoomType } from '../types/game-state';

export type CameraMode = 'LOCKED' | 'ADAPTIVE' | 'FREE';

export interface DungeonSceneData {
    session: ManualDungeonSession;
    moveEnergy: number;
    bossEnergy: number;
    onMove: (dx: number, dy: number) => void;
    cameraMode: CameraMode;
    initialZoom?: number;
}

export default class DungeonScene extends Phaser.Scene {
    declare public add: Phaser.GameObjects.GameObjectFactory;
    declare public tweens: Phaser.Tweens.TweenManager;
    declare public scale: Phaser.Scale.ScaleManager;
    declare public cameras: Phaser.Cameras.Scene2D.CameraManager;
    declare public input: Phaser.Input.InputPlugin;
    declare public time: Phaser.Time.Clock;
    declare public events: Phaser.Events.EventEmitter;
    declare public load: Phaser.Loader.LoaderPlugin;
    declare public textures: Phaser.Textures.TextureManager;
    declare public anims: Phaser.Animations.AnimationManager;

    private session!: ManualDungeonSession;
    private onMoveCallback!: (dx: number, dy: number) => void;
    private cameraMode: CameraMode = 'LOCKED';
    private zoom: number = 1.0;

    private root!: Phaser.GameObjects.Container;
    private mapLayer!: Phaser.GameObjects.Container;
    private contentLayer!: Phaser.GameObjects.Container;
    private playerLayer!: Phaser.GameObjects.Container;
    private fxLayer!: Phaser.GameObjects.Container;

    private playerMarker!: Phaser.GameObjects.Container;
    private revealedTiles: Set<string> = new Set();
    private contentByCoord: Map<string, Phaser.GameObjects.Text> = new Map();

    private sprayEmitter!: Phaser.GameObjects.Particles.ParticleEmitter;
    private vignette!: Phaser.GameObjects.Graphics;
    private redFocusOverlay!: Phaser.GameObjects.Graphics;

    private uiCamera!: Phaser.Cameras.Scene2D.Camera;

    private tileWidth = 84;
    private tileGap = 8;
    private isMoving = false;

    private isDragging = false;
    private dragStartX = 0;
    private dragStartY = 0;

    private cameraTrackTween: Phaser.Tweens.Tween | null = null;

    constructor() {
        super('DungeonScene');
    }

    init(data: DungeonSceneData) {
        this.session = data.session;
        this.onMoveCallback = data.onMove;
        this.cameraMode = data.cameraMode ?? 'LOCKED';
        this.zoom = data.initialZoom ?? 1.0;
    }

    preload() {
        this.load.image('sparkle', getAssetUrl('particle_spark1.png'));
        this.load.image('red_mist', getAssetUrl('particle_spark2.png'));
    }

    create() {
        const { width, height } = this.scale;

        this.cameras.main.setBackgroundColor(0x000000);
        this.cameras.main.setZoom(this.zoom);

        this.uiCamera = this.cameras.add(0, 0, width, height).setName('HUD');
        this.uiCamera.setScroll(0, 0);
        this.uiCamera.setZoom(1);

        this.root = this.add.container(0, 0);
        this.mapLayer = this.add.container(0, 0);
        this.contentLayer = this.add.container(0, 0);
        this.playerLayer = this.add.container(0, 0);
        this.fxLayer = this.add.container(0, 0).setDepth(100);

        this.root.add([this.mapLayer, this.contentLayer, this.playerLayer]);

        this.vignette = this.add.graphics().setDepth(200).setScrollFactor(0);
        this.redFocusOverlay = this.add.graphics().setDepth(210).setScrollFactor(0);

        this.cameras.main.ignore([this.vignette, this.redFocusOverlay]);
        this.uiCamera.ignore(this.root);

        this.sprayEmitter = this.add.particles(0, 0, 'sparkle', {
            speed: { min: 60, max: 140 },
            scale: { start: 0.6, end: 0 },
            alpha: { start: 1, end: 0 },
            lifespan: 800,
            gravityY: 80,
            blendMode: 'ADD',
            emitting: false
        });
        this.root.add(this.sprayEmitter);

        this.initialRender();
        this.createPlayer();
        this.alignViewToPlayer(); 

        this.scale.on('resize', (gameSize: Phaser.Structs.Size) => {
            this.uiCamera.setSize(gameSize.width, gameSize.height);
            this.alignViewToPlayer();
            this.drawRedFocus();
        }, this);
        this.setupDragControls();

        this.drawRedFocus();
    }

    public updateZoom(newZoom: number) {
        this.zoom = newZoom;
        this.cameras.main.setZoom(newZoom);
        this.alignViewToPlayer();
    }

    public setCameraMode(mode: CameraMode) {
        this.cameraMode = mode;
        if (mode === 'LOCKED' && !this.isMoving) {
            this.alignViewToPlayer(); 
        }
    }

    private drawRedFocus() {
        const { width, height } = this.scale;
        this.redFocusOverlay.clear();

        const isFocusNeeded = this.session.encounterStatus === 'ENCOUNTERED' || this.session.encounterStatus === 'BATTLE';
        if (!isFocusNeeded) return;

        this.redFocusOverlay.setScale(1);

        const thickness = 140; 
        const color = 0x7f1d1d;
        const outerAlpha = 0.75;
        const innerAlpha = 0;

        this.redFocusOverlay.fillGradientStyle(color, color, color, color, outerAlpha, outerAlpha, innerAlpha, innerAlpha);
        this.redFocusOverlay.fillRect(0, 0, width, thickness);

        this.redFocusOverlay.fillGradientStyle(color, color, color, color, innerAlpha, innerAlpha, outerAlpha, outerAlpha);
        this.redFocusOverlay.fillRect(0, height - thickness, width, thickness);

        this.redFocusOverlay.fillGradientStyle(color, color, color, color, outerAlpha, innerAlpha, outerAlpha, innerAlpha);
        this.redFocusOverlay.fillRect(0, 0, thickness, height);

        this.redFocusOverlay.fillGradientStyle(color, color, color, color, innerAlpha, outerAlpha, innerAlpha, outerAlpha);
        this.redFocusOverlay.fillRect(width - thickness, 0, thickness, height);
    }

    private setupDragControls() {
        this.input.on('pointerdown', (pointer: Phaser.Input.Pointer) => {
            if (this.session.encounterStatus === 'BATTLE') return;
            this.isDragging = true;
            this.dragStartX = pointer.x - this.root.x;
            this.dragStartY = pointer.y - this.root.y;

            if (this.cameraTrackTween) {
                this.cameraTrackTween.stop();
                this.cameraTrackTween = null;
            }
        });

        this.input.on('pointermove', (pointer: Phaser.Input.Pointer) => {
            if (!this.isDragging) return;
            this.root.setPosition(pointer.x - this.dragStartX, pointer.y - this.dragStartY);
        });

        this.input.on('pointerup', () => { this.isDragging = false; });
    }

    private initialRender() {
        const { grid, visited } = this.session;
        const rows = grid.length;
        const cols = grid[0].length;

        this.mapLayer.removeAll(true);
        this.contentLayer.removeAll(true);
        this.revealedTiles.clear();
        this.contentByCoord.clear();

        for (let y = 0; y < rows; y++) {
            for (let x = 0; x < cols; x++) {
                if (visited[y][x]) {
                    this.drawRevealedTile(x, y, grid[y][x], false);
                }
            }
        }
    }

    private drawRevealedTile(x: number, y: number, type: RoomType, animate: boolean) {
        const key = `${x},${y}`;
        const tx = x * (this.tileWidth + this.tileGap);
        const ty = y * (this.tileWidth + this.tileGap);

        if (!this.revealedTiles.has(key)) {
            const tile = this.add.rectangle(tx, ty, this.tileWidth, this.tileWidth, 0x1c1917)
                .setStrokeStyle(2, 0x44403c)
                .setOrigin(0.5);
            this.mapLayer.add(tile);
            if (animate) {
                this.sprayEmitter.emitParticleAt(tx, ty, 15);
                tile.setAlpha(0).setScale(0.7);
                this.tweens.add({ targets: tile, alpha: 1, scale: 1, duration: 600, ease: 'Back.easeOut' });
            }
            this.revealedTiles.add(key);
        }

        const content = this.createRoomContents(type, tx, ty);
        if (content) {
            this.contentByCoord.set(key, content);
            if (animate) {
                content.setAlpha(0).setScale(0.5);
                this.tweens.add({ targets: content, alpha: 1, scale: 1, duration: 500, delay: 200, ease: 'Cubic.easeOut' });
            }
        }
    }

    private createRoomContents(type: RoomType, x: number, y: number) {
        let content: Phaser.GameObjects.Text | null = null;
        switch (type) {
            case 'BOSS':
                content = this.add.text(x, y, '💀', { fontSize: '32px' }).setOrigin(0.5);
                if (this.session.isBossLocked && !this.session.hasKey) content.setAlpha(0.3);
                break;
            case 'ENEMY':
                content = this.add.text(x, y, '⚔️', { fontSize: '28px' }).setOrigin(0.5);
                break;
            case 'STAIRS':
                content = this.add.text(x, y, '🪜', { fontSize: '32px' }).setOrigin(0.5);
                break;
            case 'KEY': content = this.add.text(x, y, '🔑', { fontSize: '28px' }).setOrigin(0.5); break;
            case 'ENTRANCE': content = this.add.text(x, y, '🚪', { fontSize: '28px' }).setOrigin(0.5); break;
            case 'GOLD': content = this.add.text(x, y, '💰', { fontSize: '28px' }).setOrigin(0.5); break;
            case 'TRAP': content = this.add.text(x, y, '🕸️', { fontSize: '28px' }).setOrigin(0.5); break;
            case 'NPC':
                if (this.session.npcFound) return null;
                content = this.add.text(x, y, '👤', { fontSize: '30px' }).setOrigin(0.5);
                break;
        }
        if (content) this.contentLayer.add(content);
        return content;
    }

    private createPlayer() {
        const { x, y } = this.session.playerPos;
        const px = x * (this.tileWidth + this.tileGap);
        const py = y * (this.tileWidth + this.tileGap);
        const visual = this.add.container(0, 0);
        const circle = this.add.circle(0, 0, 26, 0x6366f1, 0.9).setStrokeStyle(3, 0xffffff);
        const icon = this.add.text(0, 0, '👤', { fontSize: '24px' }).setOrigin(0.5);
        visual.add([circle, icon]);
        this.playerMarker = this.add.container(px, py, [visual]);
        this.playerLayer.add(this.playerMarker);
        this.tweens.add({ targets: visual, y: -8, duration: 800, yoyo: true, repeat: -1, ease: 'Sine.easeInOut' });
    }

    private alignViewToPlayer() {
        const { width, height } = this.scale;
        const { x, y } = this.session.playerPos;
        const targetX = x * (this.tileWidth + this.tileGap);
        const targetY = y * (this.tileWidth + this.tileGap);
        this.root.setPosition((width / 2) - (targetX), (height / 2) - (targetY));
    }

    public updateSession(newSession: ManualDungeonSession) {
        const oldStatus = this.session.encounterStatus;
        const oldFloor = this.session.currentFloor;
        this.session = newSession;

        if (oldFloor !== newSession.currentFloor) {
            this.initialRender();
        }

        if (oldStatus !== newSession.encounterStatus) this.drawRedFocus();
        const { width, height } = this.scale;
        const { x, y } = newSession.playerPos;
        const targetLocalX = x * (this.tileWidth + this.tileGap);
        const targetLocalY = y * (this.tileWidth + this.tileGap);
        this.isMoving = true;
        this.tweens.add({
            targets: this.playerMarker, x: targetLocalX, y: targetLocalY, duration: 300, ease: 'Cubic.out',
            onComplete: () => { this.isMoving = false; this.initialRender(); }
        });
        if (this.cameraMode !== 'FREE') {
            const targetRootX = (width / 2) - targetLocalX;
            const targetRootY = (height / 2) - targetLocalY;
            if (this.cameraTrackTween) this.cameraTrackTween.stop();
            this.cameraTrackTween = this.tweens.add({ targets: this.root, x: targetRootX, y: targetRootY, duration: 600, ease: 'Cubic.out' });
        }
    }

    public move(dx: number, dy: number) {
        if (this.isMoving) return;
        this.onMoveCallback(dx, dy);
    }
}

