// Helper to generate the dungeon grid for manual assault mode
const generateManualGrid = (width: number, height: number, dungeonId: string, floor: number, maxFloors: number, forceNPC: boolean = false): RoomType[][] => {
    const grid: RoomType[][] = Array.from({ length: height }, () => Array(width).fill('EMPTY'));
    // Entry point is always at the top-left
    grid[0][0] = 'ENTRANCE';

    // Boss or Stairs?
    if (floor === maxFloors) {
        grid[height - 1][width - 1] = 'BOSS';
    } else {
        grid[height - 1][width - 1] = 'STAIRS';
    }

    // Randomly place exactly one key required for some dungeons (only on final floor)
    let keyPlaced = false;
    if (floor === maxFloors) {
        let attempts = 0;
        while (!keyPlaced && attempts < 100) {
            let kx = Math.floor(Math.random() * width);
            let ky = Math.floor(Math.random() * height);
            if (grid[ky][kx] === 'EMPTY') {
                grid[ky][kx] = 'KEY';
                keyPlaced = true;
            }
            attempts++;
        }
    }

    // Populate the rest of the grid
    let npcPlaced = false;
    for (let y = 0; y < height; y++) {
        for (let x = 0; x < width; x++) {
            if (grid[y][x] === 'EMPTY') {
                const r = Math.random();
                if (r < 0.18) grid[y][x] = 'ENEMY'; 
                else if (r < 0.33) grid[y][x] = 'RESOURCE'; // 재료 채집 타일 (15%)
                else if (r < 0.38) grid[y][x] = 'GOLD';
                else if (r < 0.45) grid[y][x] = 'TRAP';
                else if (r < 0.47 && !npcPlaced) {
                    grid[y][x] = 'NPC';
                    npcPlaced = true;
                }
            }
        }
    }

    // Force NPC logic (only on specific floors)
    if (forceNPC && !npcPlaced && floor === 1) {
        let attempts = 0;
        while (!npcPlaced && attempts < 10) {
            const rx = Math.floor(Math.random() * width);
            const ry = Math.floor(Math.random() * height);
            if (grid[ry][rx] === 'EMPTY') {
                grid[ry][rx] = 'NPC';
                npcPlaced = true;
            }
            attempts++;
        }
    }

    return grid;
};

export const handleStartManualDungeon = (state: GameState, payload: { dungeonId: string; partyIds: string[] }): GameState => {
    const dungeon = DUNGEONS.find(d => d.id === payload.dungeonId);
    if (!dungeon) return state;

    const party = state.knownMercenaries.filter(m => payload.partyIds.includes(m.id));
    if (party.some(m => (m.expeditionEnergy || 0) < dungeon.energyCost)) {
        return { ...state, logs: [`Your squad is too exhausted to enter ${dungeon.name}.`, ...state.logs] };
    }

    const isTillyRescued = state.knownMercenaries.some(m => m.id === 'tilly_footloose');
    const shouldForceNPC = payload.dungeonId === 'dungeon_t1_sewers' && !isTillyRescued;

    const updatedMercs = state.knownMercenaries.map(m => {
        if (payload.partyIds.includes(m.id)) {
            return { 
                ...m, 
                expeditionEnergy: Math.max(0, (m.expeditionEnergy || 0) - dungeon.energyCost), 
                status: 'ON_EXPEDITION' as const 
            };
        }
        return m;
    });

    const maxFloors = dungeon.id === 'dungeon_t1_sewers' ? 5 : 1;
    const grid = generateManualGrid(dungeon.gridWidth, dungeon.gridHeight, dungeon.id, 1, maxFloors, shouldForceNPC);
    const visited = Array.from({ length: dungeon.gridHeight }, () => Array(dungeon.gridWidth).fill(false));
    visited[0][0] = true;

    const session: ManualDungeonSession = {
        dungeonId: dungeon.id,
        partyIds: payload.partyIds,
        grid,
        visited,
        playerPos: { x: 0, y: 0 },
        pathHistory: [{ x: 0, y: 0 }],
        hasKey: false,
        isBossLocked: dungeon.isBossLocked ?? true,
        goldCollected: 0,
        encounterStatus: 'NONE',
        lastActionMessage: `Scanning sector... Floor 1 initialized.`,
        currentFloor: 1,
        maxFloors
    };

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: session,
        showManualDungeonOverlay: true,
        logs: [`Direct assault initiated: ${dungeon.name}.`, ...state.logs]
    };
};

export const handleMoveManualDungeon = (state: GameState, payload: { x: number, y: number }): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus === 'ENCOUNTERED' || session.encounterStatus === 'BATTLE') return state;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return state;

    const newX = session.playerPos.x + payload.x;
    const newY = session.playerPos.y + payload.y;

    if (newX < 0 || newX >= dungeon.gridWidth || newY < 0 || newY >= dungeon.gridHeight) {
        return { 
            ...state, 
            activeManualDungeon: { ...session, lastActionMessage: "Structural barrier detected." }
        };
    }

    const targetRoom = session.grid[newY][newX];
    if (targetRoom === 'WALL') return state;

    const isAlreadyVisited = session.visited[newY][newX];
    const cost = isAlreadyVisited ? -1 : (targetRoom === 'BOSS' || targetRoom === 'STAIRS' ? dungeon.bossEnergy : dungeon.moveEnergy);

    const party = state.knownMercenaries.filter(m => session.partyIds.includes(m.id));
    if (cost > 0 && party.some(m => (m.expeditionEnergy || 0) < cost)) {
        return { 
            ...state, 
            activeManualDungeon: { ...session, lastActionMessage: "SQUAD ALERT: Energy critically low." }
        };
    }

    let updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextEnergy = Math.max(0, (m.expeditionEnergy || 0) - cost);
            let nextHp = m.currentHp;
            if (targetRoom === 'TRAP' && !isAlreadyVisited) nextHp = Math.max(0, m.currentHp - 15);
            return { ...m, expeditionEnergy: nextEnergy, currentHp: nextHp };
        }
        return m;
    });

    const isWipedOut = updatedMercs.filter(m => session.partyIds.includes(m.id)).every(m => m.currentHp <= 0);
    if (isWipedOut) return handleRetreatManualDungeon({ ...state, knownMercenaries: updatedMercs });

    const newVisited = [...session.visited.map(row => [...row])];
    newVisited[newY][newX] = true;

    let extraGold = 0;
    let newGrid = [...session.grid.map(row => [...row])];
    let newInventory = [...state.inventory];
    let logMsg = '';
    let actionMsg = session.lastActionMessage;
    let encounterStatus: ManualDungeonSession['encounterStatus'] = 'NONE';

    if (targetRoom === 'GOLD' && !isAlreadyVisited) {
        extraGold = (dungeon.tier || 1) * 30;
        newGrid[newY][newX] = 'EMPTY';
        actionMsg = `Credits recovered. (+${extraGold} G)`;
    } else if (targetRoom === 'RESOURCE' && !isAlreadyVisited) {
        // 하베스팅 로직 (Band 1 재료 중 랜덤 획득)
        const possibleResources = ['copper_ore', 'tin_ore', 'leather_strips', 'charcoal', 'rat_hide_patch'];
        const resId = possibleResources[Math.floor(Math.random() * possibleResources.length)];
        const count = 1 + Math.floor(Math.random() * 2);
        const matDef = materials[resId];

        const existing = newInventory.find(i => i.id === resId);
        if (existing) {
            newInventory = newInventory.map(i => i.id === resId ? { ...i, quantity: i.quantity + count } : i);
        } else {
            newInventory.push({ ...matDef, quantity: count } as InventoryItem);
        }

        newGrid[newY][newX] = 'EMPTY';
        actionMsg = `Harvested ${matDef.name} x${count}.`;
        logMsg = `Recovered materials from ruins.`;
    } else if (targetRoom === 'TRAP' && !isAlreadyVisited) {
        actionMsg = `Structural hazard triggered. Integrity drop.`;
    } else if (targetRoom === 'KEY' && !isAlreadyVisited) {
        logMsg = `Area key recovered.`;
        actionMsg = `Sector key identified. Decrypting...`;
        newGrid[newY][newX] = 'EMPTY';
    } else if (targetRoom === 'ENEMY' && !isAlreadyVisited) {
        encounterStatus = 'ENCOUNTERED';
        actionMsg = `Hostile lifeforms detected. Combat protocol engaged.`;
    } else if (targetRoom === 'BOSS' && !session.isBossDefeated) {
        encounterStatus = 'ENCOUNTERED';
        actionMsg = `COMMANDER ALERT: Primary target identified.`;
    } else if (targetRoom === 'STAIRS') {
        // Floor transition logic
        const nextFloor = session.currentFloor + 1;
        const nextGrid = generateManualGrid(dungeon.gridWidth, dungeon.gridHeight, dungeon.id, nextFloor, session.maxFloors);
        const nextVisited = Array.from({ length: dungeon.gridHeight }, () => Array(dungeon.gridWidth).fill(false));
        nextVisited[0][0] = true;

        return {
            ...state,
            knownMercenaries: updatedMercs,
            inventory: newInventory,
            activeManualDungeon: {
                ...session,
                grid: nextGrid,
                visited: nextVisited,
                playerPos: { x: 0, y: 0 },
                currentFloor: nextFloor,
                lastActionMessage: `Floor transition complete. Sector ${nextFloor} analysis in progress.`
            },
            logs: [`Proceeded to Floor ${nextFloor}.`, ...state.logs]
        };
    }

    return {
        ...state,
        knownMercenaries: updatedMercs,
        inventory: newInventory,
        activeManualDungeon: {
            ...session,
            grid: newGrid,
            playerPos: { x: newX, y: newY },
            pathHistory: [{ x: newX, y: newY }, ...session.pathHistory].slice(0, 50),
            visited: newVisited,
            hasKey: targetRoom === 'KEY' ? true : session.hasKey,
            encounterStatus,
            goldCollected: session.goldCollected + extraGold,
            lastActionMessage: actionMsg
        },
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleStartCombatManual = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus !== 'ENCOUNTERED') return state;

    const currentRoom = session.grid[session.playerPos.y][session.playerPos.x];
    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    const tier = dungeon?.tier || 1;

    let monsters: Monster[] = [];

    if (currentRoom === 'BOSS') {
        const monsterId = dungeon?.bossVariantId || 'plague_rat_king';
        const monsterBase = MONSTERS[monsterId] || MONSTERS['giant_rat'];
        monsters = [{ ...monsterBase, currentHp: monsterBase.stats.maxHp }];
    } else {
        // Band 1 Random Mobs pool (Sewer focus)
        const mobs = ['giant_rat', 'sewer_slime', 'mold_sporeling', 'carrion_beetle', 'sewer_thief', 'cave_bat', 'rat_man'];

        // Determine number of enemies based on Tier and Floor depth
        // Tier 1: 1-2, Tier 2: 1-3, Tier 3+: 2-4
        let monsterCount = Math.floor(Math.random() * tier) + 1;
        if (session.currentFloor > 3) monsterCount += 1;
        monsterCount = Math.min(4, Math.max(1, monsterCount));

        for (let i = 0; i < monsterCount; i++) {
            const monsterId = mobs[Math.floor(Math.random() * mobs.length)];
            const monsterBase = MONSTERS[monsterId] || MONSTERS['giant_rat'];
            // Individualize each monster with a unique instance ID suffix if needed, but for CombatView we just need the stats
            monsters.push({ ...monsterBase, currentHp: monsterBase.stats.maxHp });
        }
    }

    return {
        ...state,
        activeManualDungeon: {
            ...session,
            encounterStatus: 'BATTLE',
            enemies: monsters
        }
    };
};

export const handleResolveCombatManual = (state: GameState, payload: { win: boolean, flee: boolean, finalParty: any[] }): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const currentRoom = session.grid[session.playerPos.y][session.playerPos.x];
    let logMsg = '';

    const livingMembers = payload.finalParty.filter(p => p.currentHp > 0);

    // XP Calculation: Total XP from all killed enemies divided by survivors
    let totalXpGained = 0;
    if (payload.win && session.enemies) {
        totalXpGained = session.enemies.reduce((sum, e) => sum + e.rewardXp, 0);
    }

    const xpPerMember = (payload.win && totalXpGained > 0 && livingMembers.length > 0) 
        ? Math.floor(totalXpGained / livingMembers.length) 
        : 0;

    if (payload.win) {
        logMsg = `Engagement complete. Sector secured. XP awarded.`;
    }

    const newKnownMercenaries = state.knownMercenaries.map(m => {
        const combatant = payload.finalParty.find(p => p.id === m.id);
        if (combatant) {
            let nextXp = m.currentXp;
            let nextLevel = m.level;
            let nextMaxHp = m.maxHp;
            let nextMaxMp = m.maxMp;
            let nextCurrentHp = combatant.currentHp;
            let bonusStatPoints = m.bonusStatPoints || 0;

            if (payload.win && combatant.currentHp > 0) {
                nextXp += xpPerMember;
                while (nextXp >= m.xpToNextLevel) {
                    nextXp -= m.xpToNextLevel;
                    nextLevel++;
                    const merged = mergePrimaryStats(m.stats, m.allocatedStats);
                    nextMaxHp = calculateMaxHp(merged, nextLevel);
                    nextMaxMp = calculateMaxMp(merged, nextLevel);
                    nextCurrentHp = nextMaxHp;
                    bonusStatPoints += 3;
                }
            }

            return { 
                ...m, 
                currentHp: nextCurrentHp, 
                currentMp: combatant.currentMp,
                currentXp: nextXp,
                level: nextLevel,
                bonusStatPoints,
                maxHp: nextMaxHp,
                maxMp: nextMaxMp,
                xpToNextLevel: nextLevel * 100
            };
        }
        return m;
    });

    const isBossDefeated = (currentRoom === 'BOSS' && payload.win) || session.isBossDefeated;
    let nextGrid = [...session.grid.map(row => [...row])];
    if (payload.win && currentRoom === 'ENEMY') {
        nextGrid[session.playerPos.y][session.playerPos.x] = 'EMPTY';
    }

    return {
        ...state,
        knownMercenaries: newKnownMercenaries,
        activeManualDungeon: {
            ...session,
            grid: nextGrid,
            encounterStatus: payload.win ? 'VICTORY' : (payload.flee ? 'NONE' : 'DEFEAT'),
            isBossDefeated,
            lastActionMessage: payload.win 
                ? `Area neutralized. Combat systems on standby.`
                : (payload.flee ? `Withdrawal confirmed.` : `CRITICAL STATUS: Rescue required.`)
        },
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleRetreatManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const isDefeat = session.encounterStatus === 'DEFEAT' || 
                    state.knownMercenaries.filter(m => session.partyIds.includes(m.id)).every(m => m.currentHp <= 0);

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    const mercResults: DungeonResult['mercenaryResults'] = [];

    const updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextStatus: any = 'HIRED';
            let statusChange: 'NONE' | 'INJURED' | 'DEAD' = 'NONE';

            if (isDefeat) {
                const roll = Math.random();
                if (roll < 0.1) { nextStatus = 'DEAD'; statusChange = 'DEAD'; }
                else { 
                    nextStatus = 'INJURED'; statusChange = 'INJURED'; 
                    m.recoveryUntilDay = state.stats.day + 2; 
                }
            } else if (m.currentHp <= 0) {
                nextStatus = 'INJURED'; statusChange = 'INJURED';
                m.recoveryUntilDay = state.stats.day + 1;
            }

            mercResults.push({
                id: m.id, name: m.name, job: m.job, levelBefore: m.level, levelAfter: m.level,
                xpGained: 0, currentXp: m.currentXp, xpToNext: m.xpToNextLevel, statusChange
            });

            return { ...m, status: nextStatus, assignedExpeditionId: undefined };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercs,
        dungeonResult: isDefeat ? {
            dungeonName: dungeon?.name || 'Unknown',
            rewards: [],
            mercenaryResults: mercResults,
            isDefeat: true
        } : state.dungeonResult,
        activeManualDungeon: null,
        showManualDungeonOverlay: false,
        logs: [isDefeat ? 'CRITICAL FAILURE: Squad neutralized.' : 'Squad retreated.', ...state.logs]
    };
};

export const handleRescueNPC = (state: GameState, payload: { npcId: string }): GameState => {
    const currentSession = state.activeManualDungeon;
    if (!currentSession) return state;

    let newGrid = [...currentSession.grid.map(row => [...row])];
    newGrid[currentSession.playerPos.y][currentSession.playerPos.x] = 'EMPTY';

    return {
        ...state,
        activeManualDungeon: { 
            ...currentSession, 
            grid: newGrid, 
            npcFound: true, 
            rescuedNpcId: payload.npcId,
            lastActionMessage: `Survivor secured! Initiating extraction protocol.`
        },
        logs: [`Survivor secured! Initiating extraction.`, ...state.logs]
    };
};

export const handleFinishManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const tempExpId = `temp_manual_${Date.now()}`;
    const tempExp = {
        id: tempExpId,
        dungeonId: session.dungeonId,
        partyIds: session.partyIds,
        startTime: 0,
        endTime: 0,
        status: 'COMPLETED' as const
    };

    const stateWithTempExp = {
        ...state,
        activeExpeditions: [...state.activeExpeditions, tempExp]
    };

    const claimedState = handleClaimExpedition(stateWithTempExp, { 
        expeditionId: tempExpId, 
        rescuedNpcId: session.rescuedNpcId 
    });

    if (session.goldCollected > 0) {
        claimedState.stats.gold += session.goldCollected;
        if (claimedState.dungeonResult) {
            claimedState.dungeonResult.goldGained = (claimedState.dungeonResult.goldGained || 0) + session.goldCollected;
        }
    }

    return {
        ...claimedState,
        activeManualDungeon: null,
        showManualDungeonOverlay: false
    };
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Shield, Sword, Activity, Skull, Zap, LogOut, FastForward, Pause, ChevronDown, ChevronUp, Sparkles } from 'lucide-react';
import { Mercenary } from '../../../models/Mercenary';
import { Monster } from '../../../models/Monster';
import { ManualDungeonSession } from '../../../types/game-state';
import { calculateCombatResult } from '../../../utils/combatLogic';
import { calculateDerivedStats, applyEquipmentBonuses, mergePrimaryStats } from '../../../models/Stats';
import { useGame } from '../../../context/GameContext';
import { SKILLS } from '../../../data/skills';
import { MercenaryPortrait } from '../../common/ui/MercenaryPortrait';

const ACTION_THRESHOLD = 1000;

interface CombatLogEntry {
    msg: string;
    team: 'PLAYER' | 'ENEMY' | 'SYSTEM';
    isCrit?: boolean;
    isSkill?: boolean;
}

interface DamagePopup {
    id: number;
    value: number;
    targetId: string;
    isCrit: boolean;
    isSkill: boolean;
}

interface DungeonCombatViewProps {
    session: ManualDungeonSession;
    party: Mercenary[];
    enemies: Monster[]; // 단일 보스에서 분대로 변경
    fleeChance: number;
    onFinish: (win: boolean, finalParty: any[]) => void;
    onFlee: (finalParty: any[]) => void;
}

const DungeonCombatView: React.FC<DungeonCombatViewProps> = ({ party, enemies, fleeChance, onFinish, onFlee }) => {
    const [partyState, setPartyState] = useState(party.map(m => {
        const primary = mergePrimaryStats(m.stats, m.allocatedStats);
        const derived = applyEquipmentBonuses(calculateDerivedStats(primary, m.level), (Object.values(m.equipment) as any[]).map(e=>e?.stats).filter(Boolean) as any);
        return { ...m, derived, currentHp: m.currentHp, currentMp: m.currentMp, gauge: 0, lastDamaged: false };
    }));

    const [enemySquadState, setEnemySquadState] = useState(enemies.map((e, idx) => ({
        ...e,
        instanceId: `enemy_${idx}`,
        gauge: 0,
        lastDamaged: false,
        hasUsedRevival: false
    })));

    const [logs, setLogs] = useState<CombatLogEntry[]>([]);
    const [damagePopups, setDamagePopups] = useState<DamagePopup[]>([]);
    const [isAuto, setIsAuto] = useState(true);
    const [isPaused, setIsPaused] = useState(false);
    const [activeActorId, setActiveActorId] = useState<string | null>(null); 
    const [showLogs, setShowLogs] = useState(false);
    const battleInterval = useRef<ReturnType<typeof setInterval> | null>(null);

    const addLog = (msg: string, team: 'PLAYER' | 'ENEMY' | 'SYSTEM', isCrit = false, isSkill = false) => {
        setLogs(prev => [{ msg, team, isCrit, isSkill }, ...prev].slice(0, 50));
    };

    const triggerDamagePopup = (targetId: string, value: number, isCrit: boolean, isSkill: boolean) => {
        const id = Date.now() + Math.random();
        setDamagePopups(prev => [...prev, { id, value, targetId, isCrit, isSkill }]);
        setTimeout(() => {
            setDamagePopups(prev => prev.filter(p => p.id !== id));
        }, 800);
    };

    const executeAttack = useCallback((attacker: any, target: any, isPlayerAttacker: boolean, skillId?: string) => {
        const skill = skillId ? SKILLS[skillId] : null;
        const multiplier = skill ? skill.multiplier : 1.0;
        const mpCost = skill ? skill.mpCost : 0;

        const res = calculateCombatResult(
            isPlayerAttacker ? attacker.derived : attacker.stats,
            isPlayerAttacker ? target.stats : target.derived,
            isPlayerAttacker ? attacker.job : 'Fighter' as any,
            isPlayerAttacker ? (attacker.derived.magicalAttack > attacker.derived.physicalAttack ? 'MAGICAL' : 'PHYSICAL') : 'PHYSICAL',
            multiplier
        );

        if (isPlayerAttacker) {
            setEnemySquadState(prev => prev.map(e => {
                if (e.instanceId === target.instanceId) {
                    const next = { ...e, lastDamaged: res.isHit };
                    if (res.isHit) {
                        let nextHp = Math.max(0, next.currentHp - res.damage);

                        // Special Revival Logic for Phoenix
                        if (nextHp <= 0 && next.id === 'phoenix' && !next.hasUsedRevival) {
                            nextHp = next.stats.maxHp;
                            next.hasUsedRevival = true;
                            addLog("The Phoenix bursts into blinding flames and rises from the ashes!", 'ENEMY', true, true);
                            triggerDamagePopup(target.instanceId, 0, true, true);
                        } else {
                            next.currentHp = nextHp;
                        }
                        triggerDamagePopup(target.instanceId, res.damage, res.isCrit, !!skill);
                    }
                    setTimeout(() => setEnemySquadState(curr => curr.map(currE => currE.instanceId === target.instanceId ? { ...currE, lastDamaged: false } : currE)), 200);
                    return next;
                }
                return e;
            }));

            if (skill) {
                setPartyState(prev => prev.map(p => p.id === attacker.id ? { ...p, currentMp: Math.max(0, p.currentMp - mpCost) } : p));
                addLog(`${attacker.name.split(' ')[0]} uses ${skill.name}! Deals ${res.damage} to ${target.name}${res.isCrit ? "!" : ""}`, 'PLAYER', res.isCrit, true);
            } else {
                addLog(`${attacker.name.split(' ')[0]} strikes ${target.name} for ${res.damage}${res.isCrit ? "!" : ""}`, 'PLAYER', res.isCrit);
            }
        } else {
            setPartyState(prev => prev.map(p => {
                if (p.id === target.id) {
                    const next = { ...p, lastDamaged: res.isHit };
                    if (res.isHit) {
                        next.currentHp = Math.max(0, next.currentHp - res.damage);
                        triggerDamagePopup(p.id, res.damage, res.isCrit, false);
                    }
                    setTimeout(() => setPartyState(curr => curr.map(c => c.id === p.id ? { ...c, lastDamaged: false } : c)), 200);
                    return next;
                }
                return p;
            }));
            addLog(`${attacker.name} strikes ${target.name.split(' ')[0]} for ${res.damage}`, 'ENEMY');
        }
    }, [addLog]);

    const processLoop = useCallback(() => {
        if (isPaused || activeActorId) return;

        setPartyState(prevParty => {
            const nextParty = [...prevParty];
            setEnemySquadState(prevEnemySquad => {
                const nextEnemySquad = [...prevEnemySquad];

                // 1. Tick Gauges
                nextParty.forEach(p => { if (p.currentHp > 0) p.gauge += p.derived.speed * 0.5; });
                nextEnemySquad.forEach(e => { if (e.currentHp > 0) e.gauge += e.stats.speed * 0.5; });

                // 2. Player Turns
                const readyMerc = nextParty.find(p => p.currentHp > 0 && p.gauge >= ACTION_THRESHOLD);
                if (readyMerc) {
                    const livingEnemies = nextEnemySquad.filter(e => e.currentHp > 0);
                    if (livingEnemies.length > 0) {
                        const targetEnemy = livingEnemies[0]; // Auto-target first living enemy
                        if (isAuto) {
                            readyMerc.gauge -= ACTION_THRESHOLD;
                            let chosenSkillId: string | undefined = undefined;
                            if (readyMerc.skillIds && readyMerc.skillIds.length > 0) {
                                const availableSkills = readyMerc.skillIds.map(id => SKILLS[id]).filter(s => readyMerc.currentMp >= s.mpCost);
                                if (availableSkills.length > 0) {
                                    chosenSkillId = availableSkills.sort((a, b) => b.multiplier - a.multiplier)[0].id;
                                }
                            }
                            executeAttack(readyMerc, targetEnemy, true, chosenSkillId);
                        } else {
                            setActiveActorId(readyMerc.id);
                        }
                    }
                }

                // 3. Enemy Turns
                const readyEnemy = nextEnemySquad.find(e => e.currentHp > 0 && e.gauge >= ACTION_THRESHOLD);
                if (readyEnemy && !activeActorId) {
                    const livingPlayers = nextParty.filter(p => p.currentHp > 0);
                    if (livingPlayers.length > 0) {
                        readyEnemy.gauge -= ACTION_THRESHOLD;
                        const targetPlayer = livingPlayers[Math.floor(Math.random() * livingPlayers.length)];
                        executeAttack(readyEnemy, targetPlayer, false);
                    }
                }

                return nextEnemySquad;
            });
            return nextParty;
        });
    }, [isPaused, isAuto, activeActorId, executeAttack]);

    useEffect(() => {
        battleInterval.current = setInterval(processLoop, 100);
        return () => { if (battleInterval.current) clearInterval(battleInterval.current); };
    }, [processLoop]);

    const handleManualCommand = (type: 'ATTACK' | 'FLEE' | 'SKILL', skillId?: string) => {
        if (!activeActorId) return;
        const actor = partyState.find(p => p.id === activeActorId);
        const livingEnemies = enemySquadState.filter(e => e.currentHp > 0);
        if (!actor || livingEnemies.length === 0) return;

        if (type === 'ATTACK' || (type === 'SKILL' && skillId)) {
            setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: p.gauge - ACTION_THRESHOLD } : p));
            executeAttack(actor, livingEnemies[0], true, skillId);
            setActiveActorId(null);
        } else if (type === 'FLEE') {
            const roll = Math.random() * 100;
            if (roll < fleeChance) {
                onFlee(partyState);
            } else {
                addLog(`${actor.name.split(' ')[0]} failed to find escape route!`, 'SYSTEM');
                setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: p.gauge - ACTION_THRESHOLD } : p));
                setActiveActorId(null);
            }
        }
    };

    useEffect(() => {
        if (enemySquadState.every(e => e.currentHp <= 0)) {
            setIsPaused(true);
            setTimeout(() => onFinish(true, partyState), 1000);
        } else if (partyState.every(p => p.currentHp <= 0)) {
            setIsPaused(true);
            setTimeout(() => onFinish(false, partyState), 1000);
        }
    }, [enemySquadState, partyState, onFinish]);

    return (
        <div className="fixed inset-0 z-[110] flex flex-col bg-stone-950 animate-in zoom-in-95 duration-500 overflow-hidden">
            <style>{`
                @keyframes damage-float {
                    0% { transform: translateY(0); opacity: 0; }
                    20% { opacity: 1; }
                    100% { transform: translateY(-40px); opacity: 0; }
                }
                .animate-damage { animation: damage-float 0.8s ease-out forwards; }
            `}</style>

            {/* Header */}
            <div className="p-3 bg-red-950/20 border-b border-red-900/30 flex justify-between items-center shrink-0">
                <div className="flex items-center gap-2">
                    <Skull className="w-4 h-4 text-red-500" />
                    <h2 className="text-white font-black uppercase text-sm tracking-widest">Combat Phase</h2>
