                            <div className="relative">
                                <div className="text-5xl md:text-6xl drop-shadow-[0_0_20px_rgba(239,68,68,0.2)]">{e.icon}</div>
                                {damagePopups.filter(p => p.targetId === e.instanceId).map(p => (
                                    <div key={p.id} className={`absolute -top-4 left-1/2 -translate-x-1/2 font-black text-xl animate-damage ${p.isSkill ? 'text-blue-400 scale-150' : p.isCrit ? 'text-amber-400 scale-125' : 'text-red-500'}`}>
                                        -{p.value}
                                    </div>
                                ))}
                            </div>
                            {e.currentHp > 0 && (
                                <div className="mt-3 w-16 md:w-24 space-y-1">
                                    <div className="h-1.5 bg-stone-950 rounded-full overflow-hidden border border-white/5">
                                        <div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(e.currentHp/e.stats.maxHp)*100}%` }} />
