const AssaultNavigator = () => {
    const { state, actions } = useGame();
    const session = state.activeManualDungeon;
    const gameRef = useRef<Phaser.Game | null>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const [isReady, setIsReady] = useState(false);
    const [showRetreatConfirm, setShowRetreatConfirm] = useState(false);
    const [lastMsg, setLastMsg] = useState("");

    // --- D-pad & Camera Zoom State ---
    const [dpadTransform, setDpadTransform] = useState(() => {
        const saved = localStorage.getItem('dpad_transform_v2'); 
        let parsed = saved ? JSON.parse(saved) : { x: 0, y: 0, scale: 0.8, opacity: 1.0 };
        if (parsed.scale > 1.2) parsed.scale = 1.2;
        if (parsed.scale < 0.4) parsed.scale = 0.4;
        if (parsed.opacity === undefined) parsed.opacity = 1.0;
        return parsed;
    });
    const [isDraggingDpad, setIsDraggingDpad] = useState(false);
    const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
    const [mapZoom, setMapZoom] = useState(1.0);
    const [showDpadMenu, setShowDpadMenu] = useState(false);

    const rafRef = useRef<number | null>(null);

    const dungeon = session ? DUNGEONS.find(d => d.id === session.dungeonId) : null;
    const party = useMemo(() => {
        if (!session) return [];
        return state.knownMercenaries.filter(m => session.partyIds.includes(m.id));
    }, [session?.partyIds, state.knownMercenaries]);

    const isEncountered = session?.encounterStatus === 'ENCOUNTERED';
    const isBattle = session?.encounterStatus === 'BATTLE';
    const currentRoom = session ? session.grid[session.playerPos.y][session.playerPos.x] : null;

    useEffect(() => {
        if (session?.lastActionMessage) {
            setLastMsg(session.lastActionMessage);
        }
    }, [session?.lastActionMessage]);

    useEffect(() => {
        if (!session) return;
        if (currentRoom === 'NPC' && !session.npcFound) {
            setLastMsg(`"Help! Please... is someone there? The rats... they're everywhere..."`);
        }
    }, [currentRoom, session?.npcFound]);

    const handleDpadMove = (dx: number, dy: number) => {
        if (isEncountered || isBattle) return;
        const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
        if (scene) scene.move(dx, dy);
    };

    const handleDragStart = (e: React.MouseEvent | React.TouchEvent) => {
        setIsDraggingDpad(true);
        const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
        const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;
        setDragStart({ x: clientX - dpadTransform.x, y: clientY - dpadTransform.y });
    };

    const handleDragMove = useCallback((e: MouseEvent | TouchEvent) => {
        if (!isDraggingDpad) return;
        if (rafRef.current) cancelAnimationFrame(rafRef.current);
        rafRef.current = requestAnimationFrame(() => {
            const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
            const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;
            setDpadTransform((prev: any) => {
                const nextX = clientX - dragStart.x;
                const nextY = clientY - dragStart.y;
                return { ...prev, x: nextX, y: nextY };
            });
            rafRef.current = null;
        });
    }, [isDraggingDpad, dragStart.x, dragStart.y]);

    const handleDragEnd = useCallback(() => {
        if (isDraggingDpad) {
            setIsDraggingDpad(false);
            if (rafRef.current) {
                cancelAnimationFrame(rafRef.current);
                rafRef.current = null;
            }
            localStorage.setItem('dpad_transform_v2', JSON.stringify(dpadTransform));
        }
    }, [isDraggingDpad, dpadTransform]);

    useEffect(() => {
        if (isDraggingDpad) {
            window.addEventListener('mousemove', handleDragMove, { passive: true });
            window.addEventListener('mouseup', handleDragEnd);
            window.addEventListener('touchmove', handleDragMove, { passive: true });
            window.addEventListener('touchend', handleDragEnd);
        }
        return () => {
            window.removeEventListener('mousemove', handleDragMove);
            window.removeEventListener('mouseup', handleDragEnd);
            window.removeEventListener('touchmove', handleDragMove);
            window.removeEventListener('touchend', handleDragEnd);
        };
    }, [isDraggingDpad, handleDragMove, handleDragEnd]);

    const cycleDpadScale = () => {
        setDpadTransform((prev: any) => {
            let nextScale = prev.scale + 0.2;
            if (nextScale > 1.25) nextScale = 0.4;
            const next = { ...prev, scale: parseFloat(nextScale.toFixed(1)) };
            localStorage.setItem('dpad_transform_v2', JSON.stringify(next));
            return next;
        });
    };

    const handleOpacityChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const val = parseFloat(e.target.value);
        setDpadTransform((prev: any) => {
            const next = { ...prev, opacity: val };
            localStorage.setItem('dpad_transform_v2', JSON.stringify(next));
            return next;
        });
    };

    const handleZoom = (delta: number) => {
        const nextZoom = Math.min(1.5, Math.max(0.5, mapZoom + delta));
        setMapZoom(nextZoom);
        const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
        if (scene) scene.updateZoom(nextZoom);
    };

    useEffect(() => {
        if (!isReady || !containerRef.current || !session || !dungeon) return;
        if (!gameRef.current) {
            const config: Phaser.Types.Core.GameConfig = {
                type: Phaser.AUTO, parent: containerRef.current, width: containerRef.current.clientWidth, height: containerRef.current.clientHeight, backgroundColor: 'transparent', transparent: true, scene: [DungeonScene],
                scale: { mode: Phaser.Scale.RESIZE, autoCenter: Phaser.Scale.CENTER_BOTH }
            };
            const game = new Phaser.Game(config);
            gameRef.current = game;
            game.scene.start('DungeonScene', { 
                session, 
                onMove: (dx: number, dy: number) => actions.moveInManualDungeon(dx, dy),
                initialZoom: mapZoom 
            });
        } else {
            const scene = gameRef.current.scene.getScene('DungeonScene') as DungeonScene;
            if (scene) scene.updateSession(session);
        }
    }, [isReady, session, actions, dungeon]);

    useEffect(() => {
        const check = () => { if (containerRef.current?.clientWidth) setIsReady(true); else requestAnimationFrame(check); };
        check();
    }, []);

    if (!session || !dungeon) return null;

    const isOnNPCTile = currentRoom === 'NPC' && !session.npcFound;

    return (
        <div className="absolute inset-0 z-[100] bg-stone-950 flex flex-col animate-in fade-in duration-500 overflow-hidden">
            <div ref={containerRef} className={`absolute inset-0 z-0 transition-opacity ${isBattle ? 'opacity-20 blur-md' : 'opacity-100'}`} />

            {!isBattle && <SquadPanel party={party} />}

            {/* Top Center: Floor Display */}
            {!isBattle && (
                <div className="absolute top-4 left-1/2 -translate-x-1/2 z-[110] flex items-center gap-3 px-4 py-2 bg-stone-900/90 backdrop-blur-md border border-amber-500/30 rounded-2xl shadow-2xl">
                    <Layers className="w-4 h-4 text-amber-500" />
                    <span className="text-xs md:text-sm font-black text-amber-50 uppercase tracking-widest font-mono">
                        Floor {session.currentFloor} / {session.maxFloors}
                    </span>
                </div>
            )}

            {/* Top Right: Zoom & Key Controls */}
            <div className="absolute top-4 right-4 z-[110] flex flex-col items-end gap-2 pointer-events-auto">
                <div className={`flex items-center gap-2 px-3 py-1.5 bg-stone-900/80 backdrop-blur-md border rounded-xl shadow-xl transition-all ${session.hasKey ? 'border-amber-500 text-amber-400' : 'border-white/5 text-stone-600 opacity-40'}`}>
                    <Key className={`w-4 h-4 ${session.hasKey ? 'animate-pulse' : ''}`} />
                    <span className="text-[10px] font-black uppercase tracking-widest">{session.hasKey ? 'Key Found' : 'No Key'}</span>
                </div>

                <div className="flex bg-stone-900/80 backdrop-blur-md border border-white/10 rounded-xl overflow-hidden shadow-2xl">
                    <button onClick={() => handleZoom(0.1)} className="p-2.5 hover:bg-stone-800 text-stone-300 transition-colors border-r border-white/5"><Plus className="w-4 h-4" /></button>
                    <div className="flex flex-col items-center justify-center px-2 min-w-[45px] select-none">
                        <span className="text-[8px] font-black text-stone-500 font-bold leading-none">ZOOM</span>
                        <span className="text-[10px] font-mono font-bold text-amber-500">{mapZoom.toFixed(1)}x</span>
                    </div>
                    <button onClick={() => handleZoom(-0.1)} className="p-2.5 hover:bg-stone-800 text-stone-300 transition-colors border-l border-white/5"><Minus className="w-4 h-4" /></button>
                </div>

                <button 
                    onClick={() => setShowRetreatConfirm(true)}
                    className="flex items-center gap-2 px-3 py-2 bg-red-950/40 hover:bg-red-900/60 border border-red-900/30 rounded-xl text-red-500 font-bold text-[10px] uppercase tracking-widest transition-all shadow-xl"
                >
                    <LogOut className="w-4 h-4" /> Retreat
                </button>
            </div>

            {/* NPC Discovery Scene */}
            {isOnNPCTile && (
                <div className="absolute inset-0 z-40 flex flex-col items-center justify-end pointer-events-none pb-20">
                    <div className="relative flex justify-center items-end w-full h-[80dvh] animate-in fade-in zoom-in slide-in-from-bottom-12 duration-1000 ease-out">
                        <div className="absolute bottom-[20%] left-1/2 -translate-x-1/2 w-64 h-64 bg-amber-500/20 blur-[80px] rounded-full -z-10 animate-pulse"></div>
                        <div className="absolute bottom-[10%] left-1/2 -translate-x-1/2 w-48 h-10 bg-black/60 blur-2xl rounded-full -z-10"></div>
                        <div className="absolute bottom-[30%] left-1/2 -translate-x-1/2 z-0">
                            <Sparkles className="w-12 h-12 text-amber-300 opacity-40 animate-bounce" />
                        </div>
                        <AnimatedMercenary
                            mercenary={TILLY_FOOTLOOSE}
                            className="h-full w-auto filter drop-shadow-[0_0_50px_rgba(245,158,11,0.5)] transition-all duration-500 relative z-10"
                        />
                    </div>
                </div>
            )}

            {isBattle && (
                <DungeonCombatView 
                    /* Fix: use 'enemies' prop instead of 'boss' and 'session.enemies' instead of 'session.bossEntity' */
                    session={session} party={party} enemies={session.enemies || []} fleeChance={50}
                    onFinish={(win, final) => actions.resolveCombatManual(win, false, final)}
                    onFlee={(final) => actions.resolveCombatManual(false, true, final)}
                />
            )}

            {!isBattle && (
                <>
                    {/* Draggable D-pad Container */}
                    {!isOnNPCTile && (
                        <div 
                            className={`pointer-events-auto transition-all z-[200] select-none ${isDraggingDpad ? 'shadow-glow-amber cursor-grabbing' : 'cursor-default'}`}
                            style={{
                                position: 'absolute',
                                bottom: 'calc(22dvh + 32px)',
                                right: 16,
                                transform: `translate3d(${dpadTransform.x}px, ${dpadTransform.y}px, 0) scale(${dpadTransform.scale})`,
                                opacity: dpadTransform.opacity,
                                transformOrigin: 'bottom right',
                                willChange: 'transform'
                            }}
                        >
                            <div className="grid grid-cols-3 gap-2 bg-stone-900/90 backdrop-blur-xl p-3 rounded-3xl border border-white/10 shadow-2xl relative">

                                {showDpadMenu && (
                                    <div className="absolute -top-12 right-0 flex items-center gap-3 pointer-events-auto animate-in fade-in slide-in-from-bottom-2 duration-300">
                                        <div className="flex items-center gap-2 bg-stone-900/80 border border-white/10 px-3 py-1.5 rounded-full shadow-lg backdrop-blur-md">
                                            <Ghost className="w-3.5 h-3.5 text-stone-500" />
                                            <input 
                                                type="range" min="0.1" max="1.0" step="0.1"
                                                value={dpadTransform.opacity}
                                                onChange={handleOpacityChange}
                                                className="w-16 h-1 bg-stone-700 rounded-lg appearance-none cursor-pointer accent-amber-500"
                                            />
                                            <span className="text-[8px] font-mono font-bold text-stone-400 w-6">{Math.round(dpadTransform.opacity * 100)}%</span>
                                        </div>

                                        <div className="flex items-center gap-2">
                                            <div 
                                                onMouseDown={handleDragStart} onTouchStart={handleDragStart}
                                                className="w-9 h-9 bg-stone-800 border border-white/20 rounded-full flex items-center justify-center text-blue-400 cursor-grab active:cursor-grabbing hover:bg-stone-700 transition-all shadow-lg active:scale-95"
                                            >
                                                <Move className="w-4 h-4" />
                                            </div>
                                            <button 
                                                onClick={cycleDpadScale}
                                                className="w-9 h-9 bg-stone-800 border border-white/20 rounded-full flex items-center justify-center text-stone-300 hover:text-white transition-all shadow-lg active:scale-90"
                                            >
                                                {dpadTransform.scale >= 1.2 ? <Minimize className="w-4 h-4" /> : <Maximize className="w-4 h-4" />}
                                            </button>
                                        </div>
                                    </div>
                                )}

                                <div />
                                <button onClick={() => handleDpadMove(0,-1)} className="w-12 h-12 bg-stone-800 rounded-xl flex items-center justify-center text-white active:bg-stone-700 shadow-lg"><ChevronUp /></button>

                                <button 
                                    onClick={() => setShowDpadMenu(!showDpadMenu)}
                                    className={`w-12 h-12 rounded-xl flex items-center justify-center transition-all ${showDpadMenu ? 'bg-amber-600 text-white shadow-glow-amber' : 'bg-stone-800 text-stone-500 hover:text-stone-300'}`}
                                >
                                    <Settings className={`w-6 h-6 ${showDpadMenu ? 'animate-spin-slow' : ''}`} />
                                </button>

                                <button onClick={() => handleDpadMove(-1,0)} className="w-12 h-12 bg-stone-800 rounded-xl flex items-center justify-center text-white active:bg-stone-700 shadow-lg"><ChevronLeft /></button>

                                <div className="w-12 h-12 bg-blue-900/20 rounded-xl flex items-center justify-center text-blue-400/40">
                                    <Zap className="w-6 h-6" />
                                </div>

                                <button onClick={() => handleDpadMove(1,0)} className="w-12 h-12 bg-stone-800 rounded-xl flex items-center justify-center text-white active:bg-stone-700 shadow-lg"><ChevronRight /></button>

                                <div />
                                <button onClick={() => handleDpadMove(0,1)} className="w-12 h-12 bg-stone-800 rounded-xl flex items-center justify-center text-white active:bg-stone-700 shadow-lg"><ChevronDown /></button>
                                <div />
                            </div>
                        </div>
                    )}

                    {/* Bottom dialogue box container */}
                    <div className="absolute bottom-4 left-1/2 -translate-x-1/2 w-[95vw] max-w-5xl z-50 pointer-events-none">
                        <div className="flex flex-col items-end gap-4 relative">
                            <DialogueBox 
                                speaker={isOnNPCTile ? "Tilly Footloose" : isEncountered ? "Tactical AI" : "Comms Link"}
                                speakerAvatar={isOnNPCTile ? getAssetUrl(TILLY_FOOTLOOSE.profileImage || 'tilly_footloose.png') : undefined}
                                text={lastMsg}
                                options={isOnNPCTile ? [
                                    { label: "RESCUE SURVIVOR", action: () => { actions.rescueMercenary('tilly_footloose'); actions.showToast("Tilly Footloose has been secured!"); }, variant: 'primary' },
                                    { label: "LEAVE FOR NOW", action: () => setLastMsg("Sector marked for later extraction. Resuming scan."), variant: 'neutral' }
                                ] : isEncountered ? [
                                    { label: "ENGAGE TARGET", action: () => actions.startCombatManual(), variant: 'primary' },
                                    { label: "RETREAT", action: () => setShowRetreatConfirm(true), variant: 'neutral' }
                                ] : currentRoom === 'ENTRANCE' && session.isBossDefeated ? [
                                    { label: "FINISH MISSION", action: () => actions.finishManualAssault(), variant: 'primary' }
                                ] : []}
                                className="w-full pointer-events-auto"
                            />
                        </div>
                    </div>
                </>
            )}

            <ConfirmationModal isOpen={showRetreatConfirm} title="Abort Mission?" message="Extraction will return the squad to safety. No rewards will be collected." onConfirm={() => actions.retreatFromManualDungeon()} onCancel={() => setShowRetreatConfirm(false)} isDanger={true} />
        </div>
    );
};

export default AssaultNavigator;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Shield, Sword, Activity, Skull, Zap, LogOut, FastForward, Pause, ChevronDown, ChevronUp, Sparkles, Target } from 'lucide-react';
import { Mercenary } from '../../../models/Mercenary';
import { Monster } from '../../../models/Monster';
import { ManualDungeonSession } from '../../../types/game-state';
import { calculateCombatResult } from '../../../utils/combatLogic';
import { calculateDerivedStats, applyEquipmentBonuses, mergePrimaryStats } from '../../../models/Stats';
import { useGame } from '../../../context/GameContext';
import { SKILLS } from '../../../data/skills';
import { MercenaryPortrait } from '../../common/ui/MercenaryPortrait';

const ACTION_THRESHOLD = 1000;

interface CombatLogEntry {
    msg: string;
    team: 'PLAYER' | 'ENEMY' | 'SYSTEM';
    isCrit?: boolean;
    isSkill?: boolean;
}

interface DamagePopup {
    id: number;
    value: number;
    targetId: string;
    isCrit: boolean;
    isSkill: boolean;
}

interface DungeonCombatViewProps {
    session: ManualDungeonSession;
    party: Mercenary[];
    enemies: Monster[];
    fleeChance: number;
    onFinish: (win: boolean, finalParty: any[]) => void;
    onFlee: (finalParty: any[]) => void;
}

const DungeonCombatView: React.FC<DungeonCombatViewProps> = ({ party, enemies, fleeChance, onFinish, onFlee }) => {
    const { actions } = useGame();
    const [partyState, setPartyState] = useState(party.map(m => {
        const primary = mergePrimaryStats(m.stats, m.allocatedStats);
        const derived = applyEquipmentBonuses(calculateDerivedStats(primary, m.level), (Object.values(m.equipment) as any[]).map(e=>e?.stats).filter(Boolean) as any);
        return { ...m, derived, currentHp: m.currentHp, currentMp: m.currentMp, gauge: 0, lastDamaged: false };
    }));

    const [enemySquadState, setEnemySquadState] = useState(enemies.map((e, idx) => ({
        ...e,
        instanceId: `enemy_${idx}`,
        gauge: 0,
        lastDamaged: false,
        hasUsedRevival: false
    })));

    const [logs, setLogs] = useState<CombatLogEntry[]>([]);
    const [damagePopups, setDamagePopups] = useState<DamagePopup[]>([]);
    const [isAuto, setIsAuto] = useState(true);
    const [isPaused, setIsPaused] = useState(false);
    const [activeActorId, setActiveActorId] = useState<string | null>(null); 
    const [showLogs, setShowLogs] = useState(false);
    const battleInterval = useRef<ReturnType<typeof setInterval> | null>(null);

    const addLog = (msg: string, team: 'PLAYER' | 'ENEMY' | 'SYSTEM', isCrit = false, isSkill = false) => {
        setLogs(prev => [{ msg, team, isCrit, isSkill }, ...prev].slice(0, 50));
    };

    const triggerDamagePopup = (targetId: string, value: number, isCrit: boolean, isSkill: boolean) => {
        const id = Date.now() + Math.random();
        setDamagePopups(prev => [...prev, { id, value, targetId, isCrit, isSkill }]);
        setTimeout(() => {
            setDamagePopups(prev => prev.filter(p => p.id !== id));
        }, 800);
    };

    const executeAttack = useCallback((attacker: any, target: any, isPlayerAttacker: boolean, skillId?: string) => {
        const skill = skillId ? SKILLS[skillId] : null;
        const multiplier = skill ? skill.multiplier : 1.0;
        const mpCost = skill ? skill.mpCost : 0;

        const res = calculateCombatResult(
            isPlayerAttacker ? attacker.derived : attacker.stats,
            isPlayerAttacker ? target.stats : target.derived,
            isPlayerAttacker ? attacker.job : 'Fighter' as any,
            isPlayerAttacker ? (attacker.derived.magicalAttack > attacker.derived.physicalAttack ? 'MAGICAL' : 'PHYSICAL') : 'PHYSICAL',
            multiplier
        );

        if (isPlayerAttacker) {
            setEnemySquadState(prev => prev.map(e => {
                if (e.instanceId === target.instanceId) {
                    const next = { ...e, lastDamaged: res.isHit };
                    if (res.isHit) {
                        let nextHp = Math.max(0, next.currentHp - res.damage);
                        if (nextHp <= 0 && next.id === 'phoenix' && !next.hasUsedRevival) {
                            nextHp = next.stats.maxHp;
                            next.hasUsedRevival = true;
                            addLog("The Phoenix bursts into blinding flames and rises from the ashes!", 'ENEMY', true, true);
                            triggerDamagePopup(target.instanceId, 0, true, true);
                        } else {
                            next.currentHp = nextHp;
                        }
                        triggerDamagePopup(target.instanceId, res.damage, res.isCrit, !!skill);
                    }
                    setTimeout(() => setEnemySquadState(curr => curr.map(currE => currE.instanceId === target.instanceId ? { ...currE, lastDamaged: false } : currE)), 200);
                    return next;
                }
                return e;
            }));

            if (skill) {
                setPartyState(prev => prev.map(p => p.id === attacker.id ? { ...p, currentMp: Math.max(0, p.currentMp - mpCost) } : p));
                addLog(`${attacker.name.split(' ')[0]} uses ${skill.name}!`, 'PLAYER', res.isCrit, true);
            } else {
                addLog(`${attacker.name.split(' ')[0]} strikes ${target.name} for ${res.damage}`, 'PLAYER', res.isCrit);
            }
        } else {
            setPartyState(prev => prev.map(p => {
                if (p.id === target.id) {
                    const next = { ...p, lastDamaged: res.isHit };
                    if (res.isHit) {
                        next.currentHp = Math.max(0, next.currentHp - res.damage);
                        triggerDamagePopup(p.id, res.damage, res.isCrit, false);
                    }
                    setTimeout(() => setPartyState(curr => curr.map(c => c.id === p.id ? { ...c, lastDamaged: false } : c)), 200);
                    return next;
                }
                return p;
            }));
            addLog(`${attacker.name} strikes ${target.name.split(' ')[0]} for ${res.damage}`, 'ENEMY');
        }
    }, [addLog]);

    const processLoop = useCallback(() => {
        if (isPaused || activeActorId) return;

        setPartyState(prevParty => {
            const nextParty = [...prevParty];
            setEnemySquadState(prevEnemySquad => {
                const nextEnemySquad = [...prevEnemySquad];

                // 1. Tick Gauges
                nextParty.forEach(p => { if (p.currentHp > 0) p.gauge += p.derived.speed * 0.5; });
                nextEnemySquad.forEach(e => { if (e.currentHp > 0) e.gauge += e.stats.speed * 0.5; });

                // 2. Player Turns
                const readyMerc = nextParty.find(p => p.currentHp > 0 && p.gauge >= ACTION_THRESHOLD);
                if (readyMerc) {
                    const livingEnemies = nextEnemySquad.filter(e => e.currentHp > 0);
                    if (livingEnemies.length > 0) {
                        const targetEnemy = livingEnemies[0]; 
                        if (isAuto) {
                            readyMerc.gauge -= ACTION_THRESHOLD;
                            let chosenSkillId: string | undefined = undefined;
                            if (readyMerc.skillIds && readyMerc.skillIds.length > 0) {
                                const availableSkills = readyMerc.skillIds.map(id => SKILLS[id]).filter(s => readyMerc.currentMp >= s.mpCost);
                                if (availableSkills.length > 0) {
                                    chosenSkillId = availableSkills.sort((a, b) => b.multiplier - a.multiplier)[0].id;
                                }
                            }
                            executeAttack(readyMerc, targetEnemy, true, chosenSkillId);
                        } else {
                            setActiveActorId(readyMerc.id);
                        }
                    }
                }

                // 3. Enemy Turns
                const readyEnemy = nextEnemySquad.find(e => e.currentHp > 0 && e.gauge >= ACTION_THRESHOLD);
                if (readyEnemy && !activeActorId) {
                    const livingPlayers = nextParty.filter(p => p.currentHp > 0);
                    if (livingPlayers.length > 0) {
                        readyEnemy.gauge -= ACTION_THRESHOLD;
                        const targetPlayer = livingPlayers[Math.floor(Math.random() * livingPlayers.length)];
                        executeAttack(readyEnemy, targetPlayer, false);
                    }
                }

                return nextEnemySquad;
            });
            return nextParty;
        });
    }, [isPaused, isAuto, activeActorId, executeAttack]);

    useEffect(() => {
        battleInterval.current = setInterval(processLoop, 100);
        return () => { if (battleInterval.current) clearInterval(battleInterval.current); };
    }, [processLoop]);

    const handleManualCommand = (type: 'ATTACK' | 'FLEE' | 'SKILL', skillId?: string) => {
        if (!activeActorId) return;
        const actor = partyState.find(p => p.id === activeActorId);
        const livingEnemies = enemySquadState.filter(e => e.currentHp > 0);
        if (!actor || livingEnemies.length === 0) return;

        if (type === 'ATTACK' || (type === 'SKILL' && skillId)) {
            setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: p.gauge - ACTION_THRESHOLD } : p));
            executeAttack(actor, livingEnemies[0], true, skillId);
            setActiveActorId(null);
        } else if (type === 'FLEE') {
            const roll = Math.random() * 100;
            if (roll < fleeChance) {
                onFlee(partyState);
            } else {
                addLog(`${actor.name.split(' ')[0]} failed to find escape route!`, 'SYSTEM');
                setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: p.gauge - ACTION_THRESHOLD } : p));
                setActiveActorId(null);
            }
        }
    };

    useEffect(() => {
        if (enemySquadState.every(e => e.currentHp <= 0)) {
            setIsPaused(true);
            setTimeout(() => onFinish(true, partyState), 1000);
        } else if (partyState.every(p => p.currentHp <= 0)) {
            setIsPaused(true);
            setTimeout(() => onFinish(false, partyState), 1000);
        }
    }, [enemySquadState, partyState, onFinish]);

    return (
        <div className="fixed inset-0 z-[150] flex flex-col bg-stone-950 animate-in fade-in duration-500 overflow-hidden select-none">
            <style>{`
                @keyframes damage-float {
                    0% { transform: translateY(0) scale(0.8); opacity: 0; }
                    20% { opacity: 1; scale: 1.2; }
                    100% { transform: translateY(-60px) scale(1.0); opacity: 0; }
                }
                .animate-damage { animation: damage-float 1s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }
            `}</style>

            {/* Top Toolbar */}
            <div className="p-3 bg-red-950/20 border-b border-red-900/30 flex justify-between items-center shrink-0 z-10">
                <div className="flex items-center gap-2">
                    <Skull className="w-4 h-4 text-red-500" />
                    <h2 className="text-white font-black uppercase text-[10px] md:text-sm tracking-widest font-mono">Combat Protocol</h2>
                </div>
                <div className="flex items-center gap-2">
                    <button 
                        onClick={() => setIsAuto(!isAuto)}
                        className={`flex items-center gap-2 px-4 py-1.5 rounded-lg border font-black text-[9px] md:text-[10px] uppercase tracking-widest transition-all ${isAuto ? 'bg-amber-600 border-amber-400 text-white' : 'bg-stone-800 border-stone-600 text-stone-400'}`}
                    >
                        {isAuto ? <FastForward className="w-3 h-3" /> : <Pause className="w-3 h-3" />}
                        {isAuto ? 'Auto-Tactics' : 'Manual-Link'}
                    </button>
                    {!isAuto && (
                        <button onClick={() => actions.showToast("Manual Mode: Select actions for ready units.")} className="p-1.5 bg-stone-800 rounded-lg text-stone-500"><Target className="w-4 h-4"/></button>
                    )}
                </div>
            </div>

            <div className="flex-1 flex flex-col relative overflow-hidden">
                {/* Background Grid Pattern */}
                <div className="absolute inset-0 opacity-[0.03] pointer-events-none" style={{ backgroundImage: 'radial-gradient(circle, #fff 1px, transparent 1px)', backgroundSize: '30px 30px' }} />

                {/* Vertical Split: Enemies (Top) vs Players (Bottom) */}
                <div className="flex-1 flex flex-col justify-around p-4 gap-8">

                    {/* ENEMY SQUAD (Row) */}
                    <div className="flex justify-center gap-3 md:gap-6 relative">
                        {enemySquadState.map((e) => (
                            <div key={e.instanceId} className={`relative flex flex-col items-center transition-all duration-300 ${e.currentHp <= 0 ? 'grayscale opacity-20 scale-90' : e.lastDamaged ? 'animate-shake-hard' : ''}`}>
                                <div className={`w-16 h-16 md:w-28 md:h-28 bg-stone-900/60 rounded-2xl border-2 flex items-center justify-center relative shadow-2xl transition-colors ${e.lastDamaged ? 'border-red-500 bg-red-950/20' : 'border-stone-800'}`}>
                                    <div className="text-4xl md:text-6xl drop-shadow-xl">{e.icon}</div>

                                    {/* Damage Popups Area */}
                                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                        {damagePopups.filter(p => p.targetId === e.instanceId).map(p => (
                                            <div key={p.id} className={`absolute font-black text-xl md:text-3xl animate-damage drop-shadow-[0_2px_4px_rgba(0,0,0,1)] ${p.isSkill ? 'text-blue-400' : p.isCrit ? 'text-amber-400' : 'text-red-500'}`}>
                                                -{p.value}
                                            </div>
                                        ))}
                                    </div>
                                </div>
                                {e.currentHp > 0 && (
                                    <div className="mt-2 w-16 md:w-28 space-y-1">
                                        <div className="h-1.5 bg-black rounded-full overflow-hidden border border-white/5 p-0.5">
                                            <div className="h-full bg-red-600 rounded-full transition-all duration-500" style={{ width: `${(e.currentHp/e.stats.maxHp)*100}%` }} />
                                        </div>
                                        <div className="h-1 bg-black rounded-full overflow-hidden border border-white/5">
                                            <div className="h-full bg-amber-500 transition-all duration-100" style={{ width: `${(e.gauge/ACTION_THRESHOLD)*100}%` }} />
                                        </div>
                                        <div className="text-[7px] font-black text-stone-500 text-center uppercase truncate tracking-widest">{e.name.split(' ')[0]}</div>
                                    </div>
                                )}
                            </div>
                        ))}
                    </div>

                    {/* Battle Message Hub (Center) */}
                    <div className="flex flex-col items-center justify-center pointer-events-none h-12">
                        <div className="bg-stone-900/80 backdrop-blur-md px-6 py-1.5 rounded-full border border-white/10 shadow-xl flex items-center gap-3 animate-in slide-in-from-bottom-2">
                             <Activity className="w-3 h-3 text-red-500 animate-pulse" />
                             <span className="text-[10px] md:text-xs font-mono font-black text-stone-300 uppercase tracking-widest truncate max-w-[200px] md:max-w-md">
                                {logs[0]?.msg || "Battle in progress..."}
                             </span>
                        </div>
                    </div>

                    {/* PLAYER SQUAD (Row) */}
                    <div className="flex justify-center gap-3 md:gap-6 relative">
                        {partyState.map((p) => {
                            const isActive = activeActorId === p.id;
                            const hpPer = (p.currentHp / p.derived.maxHp) * 100;
                            const isReady = p.gauge >= ACTION_THRESHOLD;

                            return (
                                <div key={p.id} className={`relative flex flex-col items-center transition-all duration-300 ${p.currentHp <= 0 ? 'grayscale opacity-20 scale-90' : isActive ? '-translate-y-4 scale-110' : ''}`}>
                                    <div className={`w-16 h-16 md:w-28 md:h-28 bg-stone-900/60 rounded-2xl border-2 flex items-center justify-center relative shadow-2xl transition-all ${isActive ? 'border-amber-400 bg-amber-900/10 ring-4 ring-amber-500/20' : 'border-stone-800'} ${p.lastDamaged ? 'animate-shake-hard' : ''}`}>
                                        <MercenaryPortrait mercenary={p} className="w-[85%] h-[85%] rounded-xl" />

                                        {/* Unit Markers */}
                                        {isReady && !isAuto && p.currentHp > 0 && (
                                            <div className="absolute -top-1 -right-1 w-5 h-5 bg-amber-500 rounded-full border-2 border-stone-900 flex items-center justify-center animate-bounce z-20">
                                                <Zap className="w-3 h-3 text-stone-900 fill-stone-900" />
                                            </div>
                                        )}

                                        {/* Damage Popups Area */}
                                        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                            {damagePopups.filter(dp => dp.targetId === p.id).map(dp => (
                                                <div key={dp.id} className="absolute font-black text-xl md:text-3xl animate-damage text-red-500 drop-shadow-[0_2px_4px_rgba(0,0,0,1)]">
                                                    -{dp.value}
                                                </div>
                                            ))}
                                        </div>
                                    </div>

                                    {p.currentHp > 0 && (
                                        <div className="mt-2 w-16 md:w-28 space-y-1">
                                            <div className="h-1.5 bg-black rounded-full overflow-hidden border border-white/5 p-0.5">
                                                <div className={`h-full transition-all duration-500 ${hpPer < 30 ? 'bg-red-500 animate-pulse' : 'bg-red-600'}`} style={{ width: `${hpPer}%` }} />
                                            </div>
                                            <div className="h-1 bg-black rounded-full overflow-hidden border border-white/5">
                                                <div className="h-full bg-amber-500 transition-all duration-100" style={{ width: `${(p.gauge/ACTION_THRESHOLD)*100}%` }} />
                                            </div>

                                            <div className="flex justify-between items-center px-0.5">
                                                <span className="text-[7px] font-black text-stone-400 uppercase tracking-tighter truncate">{p.name.split(' ')[0]}</span>
                                                <div className="flex items-center gap-0.5">
                                                    <Zap className="w-1.5 h-1.5 text-blue-400" />
                                                    <span className="text-[6px] font-mono text-blue-400 font-black">{Math.floor(p.currentMp)}</span>
                                                </div>
                                            </div>
                                        </div>
                                    )}

                                    {/* Manual Command Overlay for Active Unit */}
                                    {isActive && (
                                        <div className="absolute top-full left-1/2 -translate-x-1/2 mt-4 z-50 animate-in slide-in-from-top-4 duration-300">
                                            <div className="flex flex-col gap-2 bg-stone-900 border-2 border-amber-500 p-2 rounded-2xl shadow-[0_0_40px_rgba(0,0,0,0.8)] w-32 md:w-48">
                                                <button 
                                                    onClick={() => handleManualCommand('ATTACK')}
                                                    className="w-full py-2 bg-stone-800 hover:bg-stone-700 text-white rounded-xl text-[9px] md:text-xs font-black uppercase flex items-center justify-center gap-2"
                                                >
                                                    <Sword className="w-3 h-3 text-amber-500" /> Attack
                                                </button>

                                                {p.skillIds?.map(id => {
                                                    const skill = SKILLS[id];
                                                    const canUse = p.currentMp >= skill.mpCost;
                                                    return (
                                                        <button 
                                                            key={id}
                                                            disabled={!canUse}
                                                            onClick={() => handleManualCommand('SKILL', id)}
                                                            className={`w-full py-2 rounded-xl text-[8px] md:text-[10px] font-black uppercase flex flex-col items-center justify-center border-b-2 transition-all ${canUse ? 'bg-amber-600 border-amber-800 text-white hover:bg-amber-500' : 'bg-stone-950 border-stone-800 text-stone-700'}`}
                                                        >
                                                            <div className="flex items-center gap-1">
                                                                <Sparkles className="w-2.5 h-2.5" />
                                                                <span>{skill.name}</span>
                                                            </div>
                                                            <span className="text-[6px] opacity-70">{skill.mpCost} MP</span>
                                                        </button>
                                                    );
                                                })}

                                                <button 
                                                    onClick={() => handleManualCommand('FLEE')}
                                                    className="w-full py-1.5 bg-red-950/40 hover:bg-red-900/60 text-red-500 rounded-xl text-[8px] md:text-[10px] font-black uppercase flex items-center justify-center gap-2"
                                                >
                                                    <LogOut className="w-3 h-3" /> Flee
                                                </button>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                </div>
            </div>

            {/* Minimal Log Ticker (Bottom) */}
            <div className={`bg-stone-900 border-t border-stone-800 transition-all duration-500 flex flex-col shrink-0 ${showLogs ? 'h-40' : 'h-10'}`}>
                <button 
                    onClick={() => setShowLogs(!showLogs)}
                    className="w-full h-10 flex items-center justify-between px-4 bg-stone-950/40 hover:bg-stone-950/60 transition-colors"
                >
                    <div className="flex items-center gap-2">
                        <Activity className={`w-3 h-3 text-red-500 ${isPaused ? '' : 'animate-pulse'}`} />
                        <span className="text-[9px] md:text-[10px] font-black text-stone-500 uppercase tracking-widest font-mono">Engagement Data Feed</span>
                    </div>
                    {showLogs ? <ChevronDown className="w-4 h-4 text-stone-600" /> : <ChevronUp className="w-4 h-4 text-stone-600" />}
                </button>

                <div className={`flex-1 overflow-y-auto custom-scrollbar p-2 space-y-1 bg-stone-950/20 ${showLogs ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
                    {logs.map((log, idx) => (
                        <div key={idx} className={`text-[9px] md:text-[10px] font-mono px-3 py-1 border-l-2 ${log.isSkill ? 'border-amber-400 bg-amber-900/10' : log.team === 'PLAYER' ? 'border-blue-500 text-blue-100' : log.team === 'ENEMY' ? 'border-red-500 text-red-100' : 'border-amber-500 text-amber-100'}`}>
                            <span className="opacity-30 mr-2 text-[8px]">{new Date().toLocaleTimeString([], { hour12: false, minute: '2-digit', second: '2-digit' })}</span>
                            {log.msg}
                        </div>
                    ))}
                    {logs.length === 0 && <div className="h-full flex items-center justify-center text-stone-800 italic text-[10px] uppercase tracking-widest opacity-50 font-mono">Syncing tactical arrays...</div>}
                </div>
            </div>
        </div>
    );
};

export default DungeonCombatView;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Shield, Sword, Activity, Skull, Zap, LogOut, FastForward, Pause, ChevronDown, ChevronUp, Sparkles, Target } from 'lucide-react';
import { Mercenary } from '../../../models/Mercenary';
import { Monster } from '../../../models/Monster';
import { ManualDungeonSession } from '../../../types/game-state';
import { calculateCombatResult } from '../../../utils/combatLogic';
import { calculateDerivedStats, applyEquipmentBonuses, mergePrimaryStats } from '../../../models/Stats';
import { useGame } from '../../../context/GameContext';
import { SKILLS } from '../../../data/skills';
import { MercenaryPortrait } from '../../common/ui/MercenaryPortrait';

const ACTION_THRESHOLD = 1000;

interface CombatLogEntry {
    msg: string;
    team: 'PLAYER' | 'ENEMY' | 'SYSTEM';
    isCrit?: boolean;
    isSkill?: boolean;
}

interface DamagePopup {
    id: number;
    value: number;
    targetId: string;
    isCrit: boolean;
    isSkill: boolean;
}

interface DungeonCombatViewProps {
    session: ManualDungeonSession;
    party: Mercenary[];
    enemies: Monster[];
    fleeChance: number;
    onFinish: (win: boolean, finalParty: any[]) => void;
    onFlee: (finalParty: any[]) => void;
}

const DungeonCombatView: React.FC<DungeonCombatViewProps> = ({ party, enemies, fleeChance, onFinish, onFlee }) => {
    const { actions } = useGame();
    const [orientation, setOrientation] = useState<'PORTRAIT' | 'LANDSCAPE'>(
        window.innerWidth > window.innerHeight ? 'LANDSCAPE' : 'PORTRAIT'
    );

    const [partyState, setPartyState] = useState(party.map(m => {
        const primary = mergePrimaryStats(m.stats, m.allocatedStats);
        const derived = applyEquipmentBonuses(calculateDerivedStats(primary, m.level), (Object.values(m.equipment) as any[]).map(e=>e?.stats).filter(Boolean) as any);
        return { ...m, derived, currentHp: m.currentHp, currentMp: m.currentMp, gauge: 0, lastDamaged: false };
    }));

    const [enemySquadState, setEnemySquadState] = useState(enemies.map((e, idx) => ({
        ...e,
        instanceId: `enemy_${idx}`,
        gauge: 0,
        lastDamaged: false,
        hasUsedRevival: false
    })));

    const [logs, setLogs] = useState<CombatLogEntry[]>([]);
    const [damagePopups, setDamagePopups] = useState<DamagePopup[]>([]);
    const [isAuto, setIsAuto] = useState(true);
    const [isPaused, setIsPaused] = useState(false);
    const [activeActorId, setActiveActorId] = useState<string | null>(null); 
    const [attackingUnitId, setAttackingUnitId] = useState<string | null>(null); // For Dash Animation
    const [showLogs, setShowLogs] = useState(false);
    const battleInterval = useRef<ReturnType<typeof setInterval> | null>(null);

    // Orientation Detector
    useEffect(() => {
        const handleResize = () => {
            setOrientation(window.innerWidth > window.innerHeight ? 'LANDSCAPE' : 'PORTRAIT');
        };
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    const addLog = (msg: string, team: 'PLAYER' | 'ENEMY' | 'SYSTEM', isCrit = false, isSkill = false) => {
        setLogs(prev => [{ msg, team, isCrit, isSkill }, ...prev].slice(0, 50));
    };

    const triggerDamagePopup = (targetId: string, value: number, isCrit: boolean, isSkill: boolean) => {
        const id = Date.now() + Math.random();
        setDamagePopups(prev => [...prev, { id, value, targetId, isCrit, isSkill }]);
        setTimeout(() => {
            setDamagePopups(prev => prev.filter(p => p.id !== id));
        }, 800);
    };

    const executeAttack = useCallback((attacker: any, target: any, isPlayerAttacker: boolean, skillId?: string) => {
        // Trigger Visual Dash
        const attackerId = isPlayerAttacker ? attacker.id : target.instanceId; // Logical ID check
        setAttackingUnitId(isPlayerAttacker ? attacker.id : target.instanceId);

        setTimeout(() => {
            const skill = skillId ? SKILLS[skillId] : null;
            const multiplier = skill ? skill.multiplier : 1.0;
            const mpCost = skill ? skill.mpCost : 0;

            const res = calculateCombatResult(
                isPlayerAttacker ? attacker.derived : attacker.stats,
                isPlayerAttacker ? target.stats : target.derived,
                isPlayerAttacker ? attacker.job : 'Fighter' as any,
                isPlayerAttacker ? (attacker.derived.magicalAttack > attacker.derived.physicalAttack ? 'MAGICAL' : 'PHYSICAL') : 'PHYSICAL',
                multiplier
            );

            if (isPlayerAttacker) {
                setEnemySquadState(prev => prev.map(e => {
                    if (e.instanceId === target.instanceId) {
                        const next = { ...e, lastDamaged: res.isHit };
                        if (res.isHit) {
                            let nextHp = Math.max(0, next.currentHp - res.damage);
                            if (nextHp <= 0 && next.id === 'phoenix' && !next.hasUsedRevival) {
                                nextHp = next.stats.maxHp;
                                next.hasUsedRevival = true;
                                addLog("Phoenix rebirth triggered!", 'ENEMY', true, true);
                                triggerDamagePopup(target.instanceId, 0, true, true);
                            } else {
                                next.currentHp = nextHp;
                            }
                            triggerDamagePopup(target.instanceId, res.damage, res.isCrit, !!skill);
                        }
                        setTimeout(() => setEnemySquadState(curr => curr.map(currE => currE.instanceId === target.instanceId ? { ...currE, lastDamaged: false } : currE)), 200);
                        return next;
                    }
                    return e;
                }));

                if (skill) {
                    setPartyState(prev => prev.map(p => p.id === attacker.id ? { ...p, currentMp: Math.max(0, p.currentMp - mpCost) } : p));
                    addLog(`${attacker.name.split(' ')[0]} used ${skill.name}!`, 'PLAYER', res.isCrit, true);
                } else {
                    addLog(`${attacker.name.split(' ')[0]} hits ${target.name} for ${res.damage}`, 'PLAYER', res.isCrit);
                }
            } else {
                setPartyState(prev => prev.map(p => {
                    if (p.id === target.id) {
                        const next = { ...p, lastDamaged: res.isHit };
                        if (res.isHit) {
                            next.currentHp = Math.max(0, next.currentHp - res.damage);
                            triggerDamagePopup(p.id, res.damage, res.isCrit, false);
                        }
                        setTimeout(() => setPartyState(curr => curr.map(c => c.id === p.id ? { ...c, lastDamaged: false } : c)), 200);
                        return next;
                    }
                    return p;
                }));
                addLog(`${attacker.name} strikes ${target.name.split(' ')[0]} for ${res.damage}`, 'ENEMY');
            }

            // End Animation
            setTimeout(() => setAttackingUnitId(null), 150);
        }, 200); // Wait for dash to peak
    }, [addLog]);

    const processLoop = useCallback(() => {
        if (isPaused || activeActorId || attackingUnitId) return;

        setPartyState(prevParty => {
            const nextParty = [...prevParty];
            setEnemySquadState(prevEnemySquad => {
                const nextEnemySquad = [...prevEnemySquad];

                // 1. Tick Gauges
                nextParty.forEach(p => { if (p.currentHp > 0) p.gauge += p.derived.speed * 0.5; });
                nextEnemySquad.forEach(e => { if (e.currentHp > 0) e.gauge += e.stats.speed * 0.5; });

                // 2. Player Turns
                const readyMerc = nextParty.find(p => p.currentHp > 0 && p.gauge >= ACTION_THRESHOLD);
                if (readyMerc) {
                    const livingEnemies = nextEnemySquad.filter(e => e.currentHp > 0);
                    if (livingEnemies.length > 0) {
                        const targetEnemy = livingEnemies[0]; 
                        if (isAuto) {
                            readyMerc.gauge -= ACTION_THRESHOLD;
                            let chosenSkillId: string | undefined = undefined;
                            if (readyMerc.skillIds && readyMerc.skillIds.length > 0) {
                                const availableSkills = readyMerc.skillIds.map(id => SKILLS[id]).filter(s => readyMerc.currentMp >= s.mpCost);
                                if (availableSkills.length > 0) {
                                    chosenSkillId = availableSkills.sort((a, b) => b.multiplier - a.multiplier)[0].id;
                                }
                            }
                            executeAttack(readyMerc, targetEnemy, true, chosenSkillId);
                        } else {
                            setActiveActorId(readyMerc.id);
                        }
                    }
                }

                // 3. Enemy Turns
                const readyEnemy = nextEnemySquad.find(e => e.currentHp > 0 && e.gauge >= ACTION_THRESHOLD);
                if (readyEnemy && !activeActorId && !attackingUnitId) {
                    const livingPlayers = nextParty.filter(p => p.currentHp > 0);
                    if (livingPlayers.length > 0) {
                        readyEnemy.gauge -= ACTION_THRESHOLD;
                        const targetPlayer = livingPlayers[Math.floor(Math.random() * livingPlayers.length)];
                        executeAttack(readyEnemy, targetPlayer, false);
                    }
                }

                return nextEnemySquad;
            });
            return nextParty;
        });
    }, [isPaused, isAuto, activeActorId, attackingUnitId, executeAttack]);

    useEffect(() => {
        battleInterval.current = setInterval(processLoop, 100);
        return () => { if (battleInterval.current) clearInterval(battleInterval.current); };
    }, [processLoop]);

    const handleManualCommand = (type: 'ATTACK' | 'FLEE' | 'SKILL', skillId?: string) => {
        if (!activeActorId) return;
        const actor = partyState.find(p => p.id === activeActorId);
        const livingEnemies = enemySquadState.filter(e => e.currentHp > 0);
        if (!actor || livingEnemies.length === 0) return;

        if (type === 'ATTACK' || (type === 'SKILL' && skillId)) {
            setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: p.gauge - ACTION_THRESHOLD } : p));
            executeAttack(actor, livingEnemies[0], true, skillId);
            setActiveActorId(null);
        } else if (type === 'FLEE') {
            const roll = Math.random() * 100;
            if (roll < fleeChance) {
                onFlee(partyState);
            } else {
                addLog(`${actor.name.split(' ')[0]} failed to find escape route!`, 'SYSTEM');
                setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: p.gauge - ACTION_THRESHOLD } : p));
                setActiveActorId(null);
            }
        }
    };

    useEffect(() => {
        if (enemySquadState.every(e => e.currentHp <= 0)) {
            setIsPaused(true);
            setTimeout(() => onFinish(true, partyState), 1200);
        } else if (partyState.every(p => p.currentHp <= 0)) {
            setIsPaused(true);
            setTimeout(() => onFinish(false, partyState), 1200);
        }
    }, [enemySquadState, partyState, onFinish]);

    // UI Helper for Attack Dash
    const getUnitStyle = (id: string, side: 'PLAYER' | 'ENEMY'): React.CSSProperties => {
        if (attackingUnitId !== id) return {};

        let transform = '';
        if (orientation === 'PORTRAIT') {
            transform = side === 'PLAYER' ? 'translateY(-120px) scale(1.1)' : 'translateY(120px) scale(1.1)';
        } else {
            transform = side === 'PLAYER' ? 'translateX(120px) scale(1.1)' : 'translateX(-120px) scale(1.1)';
        }

        return { transform, zIndex: 100 };
    };

    return (
        <div className="fixed inset-0 z-[150] flex flex-col bg-stone-950 animate-in fade-in duration-500 overflow-hidden select-none font-sans">
            <style>{`
                @keyframes damage-float {
                    0% { transform: translateY(0) scale(0.8); opacity: 0; }
                    20% { opacity: 1; scale: 1.2; }
                    100% { transform: translateY(-60px) scale(1.0); opacity: 0; }
                }
                .animate-damage { animation: damage-float 1s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }

                @keyframes unit-shake {
                    0%, 100% { transform: translate(0,0); }
                    25% { transform: translate(-4px, 2px); }
                    50% { transform: translate(4px, -2px); }
                    75% { transform: translate(-2px, -4px); }
                }
                .animate-hit { animation: unit-shake 0.2s ease-in-out 3; }
            `}</style>

            {/* Top Toolbar */}
            <div className="p-3 bg-red-950/20 border-b border-red-900/30 flex justify-between items-center shrink-0 z-[200]">
                <div className="flex items-center gap-2">
                    <Skull className="w-4 h-4 text-red-500" />
                    <h2 className="text-white font-black uppercase text-[10px] md:text-sm tracking-widest font-mono">Combat Zone</h2>
                </div>
                <div className="flex items-center gap-2">
                    <button 
                        onClick={() => setIsAuto(!isAuto)}
                        className={`flex items-center gap-2 px-4 py-1.5 rounded-lg border font-black text-[9px] md:text-[10px] uppercase tracking-widest transition-all ${isAuto ? 'bg-amber-600 border-amber-400 text-white shadow-glow-sm' : 'bg-stone-800 border-stone-600 text-stone-400'}`}
                    >
                        {isAuto ? <FastForward className="w-3 h-3" /> : <Pause className="w-3 h-3" />}
                        {isAuto ? 'AUTO' : 'MANUAL'}
                    </button>
                </div>
            </div>

            <div className={`flex-1 flex relative overflow-hidden transition-all duration-700 ${orientation === 'PORTRAIT' ? 'flex-col' : 'flex-row'}`}>
                {/* Visual Background Decor */}
                <div className="absolute inset-0 opacity-[0.02] pointer-events-none" style={{ backgroundImage: 'radial-gradient(circle, #fff 1px, transparent 1px)', backgroundSize: '40px 40px' }} />

                {/* SQUAD AREA 1 (Top in Portrait / Right in Landscape) */}
                <div className={`flex flex-1 items-center justify-center p-4 gap-3 md:gap-6 ${orientation === 'PORTRAIT' ? 'order-1' : 'order-2'}`}>
                    {enemySquadState.map((e) => (
                        <div 
                            key={e.instanceId} 
                            style={getUnitStyle(e.instanceId, 'ENEMY')}
                            className={`relative flex flex-col items-center transition-all duration-300 ease-out ${e.currentHp <= 0 ? 'grayscale opacity-20 scale-90' : e.lastDamaged ? 'animate-hit' : ''}`}
                        >
                            <div className={`w-16 h-16 md:w-32 md:h-32 bg-stone-900/60 rounded-2xl border-2 flex items-center justify-center relative shadow-2xl transition-colors ${e.lastDamaged ? 'border-red-500 bg-red-950/20' : 'border-stone-800'} ${attackingUnitId === e.instanceId ? 'ring-4 ring-red-500/40' : ''}`}>
                                <div className="text-4xl md:text-7xl drop-shadow-[0_4px_10px_rgba(0,0,0,0.5)]">{e.icon}</div>

                                {/* Damage Popups */}
                                <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                    {damagePopups.filter(p => p.targetId === e.instanceId).map(p => (
                                        <div key={p.id} className={`absolute font-black text-2xl md:text-4xl animate-damage drop-shadow-[0_4px_6px_rgba(0,0,0,1)] ${p.isSkill ? 'text-blue-400' : p.isCrit ? 'text-amber-400' : 'text-red-500'}`}>
                                            -{p.value}
                                        </div>
                                    ))}
                                </div>
                            </div>
                            {e.currentHp > 0 && (
                                <div className="mt-2 w-16 md:w-32 space-y-1">
                                    <div className="h-1.5 bg-black rounded-full overflow-hidden border border-white/5">
                                        <div className="h-full bg-red-600 rounded-full transition-all duration-500" style={{ width: `${(e.currentHp/e.stats.maxHp)*100}%` }} />
                                    </div>
                                    <div className="h-1 bg-black rounded-full overflow-hidden border border-white/5">
                                        <div className="h-full bg-amber-500 transition-all duration-100" style={{ width: `${(e.gauge/ACTION_THRESHOLD)*100}%` }} />
                                    </div>
                                    <div className="text-[7px] font-black text-stone-500 text-center uppercase truncate tracking-[0.2em]">{e.name.split(' ')[0]}</div>
                                </div>
                            )}
                        </div>
                    ))}
                </div>

                {/* SQUAD AREA 2 (Bottom in Portrait / Left in Landscape) */}
                <div className={`flex flex-1 items-center justify-center p-4 gap-3 md:gap-6 ${orientation === 'PORTRAIT' ? 'order-3' : 'order-1'}`}>
                    {partyState.map((p) => {
                        const isActive = activeActorId === p.id;
                        const hpPer = (p.currentHp / p.derived.maxHp) * 100;
                        const isReady = p.gauge >= ACTION_THRESHOLD;

                        return (
                            <div 
                                key={p.id} 
                                style={getUnitStyle(p.id, 'PLAYER')}
                                className={`relative flex flex-col items-center transition-all duration-300 ease-out ${p.currentHp <= 0 ? 'grayscale opacity-20 scale-90' : isActive ? '-translate-y-2' : ''} ${p.lastDamaged ? 'animate-hit' : ''}`}
                            >
                                <div className={`w-16 h-16 md:w-32 md:h-32 bg-stone-900/60 rounded-2xl border-2 flex items-center justify-center relative shadow-2xl transition-all ${isActive ? 'border-amber-400 bg-amber-900/10 ring-4 ring-amber-500/20' : 'border-stone-800'} ${attackingUnitId === p.id ? 'ring-4 ring-amber-400/50' : ''}`}>
                                    <MercenaryPortrait mercenary={p} className="w-[85%] h-[85%] rounded-xl" />

                                    {isReady && !isAuto && p.currentHp > 0 && (
                                        <div className="absolute -top-1.5 -right-1.5 w-6 h-6 bg-amber-500 rounded-full border-2 border-stone-900 flex items-center justify-center animate-bounce z-20 shadow-lg">
                                            <Zap className="w-3.5 h-3.5 text-stone-900 fill-stone-900" />
                                        </div>
                                    )}

                                    {/* Damage Popups */}
                                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                        {damagePopups.filter(dp => dp.targetId === p.id).map(dp => (
                                            <div key={dp.id} className="absolute font-black text-2xl md:text-4xl animate-damage text-red-500 drop-shadow-[0_4px_6px_rgba(0,0,0,1)]">
                                                -{dp.value}
                                            </div>
                                        ))}
                                    </div>
                                </div>

                                {p.currentHp > 0 && (
                                    <div className="mt-2 w-16 md:w-32 space-y-1">
                                        <div className="h-1.5 bg-black rounded-full overflow-hidden border border-white/5">
                                            <div className={`h-full transition-all duration-500 ${hpPer < 30 ? 'bg-red-500 animate-pulse' : 'bg-red-600'}`} style={{ width: `${hpPer}%` }} />
                                        </div>
                                        <div className="h-1 bg-black rounded-full overflow-hidden border border-white/5">
                                            <div className="h-full bg-amber-500 transition-all duration-100" style={{ width: `${(p.gauge/ACTION_THRESHOLD)*100}%` }} />
                                        </div>

                                        <div className="flex justify-between items-center px-0.5">
                                            <span className="text-[7px] font-black text-stone-400 uppercase tracking-tighter truncate">{p.name.split(' ')[0]}</span>
                                            <div className="flex items-center gap-0.5">
                                                <Zap className="w-1.5 h-1.5 text-blue-400" />
                                                <span className="text-[6px] font-mono text-blue-400 font-black">{Math.floor(p.currentMp)}</span>
                                            </div>
                                        </div>
                                    </div>
                                )}

                                {/* Manual Action Menu */}
                                {isActive && (
                                    <div className="absolute top-full left-1/2 -translate-x-1/2 mt-4 z-[300] animate-in slide-in-from-top-4 duration-300">
                                        <div className="flex flex-col gap-2 bg-stone-900/95 backdrop-blur-xl border-2 border-amber-500 p-2 rounded-2xl shadow-[0_0_50px_rgba(0,0,0,0.9)] w-36 md:w-52">
                                            <button 
                                                onClick={() => handleManualCommand('ATTACK')}
                                                className="w-full py-2.5 bg-stone-800 hover:bg-stone-700 text-white rounded-xl text-[10px] md:text-xs font-black uppercase flex items-center justify-center gap-2 transition-all active:scale-95"
                                            >
                                                <Sword className="w-3.5 h-3.5 text-amber-500" /> Attack
                                            </button>

                                            {p.skillIds?.map(id => {
                                                const skill = SKILLS[id];
                                                const canUse = p.currentMp >= (skill?.mpCost || 0);
                                                if (!skill) return null;
                                                return (
                                                    <button 
                                                        key={id}
                                                        disabled={!canUse}
                                                        onClick={() => handleManualCommand('SKILL', id)}
                                                        className={`w-full py-2 rounded-xl text-[9px] md:text-[10px] font-black uppercase flex flex-col items-center justify-center border-b-2 transition-all ${canUse ? 'bg-amber-600 border-amber-800 text-white hover:bg-amber-500 active:scale-95' : 'bg-stone-950 border-stone-800 text-stone-700'}`}
