                                                        <div className="flex items-center gap-1">
                                                            <Sparkles className="w-3 h-3" />
                                                            <span>{skill.name}</span>
                                                        </div>
                                                        <span className="text-[7px] opacity-70">{skill.mpCost} MP</span>
