import { Monster } from '../../models/Monster';

/**
 * 랜덤한 입구와 그에 따른 가장 먼 출구를 포함한 그리드를 생성합니다.
 */
const generateManualGrid = (width: number, height: number, dungeonId: string, floor: number, maxFloors: number, forceNPC: boolean = false): { grid: RoomType[][], startPos: { x: number, y: number } } => {
    const grid: RoomType[][] = Array.from({ length: height }, () => Array(width).fill('EMPTY'));

    // 1. 입구 위치 랜덤 결정 (외곽 벽면 중 하나)
    let startX, startY;
    if (Math.random() < 0.5) {
        // 좌측 또는 우측 벽면
        startX = Math.random() < 0.5 ? 0 : width - 1;
        startY = Math.floor(Math.random() * height);
    } else {
        // 상단 또는 하단 벽면
        startX = Math.floor(Math.random() * width);
        startY = Math.random() < 0.5 ? 0 : height - 1;
    }

    grid[startY][startX] = 'ENTRANCE';

    // 2. 입구에서 가장 먼 반대편 코너를 출구로 설정
    const endX = startX < width / 2 ? width - 1 : 0;
    const endY = startY < height / 2 ? height - 1 : 0;

    if (floor === maxFloors) {
        grid[endY][endX] = 'BOSS';
    } else {
        grid[endY][endX] = 'STAIRS';
    }

    // 3. 열쇠 배치 (보스 층인 경우)
    if (floor === maxFloors) {
        let keyPlaced = false;
        let attempts = 0;
        while (!keyPlaced && attempts < 100) {
            let kx = Math.floor(Math.random() * width);
            let ky = Math.floor(Math.random() * height);
            if (grid[ky][kx] === 'EMPTY') {
                grid[ky][kx] = 'KEY';
                keyPlaced = true;
            }
            attempts++;
        }
    }

    // 4. 기타 요소들 배치 (적, 자원, 함정 등)
    let npcPlaced = false;
    for (let y = 0; y < height; y++) {
        for (let x = 0; x < width; x++) {
            if (grid[y][x] === 'EMPTY') {
                const r = Math.random();
                if (r < 0.18) grid[y][x] = 'ENEMY'; 
                else if (r < 0.33) grid[y][x] = 'RESOURCE'; 
                else if (r < 0.38) grid[y][x] = 'GOLD';
                else if (r < 0.45) grid[y][x] = 'TRAP';
                else if (r < 0.47 && !npcPlaced) {
                    grid[y][x] = 'NPC';
                    npcPlaced = true;
                }
            }
        }
    }

    // NPC 강제 배치 (필요한 경우)
    if (forceNPC && !npcPlaced && floor === 1) {
        let attempts = 0;
        while (!npcPlaced && attempts < 20) {
            const rx = Math.floor(Math.random() * width);
            const ry = Math.floor(Math.random() * height);
            if (grid[ry][rx] === 'EMPTY') {
                grid[ry][rx] = 'NPC';
                npcPlaced = true;
            }
            attempts++;
        }
    }

    return { grid, startPos: { x: startX, y: startY } };
};

export const handleStartManualDungeon = (state: GameState, payload: { dungeonId: string; partyIds: string[]; startFloor?: number }): GameState => {
    const dungeon = DUNGEONS.find(d => d.id === payload.dungeonId);
    if (!dungeon) return state;

    const startFloor = payload.startFloor || 1;
    const party = state.knownMercenaries.filter(m => payload.partyIds.includes(m.id));

    if (party.some(m => (m.expeditionEnergy || 0) < dungeon.energyCost)) {
        return { ...state, logs: [`Your squad is too exhausted to enter ${dungeon.name}.`, ...state.logs] };
    }

    const isTillyRescued = state.knownMercenaries.some(m => m.id === 'tilly_footloose');
    const shouldForceNPC = payload.dungeonId === 'dungeon_t1_sewers' && !isTillyRescued;

    const updatedMercs = state.knownMercenaries.map(m => {
        if (payload.partyIds.includes(m.id)) {
            return { 
                ...m, 
                expeditionEnergy: Math.max(0, (m.expeditionEnergy || 0) - dungeon.energyCost), 
                status: 'ON_EXPEDITION' as const 
            };
        }
        return m;
    });

    const { grid, startPos } = generateManualGrid(dungeon.gridWidth, dungeon.gridHeight, dungeon.id, startFloor, dungeon.maxFloors, shouldForceNPC);

    const visited = Array.from({ length: dungeon.gridHeight }, () => Array(dungeon.gridWidth).fill(false));
    visited[startPos.y][startPos.x] = true;

    const session: ManualDungeonSession = {
        dungeonId: dungeon.id,
        partyIds: payload.partyIds,
        grid,
        visited,
        playerPos: startPos,
        pathHistory: [startPos],
        hasKey: false,
        isBossLocked: dungeon.isBossLocked ?? true,
        goldCollected: 0,
        encounterStatus: 'NONE',
        lastActionMessage: `Scanning sector... Floor ${startFloor} initialized.`,
        currentFloor: startFloor,
        maxFloors: dungeon.maxFloors
    };

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: session,
        showManualDungeonOverlay: true,
        logs: [`Direct assault initiated: ${dungeon.name} (Floor ${startFloor}).`, ...state.logs]
    };
};

export const handleMoveManualDungeon = (state: GameState, payload: { x: number, y: number }): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus === 'ENCOUNTERED' || session.encounterStatus === 'BATTLE') return state;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return state;

    const newX = session.playerPos.x + payload.x;
    const newY = session.playerPos.y + payload.y;

    if (newX < 0 || newX >= dungeon.gridWidth || newY < 0 || newY >= dungeon.gridHeight) {
        return { 
            ...state, 
            activeManualDungeon: { ...session, lastActionMessage: "Structural barrier detected." }
        };
    }

    const targetRoom = session.grid[newY][newX];
    if (targetRoom === 'WALL') return state;

    const isAlreadyVisited = session.visited[newY][newX];
    const cost = isAlreadyVisited ? -1 : (targetRoom === 'BOSS' || targetRoom === 'STAIRS' ? dungeon.bossEnergy : dungeon.moveEnergy);

    const party = state.knownMercenaries.filter(m => session.partyIds.includes(m.id));
    if (cost > 0 && party.some(m => (m.expeditionEnergy || 0) < cost)) {
        return { 
            ...state, 
            activeManualDungeon: { ...session, lastActionMessage: "SQUAD ALERT: Energy critically low." }
        };
    }

    let updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextEnergy = Math.max(0, (m.expeditionEnergy || 0) - cost);
            let nextHp = m.currentHp;
            if (targetRoom === 'TRAP' && !isAlreadyVisited) nextHp = Math.max(0, m.currentHp - 15);
            return { ...m, expeditionEnergy: nextEnergy, currentHp: nextHp };
        }
        return m;
    });

    const isWipedOut = updatedMercs.filter(m => session.partyIds.includes(m.id)).every(m => m.currentHp <= 0);
    if (isWipedOut) return handleRetreatManualDungeon({ ...state, knownMercenaries: updatedMercs });

    const newVisited = [...session.visited.map(row => [...row])];
    newVisited[newY][newX] = true;

    let extraGold = 0;
    let newGrid = [...session.grid.map(row => [...row])];
    let newInventory = [...state.inventory];
    let logMsg = '';
    let actionMsg = session.lastActionMessage;
    let encounterStatus: ManualDungeonSession['encounterStatus'] = 'NONE';

    if (targetRoom === 'GOLD' && !isAlreadyVisited) {
        extraGold = (dungeon.tier || 1) * 30;
        newGrid[newY][newX] = 'EMPTY';
        actionMsg = `Credits recovered. (+${extraGold} G)`;
    } else if (targetRoom === 'RESOURCE' && !isAlreadyVisited) {
        const possibleResources = ['copper_ore', 'tin_ore', 'leather_strips', 'charcoal', 'rat_hide_patch'];
        const resId = possibleResources[Math.floor(Math.random() * possibleResources.length)];
        const count = 1 + Math.floor(Math.random() * 2);
        const matDef = materials[resId];

        const existing = newInventory.find(i => i.id === resId);
        if (existing) {
            newInventory = newInventory.map(i => i.id === resId ? { ...i, quantity: i.quantity + count } : i);
        } else {
            newInventory.push({ ...matDef, quantity: count } as InventoryItem);
        }

        newGrid[newY][newX] = 'EMPTY';
        actionMsg = `Harvested ${matDef.name} x${count}.`;
        logMsg = `Recovered materials from ruins.`;
    } else if (targetRoom === 'TRAP' && !isAlreadyVisited) {
        actionMsg = `Structural hazard triggered. Integrity drop.`;
    } else if (targetRoom === 'KEY' && !isAlreadyVisited) {
        logMsg = `Area key recovered.`;
        actionMsg = `Sector key identified. Decrypting...`;
        newGrid[newY][newX] = 'EMPTY';
    } else if (targetRoom === 'ENEMY' && !isAlreadyVisited) {
        encounterStatus = 'ENCOUNTERED';
        actionMsg = `Hostile lifeforms detected. Combat protocol engaged.`;
    } else if (targetRoom === 'BOSS' && !session.isBossDefeated) {
        encounterStatus = 'ENCOUNTERED';
        actionMsg = `COMMANDER ALERT: Primary target identified.`;
    } else if (targetRoom === 'STAIRS') {
        encounterStatus = 'STAIRS';
        actionMsg = `Downward passage identified. Scan for deeper sectors?`;
    }

    return {
        ...state,
        knownMercenaries: updatedMercs,
        inventory: newInventory,
        activeManualDungeon: {
            ...session,
            grid: newGrid,
            playerPos: { x: newX, y: newY },
            pathHistory: [{ x: newX, y: newY }, ...session.pathHistory].slice(0, 50),
            visited: newVisited,
            hasKey: targetRoom === 'KEY' ? true : session.hasKey,
            encounterStatus,
            goldCollected: session.goldCollected + extraGold,
            lastActionMessage: actionMsg
        },
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleProceedToNextFloorManual = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus !== 'STAIRS') return state;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return state;

    const nextFloor = session.currentFloor + 1;
    const { grid: nextGrid, startPos: nextStartPos } = generateManualGrid(dungeon.gridWidth, dungeon.gridHeight, dungeon.id, nextFloor, session.maxFloors);

    const nextVisited = Array.from({ length: dungeon.gridHeight }, () => Array(dungeon.gridWidth).fill(false));
    nextVisited[nextStartPos.y][nextStartPos.x] = true;

    const nextMaxFloor = Math.max(state.maxFloorReached[session.dungeonId] || 1, nextFloor);

    return {
        ...state,
        maxFloorReached: { ...state.maxFloorReached, [session.dungeonId]: nextMaxFloor },
        activeManualDungeon: {
            ...session,
            grid: nextGrid,
            visited: nextVisited,
            playerPos: nextStartPos,
            pathHistory: [nextStartPos],
            currentFloor: nextFloor,
            encounterStatus: 'NONE',
            lastActionMessage: `Floor transition complete. Sector ${nextFloor} analysis in progress.`
        },
        logs: [`Proceeded to Floor ${nextFloor}.`, ...state.logs]
    };
};

export const handleStartCombatManual = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus !== 'ENCOUNTERED') return state;

    const currentRoom = session.grid[session.playerPos.y][session.playerPos.x];
    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    const tier = dungeon?.tier || 1;

    let monsters: Monster[] = [];

    if (currentRoom === 'BOSS') {
        const monsterId = dungeon?.bossVariantId || 'plague_rat_king';
        const monsterBase = MONSTERS[monsterId] || MONSTERS['giant_rat'];
        monsters = [{ ...monsterBase, currentHp: monsterBase.stats.maxHp }];
    } else {
        const mobs = ['giant_rat', 'sewer_slime', 'mold_sporeling', 'carrion_beetle', 'sewer_thief', 'cave_bat', 'rat_man'];
        let monsterCount = Math.floor(Math.random() * tier) + 1;
        if (session.currentFloor > 3) monsterCount += 1;
        monsterCount = Math.min(4, Math.max(1, monsterCount));

        for (let i = 0; i < monsterCount; i++) {
            const monsterId = mobs[Math.floor(Math.random() * mobs.length)];
            const monsterBase = MONSTERS[monsterId] || MONSTERS['giant_rat'];
            monsters.push({ ...monsterBase, currentHp: monsterBase.stats.maxHp });
        }
    }

    return {
        ...state,
        activeManualDungeon: {
            ...session,
            encounterStatus: 'BATTLE',
            enemies: monsters
        }
    };
};

export const handleResolveCombatManual = (state: GameState, payload: { win: boolean, flee: boolean, finalParty: any[] }): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const currentRoom = session.grid[session.playerPos.y][session.playerPos.x];
    let logMsg = '';

    const livingMembers = payload.finalParty.filter(p => p.currentHp > 0);

    let totalXpGained = 0;
    if (payload.win && session.enemies) {
        totalXpGained = session.enemies.reduce((sum, e) => sum + e.rewardXp, 0);
    }

    const xpPerMember = (payload.win && totalXpGained > 0 && livingMembers.length > 0) 
        ? Math.floor(totalXpGained / livingMembers.length) 
        : 0;

    if (payload.win) {
        logMsg = `Engagement complete. Sector secured. XP awarded.`;
    }

    const newKnownMercenaries = state.knownMercenaries.map(m => {
        const combatant = payload.finalParty.find(p => p.id === m.id);
        if (combatant) {
            let nextXp = m.currentXp;
            let nextLevel = m.level;
            let nextMaxHp = m.maxHp;
            let nextMaxMp = m.maxMp;
            let nextCurrentHp = combatant.currentHp;
            let bonusStatPoints = m.bonusStatPoints || 0;

            if (payload.win && combatant.currentHp > 0) {
                nextXp += xpPerMember;
                while (nextXp >= m.xpToNextLevel) {
                    nextXp -= m.xpToNextLevel;
                    nextLevel++;
                    const merged = mergePrimaryStats(m.stats, m.allocatedStats);
                    nextMaxHp = calculateMaxHp(merged, nextLevel);
                    nextMaxMp = calculateMaxMp(merged, nextLevel);
                    nextCurrentHp = nextMaxHp;
                    bonusStatPoints += 3;
                }
            }

            return { 
                ...m, 
                currentHp: nextCurrentHp, 
                currentMp: combatant.currentMp,
                currentXp: nextXp,
                level: nextLevel,
                bonusStatPoints,
                maxHp: nextMaxHp,
                maxMp: nextMaxMp,
                xpToNextLevel: nextLevel * 100
            };
        }
        return m;
    });

    const isBossDefeated = (currentRoom === 'BOSS' && payload.win) || session.isBossDefeated;
    let nextGrid = [...session.grid.map(row => [...row])];
    if (payload.win && currentRoom === 'ENEMY') {
        nextGrid[session.playerPos.y][session.playerPos.x] = 'EMPTY';
    }

    return {
        ...state,
        knownMercenaries: newKnownMercenaries,
        activeManualDungeon: {
            ...session,
            grid: nextGrid,
            encounterStatus: payload.win ? 'VICTORY' : (payload.flee ? 'NONE' : 'DEFEAT'),
            isBossDefeated,
            lastActionMessage: payload.win 
                ? `Area neutralized. Combat systems on standby.`
                : (payload.flee ? `Withdrawal confirmed.` : `CRITICAL STATUS: Rescue required.`)
        },
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleRetreatManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const isDefeat = session.encounterStatus === 'DEFEAT' || 
                    state.knownMercenaries.filter(m => session.partyIds.includes(m.id)).every(m => m.currentHp <= 0);

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    const mercResults: DungeonResult['mercenaryResults'] = [];

    const updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextStatus: any = 'HIRED';
            let statusChange: 'NONE' | 'INJURED' | 'DEAD' = 'NONE';

            if (isDefeat) {
                const roll = Math.random();
                if (roll < 0.1) { nextStatus = 'DEAD'; statusChange = 'DEAD'; }
                else { 
                    nextStatus = 'INJURED'; statusChange = 'INJURED'; 
                    m.recoveryUntilDay = state.stats.day + 2; 
                }
            } else if (m.currentHp <= 0) {
                nextStatus = 'INJURED'; statusChange = 'INJURED';
                m.recoveryUntilDay = state.stats.day + 1;
            }

            mercResults.push({
                id: m.id, name: m.name, job: m.job, levelBefore: m.level, levelAfter: m.level,
                xpGained: 0, currentXp: m.currentXp, xpToNext: m.xpToNextLevel, statusChange
            });

            return { ...m, status: nextStatus, assignedExpeditionId: undefined };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercs,
        dungeonResult: isDefeat ? {
            dungeonName: dungeon?.name || 'Unknown',
            rewards: [],
            mercenaryResults: mercResults,
            isDefeat: true
        } : state.dungeonResult,
        activeManualDungeon: null,
        showManualDungeonOverlay: false,
        logs: [isDefeat ? 'CRITICAL FAILURE: Squad neutralized.' : 'Squad retreated.', ...state.logs]
    };
};

export const handleRescueNPC = (state: GameState, payload: { npcId: string }): GameState => {
    const currentSession = state.activeManualDungeon;
    if (!currentSession) return state;

    let newGrid = [...currentSession.grid.map(row => [...row])];
    newGrid[currentSession.playerPos.y][currentSession.playerPos.x] = 'EMPTY';

    return {
        ...state,
        activeManualDungeon: { 
            ...currentSession, 
            grid: newGrid, 
            npcFound: true, 
            rescuedNpcId: payload.npcId,
            lastActionMessage: `Survivor secured! Initiating extraction protocol.`
        },
        logs: [`Survivor secured! Initiating extraction.`, ...state.logs]
    };
};

export const handleFinishManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const tempExpId = `temp_manual_${Date.now()}`;
    const tempExp = {
        id: tempExpId,
        dungeonId: session.dungeonId,
        partyIds: session.partyIds,
        startTime: 0,
        endTime: 0,
        status: 'COMPLETED' as const
    };

    const stateWithTempExp = {
        ...state,
        activeExpeditions: [...state.activeExpeditions, tempExp]
    };

    const claimedState = handleClaimExpedition(stateWithTempExp, { 
        expeditionId: tempExpId, 
        rescuedNpcId: session.rescuedNpcId 
    });

    if (session.goldCollected > 0) {
        claimedState.stats.gold += session.goldCollected;
        if (claimedState.dungeonResult) {
            claimedState.dungeonResult.goldGained = (claimedState.dungeonResult.goldGained || 0) + session.goldCollected;
        }
    }

    return {
        ...claimedState,
        activeManualDungeon: null,
        showManualDungeonOverlay: false
    };
};

import { useState, useMemo, useEffect } from 'react';
import { useGame } from '../../../context/GameContext';
import { DUNGEONS } from '../../../data/dungeons';
import { materials } from '../../../data/materials';
import { EQUIPMENT_ITEMS } from '../../../data/equipment';
import { calculatePartyPower, calculateMercenaryPower } from '../../../utils/combatLogic';
import { Sword, Skull, Timer, Zap, Map as MapIcon, ChevronRight, ChevronLeft, Lock, CheckCircle, Trophy, User, XCircle, Box, AlertCircle, Gamepad2, Navigation2, Play, Ban, LogOut, HeartOff, LayoutList, Layers } from 'lucide-react';
import { getAssetUrl, formatDuration } from '../../../utils';
import AssaultNavigator from './AssaultNavigator';
import ConfirmationModal from '../../modals/ConfirmationModal';

const DungeonTab = () => {
    const { state, actions } = useGame();
    const { activeExpeditions, knownMercenaries, dungeonClearCounts, maxFloorReached, activeManualDungeon, showManualDungeonOverlay } = state;

    // View State: 'LIST' or 'DETAIL'
    const [view, setView] = useState<'LIST' | 'DETAIL'>('LIST');
    const [selectedDungeonId, setSelectedDungeonId] = useState<string | null>(null);
    const [selectedFloor, setSelectedFloor] = useState(1);
    const [party, setParty] = useState<string[]>([]);
    const [failedMercs, setFailedMercs] = useState<string[]>([]);
    const [lowHpMercs, setLowHpMercs] = useState<string[]>([]);
    const [failedPowerHighlight, setFailedPowerHighlight] = useState(false);
    const [showRecallConfirm, setShowRecallConfirm] = useState<'AUTO' | 'MANUAL' | null>(null);

    const selectedDungeon = useMemo(() => 
        DUNGEONS.find(d => d.id === selectedDungeonId) || DUNGEONS[0], 
    [selectedDungeonId]);

    const maxPartySize = selectedDungeon.maxPartySize || 4;
    const isOngoingManual = !!activeManualDungeon && activeManualDungeon.dungeonId === selectedDungeon.id;
    const currentExpedition = activeExpeditions.find(e => e.dungeonId === selectedDungeon.id);
    const hasActiveMission = !!currentExpedition || isOngoingManual;

    // --- Auto Expedition Availability Logic ---
    const isFloorCleared = useMemo(() => {
        const maxReached = maxFloorReached[selectedDungeon.id] || 1;
        // Case 1: If selected floor is below the max reached floor, it means the player found the stairs and moved past it.
        if (selectedFloor < maxReached) return true;
        // Case 2: If it's the last floor (Boss), check if the entire dungeon has been cleared at least once.
        if (selectedFloor === selectedDungeon.maxFloors && (dungeonClearCounts[selectedDungeon.id] || 0) > 0) return true;
        return false;
    }, [selectedDungeon, selectedFloor, maxFloorReached, dungeonClearCounts]);

    const hiredMercs = useMemo(() => 
        knownMercenaries.filter(m => m.status === 'HIRED' || m.status === 'ON_EXPEDITION'), 
    [knownMercenaries]);

    // UI Calculations based on selected floor
    const requiredPowerForFloor = useMemo(() => {
        const base = selectedDungeon.requiredPower;
        return Math.round(base * (1 + (selectedFloor - 1) * 0.25));
    }, [selectedDungeon, selectedFloor]);

    const energyCostForFloor = useMemo(() => {
        const base = selectedDungeon.energyCost;
        return base + (selectedFloor - 1) * 5;
    }, [selectedDungeon, selectedFloor]);

    const handleDungeonSelect = (id: string) => {
        const dungeon = DUNGEONS.find(d => d.id === id);
        if (!dungeon || dungeon.tier > state.stats.tierLevel + 1) {
            actions.showToast("This area is currently inaccessible.");
            return;
        }
        setSelectedDungeonId(id);
        setSelectedFloor(1);
        setParty([]);
        setView('DETAIL');
    };

    const handlePrevFloor = () => {
        setSelectedFloor(prev => Math.max(1, prev - 1));
    };

    const handleNextFloor = () => {
        const maxReached = maxFloorReached[selectedDungeon.id] || 1;
        if (selectedFloor >= selectedDungeon.maxFloors) return;
        if (selectedFloor >= maxReached) {
            actions.showToast("You must clear the current floor to descend deeper.");
            return;
        }
        setSelectedFloor(prev => Math.min(selectedDungeon.maxFloors, prev + 1));
    };

    const toggleMercenary = (mercId: string) => {
        if (party.includes(mercId)) {
            setParty(prev => prev.filter(id => id !== mercId));
        } else if (party.length < maxPartySize) {
            setParty(prev => [...prev, mercId]);
        }
    };

    const validateEntry = () => {
        if (party.length === 0) return false;
        const selectedMercs = knownMercenaries.filter(m => party.includes(m.id));

        const lowHpIds = selectedMercs.filter(m => (m.currentHp || 0) < 1).map(m => m.id);
        if (lowHpIds.length > 0) {
            setLowHpMercs(lowHpIds);
            setTimeout(() => setLowHpMercs([]), 2000);
            actions.showToast("Wounded members cannot be deployed.");
            return false;
        }

        const lowEnergyIds = selectedMercs.filter(m => (m.expeditionEnergy || 0) < energyCostForFloor).map(m => m.id);
        if (lowEnergyIds.length > 0) {
            setFailedMercs(lowEnergyIds);
            setTimeout(() => setFailedMercs([]), 2000);
            actions.showToast("Some squad members are too exhausted.");
            return false;
        }

        if (currentPartyPower < requiredPowerForFloor) {
            setFailedPowerHighlight(true);
            setTimeout(() => setFailedPowerHighlight(false), 2000);
            actions.showToast("Party power is insufficient for this floor.");
            return false;
        }

        return true;
    };

    const handleStartAutoExpedition = () => {
        if (!isFloorCleared) {
            actions.showToast("Auto exploration requires at least one manual clear of this floor.");
            return;
        }
        if (isOngoingManual) return actions.showToast("Manual assault active.");
        if (!validateEntry()) return;
        actions.startExpedition(selectedDungeon.id, party);
    };

    const handleStartManualAssault = () => {
        if (isOngoingManual) {
            actions.toggleManualDungeonOverlay(true);
            return;
        }
        if (!validateEntry()) return;
        actions.startManualAssault(selectedDungeon.id, party, selectedFloor);
    };

    const currentPartyPower = useMemo(() => {
        const selectedMercs = knownMercenaries.filter(m => party.includes(m.id));
        return calculatePartyPower(selectedMercs);
    }, [party, knownMercenaries]);

    const [timeLeft, setTimeLeft] = useState<string>('');
    useEffect(() => {
        if (!currentExpedition || currentExpedition.status === 'COMPLETED') {
            setTimeLeft(currentExpedition?.status === 'COMPLETED' ? '00:00' : '');
            return;
        }
        const interval = setInterval(() => {
            const diff = currentExpedition.endTime - Date.now();
            if (diff <= 0) setTimeLeft('00:00');
            else setTimeLeft(formatDuration(diff));
        }, 1000);
        return () => clearInterval(interval);
    }, [currentExpedition]);

    // --- RENDER: LIST VIEW ---
    if (view === 'LIST') {
        return (
            <div className="h-full w-full bg-stone-950 flex flex-col p-4 md:p-8 animate-in fade-in duration-500 overflow-hidden">
                <div className="flex justify-between items-end border-b border-stone-800 pb-4 mb-6 shrink-0">
                    <div>
                        <h2 className="text-2xl md:text-4xl font-black text-amber-500 font-serif uppercase tracking-tighter">Tactical Deployment</h2>
                        <p className="text-stone-500 text-[10px] md:text-xs font-bold uppercase tracking-[0.2em] mt-1">Select Engagement Zone</p>
                    </div>
                    <div className="flex items-center gap-2 bg-stone-900 px-3 py-1.5 rounded-lg border border-stone-800 text-[10px] font-mono text-stone-500">
                        <LayoutList className="w-3.5 h-3.5" /> Sector Overview
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar pr-2 space-y-4">
                    {DUNGEONS.map(d => {
                        const isLocked = d.tier > state.stats.tierLevel + 1;
                        const maxReached = maxFloorReached[d.id] || 1;
                        const progressPercent = (maxReached / d.maxFloors) * 100;

                        return (
                            <button 
                                key={d.id} 
                                onClick={() => handleDungeonSelect(d.id)}
                                className={`w-full group relative flex flex-col md:flex-row items-center gap-4 p-4 md:p-6 rounded-2xl border-2 transition-all overflow-hidden ${isLocked ? 'bg-stone-900 border-stone-800 opacity-50 grayscale' : 'bg-stone-900/40 border-stone-800 hover:border-amber-500 hover:bg-stone-800 shadow-xl active:scale-[0.99]'}`}
                            >
                                {/* Background Image/Icon */}
                                <div className="w-20 h-20 md:w-32 md:h-32 bg-stone-950 rounded-xl border-2 border-stone-800 flex items-center justify-center text-4xl md:text-6xl shrink-0 shadow-inner group-hover:scale-105 transition-transform duration-500">
                                    {isLocked ? <Lock className="w-8 h-8 text-stone-700" /> : (d.id.includes('rat') ? '🐀' : d.id.includes('goblin') ? '👺' : d.id.includes('mine') ? '⛏️' : '🏰')}
                                </div>

                                <div className="flex-1 text-center md:text-left min-w-0">
                                    <div className="flex flex-col md:flex-row md:items-center gap-2 mb-1">
                                        <h3 className="text-lg md:text-2xl font-black text-stone-100 uppercase font-serif tracking-tight">{d.name}</h3>
                                        <span className={`w-fit mx-auto md:mx-0 px-2 py-0.5 rounded font-black text-[8px] md:text-[10px] uppercase border ${isLocked ? 'border-stone-700 text-stone-600' : 'border-amber-600/30 bg-amber-900/20 text-amber-500'}`}>Tier {d.tier}</span>
                                    </div>
                                    <p className="text-stone-500 text-[10px] md:text-sm line-clamp-2 italic mb-3">"{d.description}"</p>

                                    <div className="flex flex-wrap justify-center md:justify-start gap-4">
                                        <div className="flex items-center gap-2">
                                            <Layers className="w-3.5 h-3.5 text-stone-600" />
                                            <span className="text-[10px] md:text-xs font-black text-stone-400 uppercase">Progression: <span className="text-amber-500">{maxReached}/{d.maxFloors} Floors</span></span>
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <Skull className="w-3.5 h-3.5 text-stone-600" />
                                            <span className="text-[10px] md:text-xs font-black text-stone-400 uppercase">Threat: <span className="text-red-500">POW {d.requiredPower}</span></span>
                                        </div>
                                    </div>

                                    <div className="mt-3 w-full h-1.5 bg-stone-950 rounded-full overflow-hidden border border-stone-800 shadow-inner">
                                        <div className="h-full bg-gradient-to-r from-amber-900 to-amber-500 transition-all duration-1000" style={{ width: `${progressPercent}%` }}></div>
                                    </div>
                                </div>

                                <div className="absolute top-4 right-4 md:relative md:top-0 md:right-0">
                                    {isLocked ? (
                                        <Lock className="w-6 h-6 text-stone-800" />
                                    ) : (
                                        <ChevronRight className="w-6 h-6 text-stone-700 group-hover:text-amber-500 group-hover:translate-x-1 transition-all" />
                                    )}
                                </div>
                            </button>
                        );
                    })}
                </div>
            </div>
        );
    }

    // --- RENDER: DETAIL VIEW ---
    return (
        <div className="h-full w-full flex flex-col sm:flex-row bg-stone-950 text-stone-200 overflow-hidden font-sans relative">
            {(!!activeManualDungeon && showManualDungeonOverlay) && <AssaultNavigator />}

            {/* Top/Left info Section: Reduced height from 42% to 38% on mobile for more control space */}
            <div className="w-full sm:w-[40%] h-[38%] sm:h-full flex flex-col border-b sm:border-b-0 sm:border-r border-stone-800 bg-stone-900/50 relative overflow-hidden shrink-0 min-h-0">
                <div className="absolute inset-0 opacity-10 pointer-events-none">
                    <img src={getAssetUrl('dungeon_bg.png')} className="w-full h-full object-cover grayscale" />
                </div>

                <div key={selectedDungeon.id} className="flex-1 flex flex-col items-center z-10 min-h-0">
                    <button onClick={() => setView('LIST')} className="absolute top-3 left-3 z-30 flex items-center gap-1.5 px-3 py-1.5 bg-stone-800 hover:bg-stone-700 rounded-lg border border-stone-700 text-stone-400 text-[10px] font-black uppercase transition-all shadow-xl active:scale-95">
                        <ChevronLeft className="w-3.5 h-3.5" /> Back
                    </button>

                    <div className="relative flex flex-col items-center pt-8 sm:pt-14 z-10 shrink-0 w-full">
                        <div className="h-12 sm:h-20 flex flex-col items-center justify-center text-center px-10 mb-1 sm:mb-2">
                            <h1 className="text-lg sm:text-2xl lg:text-3xl font-black text-white font-serif tracking-tighter uppercase leading-none">{selectedDungeon.name}</h1>
                            <div className="mt-1 px-3 py-0.5 rounded-full bg-amber-900/30 border border-amber-600/30 text-amber-500 text-[8px] font-black uppercase tracking-widest shadow-lg">Tier {selectedDungeon.tier}</div>
                        </div>

                        <div className="relative w-full flex items-center justify-center h-20 sm:h-44 mb-2 sm:mb-6">
                            <button 
                                onClick={handlePrevFloor} 
                                className={`absolute left-4 z-30 p-2 sm:p-5 rounded-full border transition-all active:scale-90 shadow-2xl backdrop-blur-md ${selectedFloor > 1 ? 'bg-stone-800 hover:bg-amber-600 border-stone-700 text-white' : 'bg-stone-900 border-stone-850 text-stone-800 opacity-20 cursor-not-allowed'}`}
                            >
                                <ChevronLeft className="w-5 h-5 sm:w-10 sm:h-10" />
                            </button>

                            <div className="relative group animate-in fade-in zoom-in duration-300">
                                <div className={`w-16 h-16 sm:w-36 lg:w-44 sm:h-36 lg:h-44 bg-stone-900 rounded-2xl sm:rounded-[2rem] border-2 sm:border-4 border-stone-700 flex flex-col items-center justify-center relative shadow-2xl overflow-hidden ring-4 ring-white/5`}>
                                     <div className="text-[8px] sm:text-[10px] font-black text-stone-600 uppercase">Floor</div>
                                     <div className="text-3xl sm:text-7xl lg:text-8xl font-black text-white font-mono leading-none">{selectedFloor}</div>
                                </div>
                                {selectedFloor === selectedDungeon.maxFloors && (
                                    <div className="absolute -top-2 -right-2 px-2 py-0.5 bg-red-600 border border-red-400 rounded-lg text-white font-black text-[8px] sm:text-[10px] shadow-2xl animate-pulse rotate-12 z-40">BOSS</div>
                                )}
                            </div>

                            <button 
                                onClick={handleNextFloor} 
                                className={`absolute right-4 z-30 p-2 sm:p-5 rounded-full border transition-all active:scale-90 shadow-2xl backdrop-blur-md ${selectedFloor < selectedDungeon.maxFloors ? 'bg-stone-800 hover:bg-amber-600 border-stone-700 text-white' : 'bg-stone-900 border-stone-850 text-stone-800 opacity-20 cursor-not-allowed'}`}
                            >
                                <ChevronRight className="w-5 h-5 sm:w-10 sm:h-10" />
                            </button>
                        </div>
                    </div>

                    <div className="flex-1 overflow-y-auto custom-scrollbar p-1 sm:p-8 pt-0 z-10 flex flex-col items-center min-h-0 w-full">
                        <div className="w-full max-w-sm space-y-3 sm:space-y-6">
                            <div className="bg-stone-950/40 p-2 sm:p-4 rounded-xl border border-stone-800/50">
                                <div className="flex items-center justify-center gap-1.5 mb-2">
                                    <Box className="w-3 h-3 text-stone-600" />
                                    <h4 className="text-[9px] sm:text-xs font-black text-stone-500 uppercase tracking-widest">Rewards</h4>
                                </div>
                                <div className="flex wrap justify-center gap-2 sm:gap-3">
                                    {selectedDungeon.rewards.map((reward, ridx) => (
                                        <div key={`${reward.itemId}-${ridx}`} className="w-8 h-8 md:w-14 md:h-14 bg-stone-900 border border-stone-800 rounded-lg flex items-center justify-center shadow-inner relative group">
                                            <img src={getAssetUrl(`${reward.itemId}.png`)} className="w-6 h-6 md:w-10 md:h-10 object-contain" onError={e=>e.currentTarget.style.display='none'} />
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            <div className="flex-1 flex flex-col bg-stone-925 relative overflow-hidden min-h-0 min-w-0">
                {hasActiveMission ? (
                    <div className="flex-1 flex flex-col items-center justify-center p-6 sm:p-12 text-center animate-in fade-in duration-700">
                        <Trophy className={`w-12 h-12 sm:w-28 mb-8 ${currentExpedition?.status === 'COMPLETED' ? 'text-emerald-500 animate-bounce' : 'text-stone-800 opacity-30'}`} />
                        <h2 className="text-lg sm:text-4xl font-black text-stone-100 mb-2 uppercase tracking-tighter font-serif italic">Mission Underway</h2>
                        <div className="bg-stone-900/80 border-2 border-stone-800 px-10 py-5 rounded-2xl font-mono text-2xl sm:text-4xl font-black text-amber-50 shadow-2xl flex items-center gap-3 mb-8">
                            <Timer className="w-8 h-8 animate-pulse text-amber-600" />
                            <span>{timeLeft || '---'}</span>
                        </div>
                        <div className="flex gap-3">
                            {currentExpedition?.status === 'COMPLETED' ? (
                                <button onClick={() => actions.claimExpedition(currentExpedition.id)} className="px-10 py-4 bg-emerald-600 hover:bg-emerald-500 text-white font-black rounded-xl shadow-xl flex items-center gap-2 border-b-4 border-emerald-800 active:scale-95 transition-all uppercase tracking-widest"><CheckCircle className="w-5 h-5" /> Secure Loot</button>
                            ) : (
                                <button onClick={() => setShowRecallConfirm(isOngoingManual ? 'MANUAL' : 'AUTO')} className="px-6 py-3 bg-red-950/30 hover:bg-red-900/50 border border-red-900/50 rounded-xl text-red-500 font-black text-xs uppercase tracking-widest transition-all active:scale-95"><Ban className="w-4 h-4 mr-2 inline" /> Recall Squad</button>
                            )}
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 flex flex-col overflow-hidden">
                        {/* Stats Bar: Tighter padding on mobile */}
                        <div className="p-2 sm:p-6 bg-stone-900/80 border-b border-stone-800 grid grid-cols-3 gap-2 sm:gap-4 shrink-0">
                            <div className="bg-stone-950 p-2 sm:p-4 rounded-xl border border-stone-800 flex flex-col items-center justify-center">
                                <span className="text-[8px] sm:text-[10px] text-stone-500 font-black uppercase mb-0.5 sm:mb-1">Time</span>
                                <div className="text-xs sm:text-xl font-black text-stone-200 font-mono">{selectedDungeon.durationMinutes}m</div>
                            </div>
                            <div className="bg-stone-950 p-2 sm:p-4 rounded-xl border border-stone-800 flex flex-col items-center justify-center">
                                <span className="text-[8px] sm:text-[10px] text-stone-500 font-black uppercase mb-0.5 sm:mb-1">Energy</span>
                                <div className="text-xs sm:text-xl font-black text-blue-400 font-mono">-{energyCostForFloor}</div>
                            </div>
                            <div className={`bg-stone-950 p-2 sm:p-4 rounded-xl border flex flex-col items-center justify-center transition-all ${failedPowerHighlight ? 'border-red-500 ring-2 ring-red-500/50 animate-shake-hard' : 'border-stone-800'}`}>
                                <span className="text-[8px] sm:text-[10px] text-stone-500 font-black uppercase mb-0.5 sm:mb-1">Req. Power</span>
                                <div className={`text-xs sm:text-xl font-black font-mono ${currentPartyPower >= requiredPowerForFloor ? 'text-emerald-400' : 'text-red-500'}`}>{currentPartyPower} / {requiredPowerForFloor}</div>
                            </div>
                        </div>

                        <div className="flex-1 flex flex-col sm:flex-row overflow-hidden p-3 sm:p-6 gap-4 sm:gap-6 min-h-0">
                            <div className="w-full sm:w-[45%] flex flex-col gap-2 sm:gap-3 shrink-0">
                                <h3 className="text-[9px] sm:text-xs font-black text-stone-500 uppercase tracking-widest px-1 flex justify-between"><span>Squad Slots</span><span>{party.length}/{maxPartySize}</span></h3>
                                <div className="grid grid-cols-4 sm:grid-cols-2 gap-2 sm:gap-3 shrink-0">
                                    {Array.from({ length: 4 }).map((_, idx) => {
                                        const isAvailable = idx < maxPartySize;
                                        const mercId = party[idx];
                                        const merc = knownMercenaries.find(m => m.id === mercId);
                                        const hasError = mercId && (failedMercs.includes(mercId) || lowHpMercs.includes(mercId));

                                        if (!isAvailable) return <div key={idx} className="aspect-square bg-stone-950/60 border-2 border-stone-900 rounded-xl sm:rounded-2xl flex items-center justify-center grayscale"><Ban className="w-6 sm:w-10 text-stone-800" /></div>;

                                        return (
                                            <div key={idx} className={`aspect-square bg-stone-900 border-2 rounded-xl sm:rounded-2xl flex items-center justify-center relative shadow-2xl overflow-hidden group hover:bg-stone-850 transition-all ${hasError ? 'border-red-600 animate-shake-hard' : 'border-dashed border-stone-800'}`}>
                                                {!!merc ? (
                                                    <button onClick={() => toggleMercenary(merc.id)} className="w-full h-full flex flex-col items-center justify-center p-1 sm:p-2 relative animate-in zoom-in-95">
                                                        <div className="text-2xl sm:text-6xl group-hover:scale-110 transition-transform mb-0.5 sm:mb-1">{merc.icon}</div>
                                                        <div className="text-[7px] sm:text-xs font-black text-stone-200 truncate w-full text-center">{merc.name.split(' ')[0]}</div>
                                                        <div className="absolute top-1 right-1 sm:top-2 sm:right-2 opacity-0 group-hover:opacity-100 transition-opacity"><XCircle className="w-4 sm:w-5 text-red-600" /></div>
                                                        {hasError && <div className="absolute inset-0 bg-red-900/40 backdrop-blur-[1px] flex items-center justify-center"><AlertCircle className="w-8 sm:w-10 text-white" /></div>}
                                                    </button>
                                                ) : <User className="text-stone-800/40 w-8 sm:w-12" />}
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>

                            <div className="flex-1 flex flex-col bg-stone-950/40 rounded-xl sm:rounded-2xl border border-stone-800 shadow-inner overflow-hidden">
                                <div className="p-1.5 sm:p-3 border-b border-stone-800 bg-stone-900/40 flex justify-between items-center"><span className="text-[9px] sm:text-xs font-black text-stone-400 uppercase tracking-widest">Available Units</span></div>
                                <div className="flex-1 overflow-y-auto custom-scrollbar p-2 sm:p-3 space-y-1.5 sm:space-y-2">
                                    {hiredMercs.map(merc => {
                                        const isSelected = party.includes(merc.id);
                                        const isBusy = activeExpeditions.some(e => e.partyIds.includes(merc.id)) || (activeManualDungeon?.partyIds.includes(merc.id));
                                        const power = calculateMercenaryPower(merc);
                                        const energy = merc.expeditionEnergy || 0;
                                        const hasError = failedMercs.includes(merc.id) || lowHpMercs.includes(merc.id);

                                        return (
                                            <button key={merc.id} onClick={() => !isBusy && toggleMercenary(merc.id)} disabled={isBusy} className={`w-full flex items-center justify-between p-2 sm:p-3 rounded-lg sm:rounded-xl border transition-all ${isSelected ? 'bg-amber-900/30 border-amber-600' : 'bg-stone-900 border-stone-800'} ${isBusy ? 'opacity-40 grayscale cursor-not-allowed' : ''} ${hasError ? 'border-red-600' : ''}`}>
                                                <div className="flex items-center gap-2 sm:gap-3 min-w-0">
                                                    <div className="text-xl sm:text-4xl">{merc.icon}</div>
                                                    <div className="text-left"><div className="font-black text-stone-200 text-[10px] sm:text-sm truncate">{merc.name}</div><div className="text-[8px] sm:text-[10px] text-amber-500 font-mono font-bold">POW {power}</div></div>
                                                </div>
                                                <div className="flex flex-col items-end gap-1">
                                                    {isBusy ? <span className="text-[7px] font-black uppercase text-stone-500 bg-stone-950 px-2 py-0.5 rounded">Deployed</span> : <div className="flex items-center gap-1.5"><div className="w-10 sm:w-12 h-1.5 sm:h-2 bg-stone-950 rounded-full border border-stone-800"><div className={`h-full rounded-full ${energy >= energyCostForFloor ? 'bg-blue-500' : 'bg-red-500'}`} style={{ width: `${energy}%` }} /></div><Zap className={`w-3 h-3 sm:w-4 sm:h-4 ${energy >= energyCostForFloor ? 'text-blue-500' : 'text-red-500 animate-pulse'}`} /></div>}
                                                </div>
                                            </button>
                                        );
                                    })}
                                </div>
                            </div>
                        </div>

                        {/* Action Buttons: Fixed height on mobile, adjusted padding */}
                        <div className="p-3 sm:p-6 bg-stone-900/50 border-t border-stone-800 shrink-0">
                            <div className="grid grid-cols-2 gap-3 sm:gap-4 max-w-xl mx-auto">
                                <button 
                                    onClick={handleStartAutoExpedition} 
                                    disabled={party.length === 0 || isOngoingManual || !isFloorCleared} 
                                    className={`group flex flex-col items-center justify-center gap-0.5 sm:gap-1 py-2 sm:py-4 rounded-xl border-b-4 transition-all shadow-xl ${party.length > 0 && !isOngoingManual && isFloorCleared ? 'bg-indigo-700 hover:bg-indigo-600 border-indigo-900 text-white' : 'bg-stone-800 text-stone-600 border-stone-900 cursor-not-allowed opacity-60'}`}
                                >
                                    <div className="flex items-center gap-1.5 sm:gap-2">
                                        {!isFloorCleared ? <Lock className="w-3 sm:w-4" /> : <Timer className="w-4 sm:w-5" />}
                                        <span className="font-black uppercase text-[10px] sm:text-sm">Strategic</span>
                                    </div>
                                    <span className="text-[7px] sm:text-[8px] font-bold opacity-60 uppercase">
                                        {isFloorCleared ? "Auto Expedition" : "Requires Manual"}
                                    </span>
                                </button>

                                <button onClick={handleStartManualAssault} disabled={party.length === 0 && !isOngoingManual} className={`group flex flex-col items-center justify-center gap-0.5 sm:gap-1 py-2 sm:py-4 rounded-xl border-b-4 transition-all shadow-xl ${party.length > 0 || isOngoingManual ? 'bg-amber-600 hover:bg-amber-500 border-amber-800 text-white' : 'bg-stone-800 text-stone-600 border-stone-900 cursor-not-allowed'}`}><div className="flex items-center gap-1.5 sm:gap-2"><Gamepad2 className="w-4 sm:w-5" /><span className="font-black uppercase text-[10px] sm:text-sm">{isOngoingManual ? 'Resume' : 'Direct Assault'}</span></div><span className="text-[7px] sm:text-[10px] font-bold opacity-60 uppercase">Manual Exploration</span></button>
                            </div>
                        </div>
                    </div>
                )}
            </div>

            <ConfirmationModal isOpen={!!showRecallConfirm} title="Abort Mission?" message="Recalling the squad now will forfeit all progress and potential loot. Continue?" confirmLabel="Confirm Recall" cancelLabel="Stay Deployed" isDanger onConfirm={() => { if(showRecallConfirm==='AUTO') actions.abortExpedition(currentExpedition!.id); else actions.retreatFromManualDungeon(); setShowRecallConfirm(null); }} onCancel={() => setShowRecallConfirm(null)} />
        </div>
    );
};

export default DungeonTab;

import { useState, useMemo, useEffect } from 'react';
import { useGame } from '../../../context/GameContext';
import { DUNGEONS } from '../../../data/dungeons';
import { calculatePartyPower, calculateMercenaryPower } from '../../../utils/combatLogic';
import { Skull, Timer, Zap, ChevronRight, ChevronLeft, Lock, CheckCircle, Trophy, User, XCircle, Box, AlertCircle, Gamepad2, Ban, Layers, X, Search, Sword } from 'lucide-react';
import { getAssetUrl, formatDuration } from '../../../utils';
import AssaultNavigator from './AssaultNavigator';
import ConfirmationModal from '../../modals/ConfirmationModal';

const DungeonTab = () => {
    const { state, actions } = useGame();
    const { activeExpeditions, knownMercenaries, dungeonClearCounts, maxFloorReached, activeManualDungeon, showManualDungeonOverlay } = state;

    // View State
    const [view, setView] = useState<'LIST' | 'DETAIL'>('LIST');
    const [selectedDungeonId, setSelectedDungeonId] = useState<string | null>(null);
    const [selectedFloor, setSelectedFloor] = useState(1);
    const [party, setParty] = useState<string[]>([]);
    const [failedMercs, setFailedMercs] = useState<string[]>([]);
    const [lowHpMercs, setLowHpMercs] = useState<string[]>([]);
    const [failedPowerHighlight, setFailedPowerHighlight] = useState(false);
    const [showRecallConfirm, setShowRecallConfirm] = useState<'AUTO' | 'MANUAL' | null>(null);

    // Picker Modal State
    const [isPickerOpen, setIsPickerOpen] = useState(false);

    const selectedDungeon = useMemo(() => 
        DUNGEONS.find(d => d.id === selectedDungeonId) || DUNGEONS[0], 
    [selectedDungeonId]);

    const maxPartySize = selectedDungeon.maxPartySize || 4;
    const isOngoingManual = !!activeManualDungeon && activeManualDungeon.dungeonId === selectedDungeon.id;
    const currentExpedition = activeExpeditions.find(e => e.dungeonId === selectedDungeon.id);
    const hasActiveMission = !!currentExpedition || isOngoingManual;

    const isFloorCleared = useMemo(() => {
        const maxReached = maxFloorReached[selectedDungeon.id] || 1;
        if (selectedFloor < maxReached) return true;
        if (selectedFloor === selectedDungeon.maxFloors && (dungeonClearCounts[selectedDungeon.id] || 0) > 0) return true;
        return false;
    }, [selectedDungeon, selectedFloor, maxFloorReached, dungeonClearCounts]);

    const hiredMercs = useMemo(() => 
        knownMercenaries.filter(m => m.status === 'HIRED' || m.status === 'ON_EXPEDITION'), 
    [knownMercenaries]);

    // Candidates for the picker (Not already in party)
    const availableCandidates = useMemo(() => 
        hiredMercs.filter(m => !party.includes(m.id)),
    [hiredMercs, party]);

    const requiredPowerForFloor = useMemo(() => {
        const base = selectedDungeon.requiredPower;
        return Math.round(base * (1 + (selectedFloor - 1) * 0.25));
    }, [selectedDungeon, selectedFloor]);

    const energyCostForFloor = useMemo(() => {
        const base = selectedDungeon.energyCost;
        return base + (selectedFloor - 1) * 5;
    }, [selectedDungeon, selectedFloor]);

    const handleDungeonSelect = (id: string) => {
        const dungeon = DUNGEONS.find(d => d.id === id);
        if (!dungeon || dungeon.tier > state.stats.tierLevel + 1) {
            actions.showToast("This area is currently inaccessible.");
            return;
        }
        setSelectedDungeonId(id);
        setSelectedFloor(1);
        setParty([]);
        setView('DETAIL');
    };

    const handlePrevFloor = () => setSelectedFloor(prev => Math.max(1, prev - 1));
    const handleNextFloor = () => {
        const maxReached = maxFloorReached[selectedDungeon.id] || 1;
        if (selectedFloor >= selectedDungeon.maxFloors) return;
        if (selectedFloor >= maxReached) {
            actions.showToast("You must clear the current floor to descend deeper.");
            return;
        }
        setSelectedFloor(prev => Math.min(selectedDungeon.maxFloors, prev + 1));
    };

    const toggleMercenary = (mercId: string) => {
        if (party.includes(mercId)) {
            setParty(prev => prev.filter(id => id !== mercId));
        } else if (party.length < maxPartySize) {
            setParty(prev => [...prev, mercId]);
            setIsPickerOpen(false);
        }
    };

    const validateEntry = () => {
        if (party.length === 0) return false;
        const selectedMercs = knownMercenaries.filter(m => party.includes(m.id));

        const lowHpIds = selectedMercs.filter(m => (m.currentHp || 0) < 1).map(m => m.id);
        if (lowHpIds.length > 0) {
            setLowHpMercs(lowHpIds);
            setTimeout(() => setLowHpMercs([]), 2000);
            actions.showToast("Wounded members cannot be deployed.");
            return false;
        }

        const lowEnergyIds = selectedMercs.filter(m => (m.expeditionEnergy || 0) < energyCostForFloor).map(m => m.id);
        if (lowEnergyIds.length > 0) {
            setFailedMercs(lowEnergyIds);
            setTimeout(() => setFailedMercs([]), 2000);
            actions.showToast("Some squad members are too exhausted.");
            return false;
        }

        if (currentPartyPower < requiredPowerForFloor) {
            setFailedPowerHighlight(true);
            setTimeout(() => setFailedPowerHighlight(false), 2000);
            actions.showToast("Party power is insufficient for this floor.");
            return false;
        }
        return true;
    };

    const handleStartAutoExpedition = () => {
        if (!isFloorCleared) { actions.showToast("Manual clear required."); return; }
        if (isOngoingManual) return actions.showToast("Manual assault active.");
        if (!validateEntry()) return;
        actions.startExpedition(selectedDungeon.id, party);
    };

    const handleStartManualAssault = () => {
        if (isOngoingManual) { actions.toggleManualDungeonOverlay(true); return; }
        if (!validateEntry()) return;
        actions.startManualAssault(selectedDungeon.id, party, selectedFloor);
    };

    const currentPartyPower = useMemo(() => {
        const selectedMercs = knownMercenaries.filter(m => party.includes(m.id));
        return calculatePartyPower(selectedMercs);
    }, [party, knownMercenaries]);

    const [timeLeft, setTimeLeft] = useState<string>('');
    useEffect(() => {
        if (!currentExpedition || currentExpedition.status === 'COMPLETED') {
            setTimeLeft(currentExpedition?.status === 'COMPLETED' ? '00:00' : '');
            return;
        }
        const interval = setInterval(() => {
            const diff = currentExpedition.endTime - Date.now();
            if (diff <= 0) setTimeLeft('00:00');
            else setTimeLeft(formatDuration(diff));
        }, 1000);
        return () => clearInterval(interval);
    }, [currentExpedition]);

    // --- RENDER: LIST VIEW ---
    if (view === 'LIST') {
        return (
            <div className="h-full w-full bg-stone-950 flex flex-col p-4 md:p-8 animate-in fade-in duration-500 overflow-hidden">
                <div className="flex justify-between items-end border-b border-stone-800 pb-4 mb-6 shrink-0">
                    <div>
                        <h2 className="text-2xl md:text-4xl font-black text-amber-500 font-serif uppercase tracking-tighter">Tactical Deployment</h2>
                        <p className="text-stone-500 text-[10px] md:text-xs font-bold uppercase tracking-[0.2em] mt-1">Select Engagement Zone</p>
                    </div>
                    <div className="flex items-center gap-2 bg-stone-900 px-3 py-1.5 rounded-lg border border-stone-800 text-[10px] font-mono text-stone-500">
                        <LayoutList className="w-3.5 h-3.5" /> Sector Overview
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar pr-2 space-y-4">
                    {DUNGEONS.map(d => {
                        const isLocked = d.tier > state.stats.tierLevel + 1;
                        const maxReached = maxFloorReached[d.id] || 1;
                        const progressPercent = (maxReached / d.maxFloors) * 100;
                        return (
                            <button key={d.id} onClick={() => handleDungeonSelect(d.id)} className={`w-full group relative flex flex-col md:flex-row items-center gap-4 p-4 md:p-6 rounded-2xl border-2 transition-all overflow-hidden ${isLocked ? 'bg-stone-900 border-stone-800 opacity-50 grayscale' : 'bg-stone-900/40 border-stone-800 hover:border-amber-500 hover:bg-stone-800 shadow-xl active:scale-[0.99]'}`}>
                                <div className="w-20 h-20 md:w-32 md:h-32 bg-stone-950 rounded-xl border-2 border-stone-800 flex items-center justify-center text-4xl md:text-6xl shrink-0 shadow-inner group-hover:scale-105 transition-transform duration-500">
                                    {isLocked ? <Lock className="w-8 h-8 text-stone-700" /> : (d.id.includes('rat') ? '🐀' : d.id.includes('goblin') ? '👺' : d.id.includes('mine') ? '⛏️' : '🏰')}
                                </div>
                                <div className="flex-1 text-center md:text-left min-w-0">
                                    <div className="flex flex-col md:flex-row md:items-center gap-2 mb-1">
                                        <h3 className="text-lg md:text-2xl font-black text-stone-100 uppercase font-serif tracking-tight">{d.name}</h3>
                                        <span className={`w-fit mx-auto md:mx-0 px-2 py-0.5 rounded font-black text-[8px] md:text-[10px] uppercase border ${isLocked ? 'border-stone-700 text-stone-600' : 'border-amber-600/30 bg-amber-900/20 text-amber-500'}`}>Tier {d.tier}</span>
                                    </div>
                                    <p className="text-stone-500 text-[10px] md:text-sm line-clamp-2 italic mb-3">"{d.description}"</p>
                                    <div className="flex flex-wrap justify-center md:justify-start gap-4">
                                        <div className="flex items-center gap-2"><Layers className="w-3.5 h-3.5 text-stone-600" /><span className="text-[10px] md:text-xs font-black text-stone-400 uppercase">Progression: <span className="text-amber-500">{maxReached}/{d.maxFloors} Floors</span></span></div>
                                        <div className="flex items-center gap-2"><Skull className="w-3.5 h-3.5 text-stone-600" /><span className="text-[10px] md:text-xs font-black text-stone-400 uppercase">Threat: <span className="text-red-500">POW {d.requiredPower}</span></span></div>
                                    </div>
                                    <div className="mt-3 w-full h-1.5 bg-stone-950 rounded-full overflow-hidden border border-stone-800 shadow-inner"><div className="h-full bg-gradient-to-r from-amber-900 to-amber-500 transition-all duration-1000" style={{ width: `${progressPercent}%` }}></div></div>
                                </div>
                                <div className="absolute top-4 right-4 md:relative md:top-0 md:right-0">
                                    {isLocked ? <Lock className="w-6 h-6 text-stone-800" /> : <ChevronRight className="w-6 h-6 text-stone-700 group-hover:text-amber-500 group-hover:translate-x-1 transition-all" />}
                                </div>
                            </button>
                        );
                    })}
                </div>
            </div>
        );
    }

    // --- RENDER: DETAIL VIEW ---
    return (
        <div className="h-full w-full flex flex-col sm:flex-row bg-stone-950 text-stone-200 overflow-hidden font-sans relative">
            {(!!activeManualDungeon && showManualDungeonOverlay) && <AssaultNavigator />}

            {/* Left Info Section */}
            <div className="w-full sm:w-[40%] h-[35%] sm:h-full flex flex-col border-b sm:border-b-0 sm:border-r border-stone-800 bg-stone-900/50 relative overflow-hidden shrink-0 min-h-0">
                <div className="absolute inset-0 opacity-10 pointer-events-none"><img src={getAssetUrl('dungeon_bg.png')} className="w-full h-full object-cover grayscale" /></div>
                <div className="flex-1 flex flex-col items-center z-10 min-h-0">
                    <button onClick={() => setView('LIST')} className="absolute top-3 left-3 z-30 flex items-center gap-1.5 px-3 py-1.5 bg-stone-800 hover:bg-stone-700 rounded-lg border border-stone-700 text-stone-400 text-[10px] font-black uppercase transition-all shadow-xl active:scale-95"><ChevronLeft className="w-3.5 h-3.5" /> Back</button>
                    <div className="relative flex flex-col items-center pt-8 sm:pt-14 shrink-0 w-full">
                        <div className="h-12 sm:h-20 flex flex-col items-center justify-center text-center px-10 mb-1 sm:mb-2">
                            <h1 className="text-lg sm:text-2xl lg:text-3xl font-black text-white font-serif tracking-tighter uppercase leading-none">{selectedDungeon.name}</h1>
                            <div className="mt-1 px-3 py-0.5 rounded-full bg-amber-900/30 border border-amber-600/30 text-amber-500 text-[8px] font-black uppercase tracking-widest">Tier {selectedDungeon.tier}</div>
                        </div>
                        <div className="relative w-full flex items-center justify-center h-20 sm:h-44 mb-2 sm:mb-6">
                            <button onClick={handlePrevFloor} className={`absolute left-4 z-30 p-2 sm:p-5 rounded-full border transition-all active:scale-90 ${selectedFloor > 1 ? 'bg-stone-800 hover:bg-amber-600 border-stone-700 text-white' : 'bg-stone-900 border-stone-850 text-stone-800 opacity-20 cursor-not-allowed'}`}><ChevronLeft className="w-5 h-5 sm:w-10 sm:h-10" /></button>
                            <div className="relative group animate-in fade-in zoom-in duration-300">
                                <div className="w-16 h-16 sm:w-36 lg:w-44 sm:h-36 lg:h-44 bg-stone-900 rounded-2xl sm:rounded-[2rem] border-2 sm:border-4 border-stone-700 flex flex-col items-center justify-center relative shadow-2xl ring-4 ring-white/5">
                                     <div className="text-[8px] sm:text-[10px] font-black text-stone-600 uppercase">Floor</div>
                                     <div className="text-3xl sm:text-7xl lg:text-8xl font-black text-white font-mono leading-none">{selectedFloor}</div>
                                </div>
                                {selectedFloor === selectedDungeon.maxFloors && <div className="absolute -top-2 -right-2 px-2 py-0.5 bg-red-600 border border-red-400 rounded-lg text-white font-black text-[8px] sm:text-[10px] shadow-2xl rotate-12 z-40">BOSS</div>}
                            </div>
                            <button onClick={handleNextFloor} className={`absolute right-4 z-30 p-2 sm:p-5 rounded-full border transition-all active:scale-90 ${selectedFloor < selectedDungeon.maxFloors ? 'bg-stone-800 hover:bg-amber-600 border-stone-700 text-white' : 'bg-stone-900 border-stone-850 text-stone-800 opacity-20 cursor-not-allowed'}`}><ChevronRight className="w-5 h-5 sm:w-10 sm:h-10" /></button>
                        </div>
                    </div>
                    <div className="flex-1 overflow-y-auto custom-scrollbar p-1 sm:p-8 pt-0 z-10 flex flex-col items-center min-h-0 w-full">
                        <div className="bg-stone-950/40 p-2 sm:p-4 rounded-xl border border-stone-800/50 w-full max-w-[280px]">
                            <div className="flex items-center justify-center gap-1.5 mb-2"><Box className="w-3 h-3 text-stone-600" /><h4 className="text-[9px] sm:text-xs font-black text-stone-500 uppercase tracking-widest">Potential Rewards</h4></div>
                            <div className="flex wrap justify-center gap-2 sm:gap-3">
                                {selectedDungeon.rewards.map((reward, ridx) => (
                                    <div key={`${reward.itemId}-${ridx}`} className="w-8 h-8 md:w-12 md:h-12 bg-stone-900 border border-stone-800 rounded-lg flex items-center justify-center shadow-inner group">
                                        <img src={getAssetUrl(`${reward.itemId}.png`)} className="w-6 h-6 md:w-8 md:h-8 object-contain" onError={e=>e.currentTarget.style.display='none'} />
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Right Squad & Action Section */}
            <div className="flex-1 flex flex-col bg-stone-925 relative overflow-hidden min-h-0 min-w-0">
                {hasActiveMission ? (
                    <div className="flex-1 flex flex-col items-center justify-center p-6 sm:p-12 text-center animate-in fade-in duration-700">
                        <Trophy className={`w-12 h-12 sm:w-28 mb-8 ${currentExpedition?.status === 'COMPLETED' ? 'text-emerald-500 animate-bounce' : 'text-stone-800 opacity-30'}`} />
                        <h2 className="text-lg sm:text-4xl font-black text-stone-100 mb-2 uppercase tracking-tighter font-serif italic">Mission Underway</h2>
                        <div className="bg-stone-900/80 border-2 border-stone-800 px-10 py-5 rounded-2xl font-mono text-2xl sm:text-4xl font-black text-amber-50 shadow-2xl flex items-center gap-3 mb-8"><Timer className="w-8 h-8 animate-pulse text-amber-600" /><span>{timeLeft || '---'}</span></div>
                        <div className="flex gap-3">
                            {currentExpedition?.status === 'COMPLETED' ? (
                                <button onClick={() => actions.claimExpedition(currentExpedition.id)} className="px-10 py-4 bg-emerald-600 hover:bg-emerald-500 text-white font-black rounded-xl shadow-xl flex items-center gap-2 border-b-4 border-emerald-800 active:scale-95 transition-all uppercase tracking-widest"><CheckCircle className="w-5 h-5" /> Secure Loot</button>
                            ) : (
                                <button onClick={() => setShowRecallConfirm(isOngoingManual ? 'MANUAL' : 'AUTO')} className="px-6 py-3 bg-red-950/30 hover:bg-red-900/50 border border-red-900/50 rounded-xl text-red-500 font-black text-xs uppercase tracking-widest transition-all active:scale-95"><Ban className="w-4 h-4 mr-2 inline" /> Recall Squad</button>
                            )}
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 flex flex-col overflow-hidden">
                        <div className="p-2 sm:p-4 bg-stone-900/80 border-b border-stone-800 grid grid-cols-3 gap-2 sm:gap-4 shrink-0">
                            <div className="bg-stone-950 p-2 sm:p-4 rounded-xl border border-stone-800 flex flex-col items-center justify-center">
                                <span className="text-[8px] sm:text-[10px] text-stone-500 font-black uppercase mb-0.5">Time</span>
                                <div className="text-xs sm:text-xl font-black text-stone-200 font-mono">{selectedDungeon.durationMinutes}m</div>
                            </div>
                            <div className="bg-stone-950 p-2 sm:p-4 rounded-xl border border-stone-800 flex flex-col items-center justify-center">
                                <span className="text-[8px] sm:text-[10px] text-stone-500 font-black uppercase mb-0.5">Energy</span>
                                <div className="text-xs sm:text-xl font-black text-blue-400 font-mono">-{energyCostForFloor}</div>
                            </div>
                            <div className={`bg-stone-950 p-2 sm:p-4 rounded-xl border flex flex-col items-center justify-center transition-all ${failedPowerHighlight ? 'border-red-500 ring-2 ring-red-500/50 animate-shake-hard' : 'border-stone-800'}`}>
                                <span className="text-[8px] sm:text-[10px] text-stone-500 font-black uppercase mb-0.5">Req. Power</span>
                                <div className={`text-xs sm:text-xl font-black font-mono ${currentPartyPower >= requiredPowerForFloor ? 'text-emerald-400' : 'text-red-500'}`}>{currentPartyPower} / {requiredPowerForFloor}</div>
                            </div>
                        </div>

                        <div className="flex-1 flex flex-col items-center justify-center p-4 sm:p-8 min-h-0 overflow-hidden">
                            <div className="w-full max-w-xl space-y-4">
                                <div className="flex justify-between items-end px-2">
                                    <h3 className="text-[10px] sm:text-xs font-black text-stone-500 uppercase tracking-widest">Squad Assembly</h3>
                                    <span className="text-[10px] font-mono text-stone-600">{party.length} / {maxPartySize}</span>
                                </div>
                                <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 sm:gap-4">
                                    {Array.from({ length: 4 }).map((_, idx) => {
                                        const isAvailable = idx < maxPartySize;
                                        const mercId = party[idx];
                                        const merc = knownMercenaries.find(m => m.id === mercId);
                                        const hasError = mercId && (failedMercs.includes(mercId) || lowHpMercs.includes(mercId));

                                        if (!isAvailable) return <div key={idx} className="aspect-square bg-stone-950/60 border-2 border-stone-900 rounded-2xl flex items-center justify-center grayscale"><Ban className="w-8 text-stone-800" /></div>;

                                        return (
                                            <div key={idx} className={`aspect-square bg-stone-900 border-2 rounded-2xl flex items-center justify-center relative shadow-2xl overflow-hidden group hover:bg-stone-850 transition-all ${hasError ? 'border-red-600 animate-shake-hard' : 'border-dashed border-stone-800'}`}>
                                                {!!merc ? (
                                                    <button onClick={() => toggleMercenary(merc.id)} className="w-full h-full flex flex-col items-center justify-center p-2 relative animate-in zoom-in-95">
                                                        <div className="text-4xl sm:text-6xl group-hover:scale-110 transition-transform mb-1">{merc.icon}</div>
                                                        <div className="text-[8px] sm:text-xs font-black text-stone-200 truncate w-full text-center">{merc.name}</div>
                                                        <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity"><XCircle className="w-5 text-red-600" /></div>
                                                        {hasError && <div className="absolute inset-0 bg-red-900/40 backdrop-blur-[1px] flex items-center justify-center"><AlertCircle className="w-10 text-white" /></div>}
                                                    </button>
                                                ) : (
                                                    <button onClick={() => setIsPickerOpen(true)} className="w-full h-full flex flex-col items-center justify-center gap-2 text-stone-700 hover:text-amber-500 hover:bg-stone-850 transition-all">
                                                        <User className="w-10 h-10 opacity-20" />
                                                        <span className="text-[8px] font-black uppercase tracking-tighter">Add Member</span>
                                                    </button>
                                                )}
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        </div>

                        <div className="p-4 sm:p-8 bg-stone-900/50 border-t border-stone-800 shrink-0">
                            <div className="grid grid-cols-2 gap-4 max-w-xl mx-auto">
                                <button onClick={handleStartAutoExpedition} disabled={party.length === 0 || isOngoingManual || !isFloorCleared} className={`flex flex-col items-center justify-center gap-1 py-3 sm:py-5 rounded-xl border-b-4 transition-all shadow-xl ${party.length > 0 && !isOngoingManual && isFloorCleared ? 'bg-indigo-700 hover:bg-indigo-600 border-indigo-900 text-white' : 'bg-stone-800 text-stone-600 border-stone-900 opacity-60'}`}>
                                    <div className="flex items-center gap-2">{!isFloorCleared ? <Lock className="w-4" /> : <Timer className="w-5" />}<span className="font-black uppercase text-xs sm:text-sm">Strategic Deploy</span></div>
                                    <span className="text-[7px] sm:text-[9px] font-bold opacity-60 uppercase">{isFloorCleared ? "Auto Expedition" : "Requires Manual Clear"}</span>
                                </button>
                                <button onClick={handleStartManualAssault} disabled={party.length === 0 && !isOngoingManual} className={`flex flex-col items-center justify-center gap-1 py-3 sm:py-5 rounded-xl border-b-4 transition-all shadow-xl ${party.length > 0 || isOngoingManual ? 'bg-amber-600 hover:bg-amber-500 border-amber-800 text-white' : 'bg-stone-800 text-stone-600 border-stone-900 opacity-60'}`}><div className="flex items-center gap-2"><Gamepad2 className="w-5" /><span className="font-black uppercase text-xs sm:text-sm">{isOngoingManual ? 'Resume' : 'Direct Assault'}</span></div><span className="text-[7px] sm:text-[9px] font-bold opacity-60 uppercase">Manual Exploration</span></button>
                            </div>
                        </div>
                    </div>
                )}
            </div>

            {/* UNIT PICKER MODAL */}
            {isPickerOpen && (
                <div className="fixed inset-0 z-[1000] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-in fade-in duration-200">
                    <div className="bg-stone-900 border-2 border-stone-700 rounded-3xl w-full max-w-2xl max-h-[80vh] flex flex-col shadow-2xl overflow-hidden animate-in zoom-in-95">
                        <div className="p-4 border-b border-stone-800 bg-stone-850 flex justify-between items-center">
                            <div className="flex items-center gap-3">
                                <div className="bg-amber-900/30 p-2 rounded-xl border border-amber-700/50"><User className="w-5 h-5 text-amber-500" /></div>
                                <div>
                                    <h3 className="text-lg font-black text-stone-100 font-serif uppercase">Select Squad Member</h3>
                                    <p className="text-[10px] text-stone-500 font-black uppercase">Assign available units to the squad</p>
                                </div>
                            </div>
                            <button onClick={() => setIsPickerOpen(false)} className="p-2 hover:bg-stone-800 rounded-full text-stone-500 transition-colors"><X className="w-6 h-6" /></button>
                        </div>
                        <div className="flex-1 overflow-y-auto p-4 space-y-2 custom-scrollbar bg-stone-950/40">
                            {availableCandidates.length === 0 ? (
                                <div className="flex flex-col items-center justify-center py-20 opacity-20"><Search className="w-16 h-16 mb-4" /><p className="font-black uppercase text-sm tracking-widest">No candidates available</p></div>
                            ) : (
                                availableCandidates.map(merc => {
                                    const isBusy = activeExpeditions.some(e => e.partyIds.includes(merc.id)) || (activeManualDungeon?.partyIds.includes(merc.id));
                                    const power = calculateMercenaryPower(merc);
                                    const energy = merc.expeditionEnergy || 0;
                                    return (
                                        <button key={merc.id} onClick={() => !isBusy && toggleMercenary(merc.id)} disabled={isBusy} className={`w-full flex items-center justify-between p-3 rounded-xl border transition-all ${isBusy ? 'bg-stone-950 border-stone-900 opacity-40 grayscale cursor-not-allowed' : 'bg-stone-800 border-stone-700 hover:border-amber-500 hover:bg-stone-750 shadow-lg'}`}>
                                            <div className="flex items-center gap-4 min-w-0">
                                                <div className="text-4xl">{merc.icon}</div>
                                                <div className="text-left">
                                                    <div className="font-black text-stone-100 text-sm md:text-base truncate">{merc.name}</div>
                                                    <div className="flex items-center gap-2 mt-0.5">
                                                        <span className="text-[9px] font-black text-stone-500 uppercase tracking-widest">{merc.job} • Lv.{merc.level}</span>
                                                        <div className="flex items-center gap-1 text-[10px] text-amber-500 font-mono font-bold border-l border-stone-700 pl-2"><Sword className="w-3 h-3" /> {power}</div>
                                                    </div>
                                                </div>
                                            </div>
                                            <div className="flex flex-col items-end gap-1.5">
                                                {isBusy ? <span className="text-[8px] font-black uppercase text-stone-600 bg-stone-900 px-2 py-0.5 rounded border border-white/5">On Mission</span> : (
                                                    <div className="flex items-center gap-2">
                                                        <div className="w-16 h-2 bg-stone-950 rounded-full border border-stone-700 p-0.5 overflow-hidden"><div className={`h-full rounded-full ${energy >= energyCostForFloor ? 'bg-blue-500' : 'bg-red-600 animate-pulse'}`} style={{ width: `${energy}%` }} /></div>
                                                        <Zap className={`w-3.5 h-3.5 ${energy >= energyCostForFloor ? 'text-blue-400' : 'text-red-500 animate-pulse'}`} />
                                                    </div>
                                                )}
                                            </div>
                                        </button>
                                    );
                                })
                            )}
                        </div>
                        <div className="p-4 bg-stone-900 border-t border-stone-800 text-center"><p className="text-[9px] text-stone-600 font-black uppercase tracking-widest">Squad Strength relies on matching equipment and attributes.</p></div>
                    </div>
                </div>
            )}

            <ConfirmationModal isOpen={!!showRecallConfirm} title="Abort Mission?" message="Recalling the squad now will forfeit all progress and potential loot. Continue?" confirmLabel="Confirm Recall" cancelLabel="Stay Deployed" isDanger onConfirm={() => { if(showRecallConfirm==='AUTO') actions.abortExpedition(currentExpedition!.id); else actions.retreatFromManualDungeon(); setShowRecallConfirm(null); }} onCancel={() => setShowRecallConfirm(null)} />
        </div>
    );
};

export default DungeonTab;

import { useState, useMemo, useEffect } from 'react';
import { useGame } from '../../../context/GameContext';
import { DUNGEONS } from '../../../data/dungeons';
import { calculatePartyPower, calculateMercenaryPower } from '../../../utils/combatLogic';
// Add LayoutList to lucide-react imports
import { Skull, Timer, Zap, ChevronRight, ChevronLeft, Lock, CheckCircle, Trophy, User, XCircle, Box, AlertCircle, Gamepad2, Ban, Layers, X, Search, Sword, LayoutList } from 'lucide-react';
import { getAssetUrl, formatDuration } from '../../../utils';
import AssaultNavigator from './AssaultNavigator';
import ConfirmationModal from '../../modals/ConfirmationModal';

const DungeonTab = () => {
    const { state, actions } = useGame();
    const { activeExpeditions, knownMercenaries, dungeonClearCounts, maxFloorReached, activeManualDungeon, showManualDungeonOverlay } = state;

    // View State
    const [view, setView] = useState<'LIST' | 'DETAIL'>('LIST');
    const [selectedDungeonId, setSelectedDungeonId] = useState<string | null>(null);
    const [selectedFloor, setSelectedFloor] = useState(1);
    const [party, setParty] = useState<string[]>([]);
    const [failedMercs, setFailedMercs] = useState<string[]>([]);
    const [lowHpMercs, setLowHpMercs] = useState<string[]>([]);
    const [failedPowerHighlight, setFailedPowerHighlight] = useState(false);
    const [showRecallConfirm, setShowRecallConfirm] = useState<'AUTO' | 'MANUAL' | null>(null);

    // Picker Modal State
    const [isPickerOpen, setIsPickerOpen] = useState(false);

    const selectedDungeon = useMemo(() => 
        DUNGEONS.find(d => d.id === selectedDungeonId) || DUNGEONS[0], 
    [selectedDungeonId]);

    const maxPartySize = selectedDungeon.maxPartySize || 4;
    const isOngoingManual = !!activeManualDungeon && activeManualDungeon.dungeonId === selectedDungeon.id;
    const currentExpedition = activeExpeditions.find(e => e.dungeonId === selectedDungeon.id);
    const hasActiveMission = !!currentExpedition || isOngoingManual;

    const isFloorCleared = useMemo(() => {
        const maxReached = maxFloorReached[selectedDungeon.id] || 1;
        if (selectedFloor < maxReached) return true;
        if (selectedFloor === selectedDungeon.maxFloors && (dungeonClearCounts[selectedDungeon.id] || 0) > 0) return true;
        return false;
    }, [selectedDungeon, selectedFloor, maxFloorReached, dungeonClearCounts]);

    const hiredMercs = useMemo(() => 
        knownMercenaries.filter(m => m.status === 'HIRED' || m.status === 'ON_EXPEDITION'), 
    [knownMercenaries]);

    // Candidates for the picker (Not already in party)
    const availableCandidates = useMemo(() => 
        hiredMercs.filter(m => !party.includes(m.id)),
    [hiredMercs, party]);

    const requiredPowerForFloor = useMemo(() => {
        const base = selectedDungeon.requiredPower;
        return Math.round(base * (1 + (selectedFloor - 1) * 0.25));
    }, [selectedDungeon, selectedFloor]);

    const energyCostForFloor = useMemo(() => {
        const base = selectedDungeon.energyCost;
        return base + (selectedFloor - 1) * 5;
    }, [selectedDungeon, selectedFloor]);

    const handleDungeonSelect = (id: string) => {
        const dungeon = DUNGEONS.find(d => d.id === id);
        if (!dungeon || dungeon.tier > state.stats.tierLevel + 1) {
            actions.showToast("This area is currently inaccessible.");
            return;
        }
        setSelectedDungeonId(id);
        setSelectedFloor(1);
        setParty([]);
        setView('DETAIL');
    };

    const handlePrevFloor = () => setSelectedFloor(prev => Math.max(1, prev - 1));
    const handleNextFloor = () => {
        const maxReached = maxFloorReached[selectedDungeon.id] || 1;
        if (selectedFloor >= selectedDungeon.maxFloors) return;
        if (selectedFloor >= maxReached) {
            actions.showToast("You must clear the current floor to descend deeper.");
            return;
        }
        setSelectedFloor(prev => Math.min(selectedDungeon.maxFloors, prev + 1));
    };

    const toggleMercenary = (mercId: string) => {
        if (party.includes(mercId)) {
            setParty(prev => prev.filter(id => id !== mercId));
        } else if (party.length < maxPartySize) {
            setParty(prev => [...prev, mercId]);
            setIsPickerOpen(false);
        }
    };

    const validateEntry = () => {
        if (party.length === 0) return false;
        const selectedMercs = knownMercenaries.filter(m => party.includes(m.id));

        const lowHpIds = selectedMercs.filter(m => (m.currentHp || 0) < 1).map(m => i.id);
        if (lowHpIds.length > 0) {
            setLowHpMercs(lowHpIds);
            setTimeout(() => setLowHpMercs([]), 2000);
            actions.showToast("Wounded members cannot be deployed.");
            return false;
        }

        const lowEnergyIds = selectedMercs.filter(m => (m.expeditionEnergy || 0) < energyCostForFloor).map(m => m.id);
        if (lowEnergyIds.length > 0) {
            setFailedMercs(lowEnergyIds);
            setTimeout(() => setFailedMercs([]), 2000);
            actions.showToast("Some squad members are too exhausted.");
            return false;
        }

        if (currentPartyPower < requiredPowerForFloor) {
            setFailedPowerHighlight(true);
            setTimeout(() => setFailedPowerHighlight(false), 2000);
            actions.showToast("Party power is insufficient for this floor.");
            return false;
        }
        return true;
    };

    const handleStartAutoExpedition = () => {
        if (!isFloorCleared) { actions.showToast("Manual clear required."); return; }
        if (isOngoingManual) return actions.showToast("Manual assault active.");
        if (!validateEntry()) return;
        actions.startExpedition(selectedDungeon.id, party);
    };

    const handleStartManualAssault = () => {
        if (isOngoingManual) { actions.toggleManualDungeonOverlay(true); return; }
        if (!validateEntry()) return;
        actions.startManualAssault(selectedDungeon.id, party, selectedFloor);
    };

    const currentPartyPower = useMemo(() => {
        const selectedMercs = knownMercenaries.filter(m => party.includes(m.id));
        return calculatePartyPower(selectedMercs);
    }, [party, knownMercenaries]);

    const [timeLeft, setTimeLeft] = useState<string>('');
    useEffect(() => {
        if (!currentExpedition || currentExpedition.status === 'COMPLETED') {
            setTimeLeft(currentExpedition?.status === 'COMPLETED' ? '00:00' : '');
            return;
        }
        const interval = setInterval(() => {
            const diff = currentExpedition.endTime - Date.now();
            if (diff <= 0) setTimeLeft('00:00');
            else setTimeLeft(formatDuration(diff));
        }, 1000);
        return () => clearInterval(interval);
    }, [currentExpedition]);

    // --- RENDER: LIST VIEW ---
    if (view === 'LIST') {
        return (
            <div className="h-full w-full bg-stone-950 flex flex-col p-4 md:p-8 animate-in fade-in duration-500 overflow-hidden">
                <div className="flex justify-between items-end border-b border-stone-800 pb-4 mb-6 shrink-0">
                    <div>
                        <h2 className="text-2xl md:text-4xl font-black text-amber-500 font-serif uppercase tracking-tighter">Tactical Deployment</h2>
                        <p className="text-stone-500 text-[10px] md:text-xs font-bold uppercase tracking-[0.2em] mt-1">Select Engagement Zone</p>
                    </div>
                    <div className="flex items-center gap-2 bg-stone-900 px-3 py-1.5 rounded-lg border border-stone-800 text-[10px] font-mono text-stone-500">
                        <LayoutList className="w-3.5 h-3.5" /> Sector Overview
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar pr-2 space-y-4">
                    {DUNGEONS.map(d => {
                        const isLocked = d.tier > state.stats.tierLevel + 1;
                        const maxReached = maxFloorReached[d.id] || 1;
                        const progressPercent = (maxReached / d.maxFloors) * 100;
                        return (
                            <button key={d.id} onClick={() => handleDungeonSelect(d.id)} className={`w-full group relative flex flex-col md:flex-row items-center gap-4 p-4 md:p-6 rounded-2xl border-2 transition-all overflow-hidden ${isLocked ? 'bg-stone-900 border-stone-800 opacity-50 grayscale' : 'bg-stone-900/40 border-stone-800 hover:border-amber-500 hover:bg-stone-800 shadow-xl active:scale-[0.99]'}`}>
                                <div className="w-20 h-20 md:w-32 md:h-32 bg-stone-950 rounded-xl border-2 border-stone-800 flex items-center justify-center text-4xl md:text-6xl shrink-0 shadow-inner group-hover:scale-105 transition-transform duration-500">
                                    {isLocked ? <Lock className="w-8 h-8 text-stone-700" /> : (d.id.includes('rat') ? '🐀' : d.id.includes('goblin') ? '👺' : d.id.includes('mine') ? '⛏️' : '🏰')}
                                </div>
                                <div className="flex-1 text-center md:text-left min-w-0">
                                    <div className="flex flex-col md:flex-row md:items-center gap-2 mb-1">
                                        <h3 className="text-lg md:text-2xl font-black text-stone-100 uppercase font-serif tracking-tight">{d.name}</h3>
                                        <span className={`w-fit mx-auto md:mx-0 px-2 py-0.5 rounded font-black text-[8px] md:text-[10px] uppercase border ${isLocked ? 'border-stone-700 text-stone-600' : 'border-amber-600/30 bg-amber-900/20 text-amber-500'}`}>Tier {d.tier}</span>
                                    </div>
                                    <p className="text-stone-500 text-[10px] md:text-sm line-clamp-2 italic mb-3">"{d.description}"</p>
                                    <div className="flex wrap justify-center md:justify-start gap-4">
                                        <div className="flex items-center gap-2"><Layers className="w-3.5 h-3.5 text-stone-600" /><span className="text-[10px] md:text-xs font-black text-stone-400 uppercase">Progression: <span className="text-amber-500">{maxReached}/{d.maxFloors} Floors</span></span></div>
                                        <div className="flex items-center gap-2"><Skull className="w-3.5 h-3.5 text-stone-600" /><span className="text-[10px] md:text-xs font-black text-stone-400 uppercase">Threat: <span className="text-red-500">POW {d.requiredPower}</span></span></div>
                                    </div>
                                    <div className="mt-3 w-full h-1.5 bg-stone-950 rounded-full overflow-hidden border border-stone-800 shadow-inner"><div className="h-full bg-gradient-to-r from-amber-900 to-amber-500 transition-all duration-1000" style={{ width: `${progressPercent}%` }}></div></div>
                                </div>
                                <div className="absolute top-4 right-4 md:relative md:top-0 md:right-0">
                                    {isLocked ? <Lock className="w-6 h-6 text-stone-800" /> : <ChevronRight className="w-6 h-6 text-stone-700 group-hover:text-amber-500 group-hover:translate-x-1 transition-all" />}
                                </div>
                            </button>
                        );
                    })}
                </div>
            </div>
        );
    }

    // --- RENDER: DETAIL VIEW ---
    return (
        <div className="h-full w-full flex flex-col sm:flex-row bg-stone-950 text-stone-200 overflow-hidden font-sans relative">
            {(!!activeManualDungeon && showManualDungeonOverlay) && <AssaultNavigator />}

            {/* Left Info Section */}
            <div className="w-full sm:w-[40%] h-[35%] sm:h-full flex flex-col border-b sm:border-b-0 sm:border-r border-stone-800 bg-stone-900/50 relative overflow-hidden shrink-0 min-h-0">
                <div className="absolute inset-0 opacity-10 pointer-events-none"><img src={getAssetUrl('dungeon_bg.png')} className="w-full h-full object-cover grayscale" /></div>
                <div className="flex-1 flex flex-col items-center z-10 min-h-0">
                    <button onClick={() => setView('LIST')} className="absolute top-3 left-3 z-30 flex items-center gap-1.5 px-3 py-1.5 bg-stone-800 hover:bg-stone-700 rounded-lg border border-stone-700 text-stone-400 text-[10px] font-black uppercase transition-all shadow-xl active:scale-95"><ChevronLeft className="w-3.5 h-3.5" /> Back</button>
                    <div className="relative flex flex-col items-center pt-8 sm:pt-14 shrink-0 w-full">
                        <div className="h-12 sm:h-20 flex flex-col items-center justify-center text-center px-10 mb-1 sm:mb-2">
                            <h1 className="text-lg sm:text-2xl lg:text-3xl font-black text-white font-serif tracking-tighter uppercase leading-none">{selectedDungeon.name}</h1>
                            <div className="mt-1 px-3 py-0.5 rounded-full bg-amber-900/30 border border-amber-600/30 text-amber-500 text-[8px] font-black uppercase tracking-widest">Tier {selectedDungeon.tier}</div>
                        </div>
                        <div className="relative w-full flex items-center justify-center h-20 sm:h-44 mb-2 sm:mb-6">
                            <button onClick={handlePrevFloor} className={`absolute left-4 z-30 p-2 sm:p-5 rounded-full border transition-all active:scale-90 ${selectedFloor > 1 ? 'bg-stone-800 hover:bg-amber-600 border-stone-700 text-white' : 'bg-stone-900 border-stone-850 text-stone-800 opacity-20 cursor-not-allowed'}`}><ChevronLeft className="w-5 h-5 sm:w-10 sm:h-10" /></button>
                            <div className="relative group animate-in fade-in zoom-in duration-300">
                                <div className="w-16 h-16 sm:w-36 lg:w-44 sm:h-36 lg:h-44 bg-stone-900 rounded-2xl sm:rounded-[2rem] border-2 sm:border-4 border-stone-700 flex flex-col items-center justify-center relative shadow-2xl ring-4 ring-white/5">
                                     <div className="text-[8px] sm:text-[10px] font-black text-stone-600 uppercase">Floor</div>
                                     <div className="text-3xl sm:text-7xl lg:text-8xl font-black text-white font-mono leading-none">{selectedFloor}</div>
                                </div>
                                {selectedFloor === selectedDungeon.maxFloors && <div className="absolute -top-2 -right-2 px-2 py-0.5 bg-red-600 border border-red-400 rounded-lg text-white font-black text-[8px] sm:text-[10px] shadow-2xl rotate-12 z-40">BOSS</div>}
                            </div>
                            <button onClick={handleNextFloor} className={`absolute right-4 z-30 p-2 sm:p-5 rounded-full border transition-all active:scale-90 ${selectedFloor < selectedDungeon.maxFloors ? 'bg-stone-800 hover:bg-amber-600 border-stone-700 text-white' : 'bg-stone-900 border-stone-850 text-stone-800 opacity-20 cursor-not-allowed'}`}><ChevronRight className="w-5 h-5 sm:w-10 sm:h-10" /></button>
                        </div>
                    </div>
                    <div className="flex-1 overflow-y-auto custom-scrollbar p-1 sm:p-8 pt-0 z-10 flex flex-col items-center min-h-0 w-full">
                        <div className="bg-stone-950/40 p-2 sm:p-4 rounded-xl border border-stone-800/50 w-full max-w-[280px]">
                            <div className="flex items-center justify-center gap-1.5 mb-2"><Box className="w-3 h-3 text-stone-600" /><h4 className="text-[9px] sm:text-xs font-black text-stone-500 uppercase tracking-widest">Potential Rewards</h4></div>
                            <div className="flex wrap justify-center gap-2 sm:gap-3">
                                {selectedDungeon.rewards.map((reward, ridx) => (
                                    <div key={`${reward.itemId}-${ridx}`} className="w-8 h-8 md:w-12 md:h-12 bg-stone-900 border border-stone-800 rounded-lg flex items-center justify-center shadow-inner group">
                                        <img src={getAssetUrl(`${reward.itemId}.png`)} className="w-6 h-6 md:w-8 md:h-8 object-contain" onError={e=>e.currentTarget.style.display='none'} />
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Right Squad & Action Section */}
            <div className="flex-1 flex flex-col bg-stone-925 relative overflow-hidden min-h-0 min-w-0">
                {hasActiveMission ? (
                    <div className="flex-1 flex flex-col items-center justify-center p-6 sm:p-12 text-center animate-in fade-in duration-700">
                        <Trophy className={`w-12 h-12 sm:w-28 mb-8 ${currentExpedition?.status === 'COMPLETED' ? 'text-emerald-500 animate-bounce' : 'text-stone-800 opacity-30'}`} />
                        <h2 className="text-lg sm:text-4xl font-black text-stone-100 mb-2 uppercase tracking-tighter font-serif italic">Mission Underway</h2>
                        <div className="bg-stone-900/80 border-2 border-stone-800 px-10 py-5 rounded-2xl font-mono text-2xl sm:text-4xl font-black text-amber-50 shadow-2xl flex items-center gap-3 mb-8"><Timer className="w-8 h-8 animate-pulse text-amber-600" /><span>{timeLeft || '---'}</span></div>
                        <div className="flex gap-3">
                            {currentExpedition?.status === 'COMPLETED' ? (
                                <button onClick={() => actions.claimExpedition(currentExpedition.id)} className="px-10 py-4 bg-emerald-600 hover:bg-emerald-500 text-white font-black rounded-xl shadow-xl flex items-center gap-2 border-b-4 border-emerald-800 active:scale-95 transition-all uppercase tracking-widest"><CheckCircle className="w-5 h-5" /> Secure Loot</button>
                            ) : (
                                <button onClick={() => setShowRecallConfirm(isOngoingManual ? 'MANUAL' : 'AUTO')} className="px-6 py-3 bg-red-950/30 hover:bg-red-900/50 border border-red-900/50 rounded-xl text-red-500 font-black text-xs uppercase tracking-widest transition-all active:scale-95"><Ban className="w-4 h-4 mr-2 inline" /> Recall Squad</button>
                            )}
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 flex flex-col overflow-hidden">
                        <div className="p-2 sm:p-4 bg-stone-900/80 border-b border-stone-800 grid grid-cols-3 gap-2 sm:gap-4 shrink-0">
                            <div className="bg-stone-950 p-2 sm:p-4 rounded-xl border border-stone-800 flex flex-col items-center justify-center">
                                <span className="text-[8px] sm:text-[10px] text-stone-500 font-black uppercase mb-0.5">Time</span>
                                <div className="text-xs sm:text-xl font-black text-stone-200 font-mono">{selectedDungeon.durationMinutes}m</div>
                            </div>
                            <div className="bg-stone-950 p-2 sm:p-4 rounded-xl border border-stone-800 flex flex-col items-center justify-center">
                                <span className="text-[8px] sm:text-[10px] text-stone-500 font-black uppercase mb-0.5">Energy</span>
                                <div className="text-xs sm:text-xl font-black text-blue-400 font-mono">-{energyCostForFloor}</div>
                            </div>
                            <div className={`bg-stone-950 p-2 sm:p-4 rounded-xl border flex flex-col items-center justify-center transition-all ${failedPowerHighlight ? 'border-red-500 ring-2 ring-red-500/50 animate-shake-hard' : 'border-stone-800'}`}>
                                <span className="text-[8px] sm:text-[10px] text-stone-500 font-black uppercase mb-0.5">Req. Power</span>
                                <div className={`text-xs sm:text-xl font-black font-mono ${currentPartyPower >= requiredPowerForFloor ? 'text-emerald-400' : 'text-red-500'}`}>{currentPartyPower} / {requiredPowerForFloor}</div>
                            </div>
                        </div>

                        <div className="flex-1 flex flex-col items-center justify-center p-4 sm:p-8 min-h-0 overflow-hidden">
                            <div className="w-full max-w-xl space-y-4">
                                <div className="flex justify-between items-end px-2">
                                    <h3 className="text-[10px] sm:text-xs font-black text-stone-500 uppercase tracking-widest">Squad Assembly</h3>
                                    <span className="text-[10px] font-mono text-stone-600">{party.length} / {maxPartySize}</span>
                                </div>
                                <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 sm:gap-4">
                                    {Array.from({ length: 4 }).map((_, idx) => {
                                        const isAvailable = idx < maxPartySize;
                                        const mercId = party[idx];
                                        const merc = knownMercenaries.find(m => m.id === mercId);
                                        const hasError = mercId && (failedMercs.includes(mercId) || lowHpMercs.includes(mercId));

                                        if (!isAvailable) return <div key={idx} className="aspect-square bg-stone-950/60 border-2 border-stone-900 rounded-2xl flex items-center justify-center grayscale"><Ban className="w-8 text-stone-800" /></div>;

                                        return (
                                            <div key={idx} className={`aspect-square bg-stone-900 border-2 rounded-2xl flex items-center justify-center relative shadow-2xl overflow-hidden group hover:bg-stone-850 transition-all ${hasError ? 'border-red-600 animate-shake-hard' : 'border-dashed border-stone-800'}`}>
                                                {!!merc ? (
                                                    <button onClick={() => toggleMercenary(merc.id)} className="w-full h-full flex flex-col items-center justify-center p-2 relative animate-in zoom-in-95">
                                                        <div className="text-4xl sm:text-6xl group-hover:scale-110 transition-transform mb-1">{merc.icon}</div>
                                                        <div className="text-[8px] sm:text-xs font-black text-stone-200 truncate w-full text-center">{merc.name}</div>
                                                        <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity"><XCircle className="w-5 text-red-600" /></div>
                                                        {hasError && <div className="absolute inset-0 bg-red-900/40 backdrop-blur-[1px] flex items-center justify-center"><AlertCircle className="w-10 text-white" /></div>}
                                                    </button>
                                                ) : (
                                                    <button onClick={() => setIsPickerOpen(true)} className="w-full h-full flex flex-col items-center justify-center gap-2 text-stone-700 hover:text-amber-500 hover:bg-stone-850 transition-all">
                                                        <User className="w-10 h-10 opacity-20" />
                                                        <span className="text-[8px] font-black uppercase tracking-tighter">Add Member</span>
                                                    </button>
                                                )}
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        </div>

                        <div className="p-4 sm:p-8 bg-stone-900/50 border-t border-stone-800 shrink-0">
                            <div className="grid grid-cols-2 gap-4 max-w-xl mx-auto">
                                <button onClick={handleStartAutoExpedition} disabled={party.length === 0 || isOngoingManual || !isFloorCleared} className={`flex flex-col items-center justify-center gap-1 py-3 sm:py-5 rounded-xl border-b-4 transition-all shadow-xl ${party.length > 0 && !isOngoingManual && isFloorCleared ? 'bg-indigo-700 hover:bg-indigo-600 border-indigo-900 text-white' : 'bg-stone-800 text-stone-600 border-stone-900 opacity-60'}`}>
                                    <div className="flex items-center gap-2">{!isFloorCleared ? <Lock className="w-4" /> : <Timer className="w-5" />}<span className="font-black uppercase text-xs sm:text-sm">Strategic Deploy</span></div>
                                    <span className="text-[7px] sm:text-[9px] font-bold opacity-60 uppercase">{isFloorCleared ? "Auto Expedition" : "Requires Manual Clear"}</span>
                                </button>
                                <button onClick={handleStartManualAssault} disabled={party.length === 0 && !isOngoingManual} className={`flex flex-col items-center justify-center gap-1 py-3 sm:py-5 rounded-xl border-b-4 transition-all shadow-xl ${party.length > 0 || isOngoingManual ? 'bg-amber-600 hover:bg-amber-500 border-amber-800 text-white' : 'bg-stone-800 text-stone-600 border-stone-900 opacity-60'}`}><div className="flex items-center gap-2"><Gamepad2 className="w-5" /><span className="font-black uppercase text-xs sm:text-sm">{isOngoingManual ? 'Resume' : 'Direct Assault'}</span></div><span className="text-[7px] sm:text-[9px] font-bold opacity-60 uppercase">Manual Exploration</span></button>
                            </div>
                        </div>
                    </div>
                )}
            </div>

            {/* UNIT PICKER MODAL */}
            {isPickerOpen && (
                <div className="fixed inset-0 z-[1000] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-in fade-in duration-200">
                    <div className="bg-stone-900 border-2 border-stone-700 rounded-3xl w-full max-w-2xl max-h-[80vh] flex flex-col shadow-2xl overflow-hidden animate-in zoom-in-95">
                        <div className="p-4 border-b border-stone-800 bg-stone-850 flex justify-between items-center">
                            <div className="flex items-center gap-3">
                                <div className="bg-amber-900/30 p-2 rounded-xl border border-amber-700/50"><User className="w-5 h-5 text-amber-500" /></div>
                                <div>
                                    <h3 className="text-lg font-black text-stone-100 font-serif uppercase">Select Squad Member</h3>
                                    <p className="text-[10px] text-stone-500 font-black uppercase">Assign available units to the squad</p>
                                </div>
                            </div>
                            <button onClick={() => setIsPickerOpen(false)} className="p-2 hover:bg-stone-800 rounded-full text-stone-500 transition-colors"><X className="w-6 h-6" /></button>
                        </div>
                        <div className="flex-1 overflow-y-auto p-4 space-y-2 custom-scrollbar bg-stone-950/40">
                            {availableCandidates.length === 0 ? (
                                <div className="flex flex-col items-center justify-center py-20 opacity-20"><Search className="w-16 h-16 mb-4" /><p className="font-black uppercase text-sm tracking-widest">No candidates available</p></div>
                            ) : (
                                availableCandidates.map(merc => {
                                    const isBusy = activeExpeditions.some(e => e.partyIds.includes(merc.id)) || (activeManualDungeon?.partyIds.includes(merc.id));
                                    const power = calculateMercenaryPower(merc);
                                    const energy = merc.expeditionEnergy || 0;
                                    return (
                                        <button key={merc.id} onClick={() => !isBusy && toggleMercenary(merc.id)} disabled={isBusy} className={`w-full flex items-center justify-between p-3 rounded-xl border transition-all ${isBusy ? 'bg-stone-950 border-stone-900 opacity-40 grayscale cursor-not-allowed' : 'bg-stone-800 border-stone-700 hover:border-amber-500 hover:bg-stone-750 shadow-lg'}`}>
                                            <div className="flex items-center gap-4 min-w-0">
                                                <div className="text-4xl">{merc.icon}</div>
                                                <div className="text-left">
                                                    <div className="font-black text-stone-100 text-sm md:text-base truncate">{merc.name}</div>
                                                    <div className="flex items-center gap-2 mt-0.5">
                                                        <span className="text-[9px] font-black text-stone-500 uppercase tracking-widest">{merc.job} • Lv.{merc.level}</span>
                                                        <div className="flex items-center gap-1 text-[10px] text-amber-500 font-mono font-bold border-l border-stone-700 pl-2"><Sword className="w-3 h-3" /> {power}</div>
                                                    </div>
                                                </div>
                                            </div>
                                            <div className="flex flex-col items-end gap-1.5">
                                                {isBusy ? <span className="text-[8px] font-black uppercase text-stone-600 bg-stone-900 px-2 py-0.5 rounded border border-white/5">On Mission</span> : (
                                                    <div className="flex items-center gap-2">
                                                        <div className="w-16 h-2 bg-stone-950 rounded-full border border-stone-700 p-0.5 overflow-hidden"><div className={`h-full rounded-full ${energy >= energyCostForFloor ? 'bg-blue-500' : 'bg-red-600 animate-pulse'}`} style={{ width: `${energy}%` }} /></div>
                                                        <Zap className={`w-3.5 h-3.5 ${energy >= energyCostForFloor ? 'text-blue-400' : 'text-red-500 animate-pulse'}`} />
                                                    </div>
                                                )}
                                            </div>
                                        </button>
                                    );
                                })
                            )}
                        </div>
                        <div className="p-4 bg-stone-900 border-t border-stone-800 text-center"><p className="text-[9px] text-stone-600 font-black uppercase tracking-widest">Squad Strength relies on matching equipment and attributes.</p></div>
                    </div>
                </div>
            )}

            <ConfirmationModal isOpen={!!showRecallConfirm} title="Abort Mission?" message="Recalling the squad now will forfeit all progress and potential loot. Continue?" confirmLabel="Confirm Recall" cancelLabel="Stay Deployed" isDanger onConfirm={() => { if(showRecallConfirm==='AUTO') actions.abortExpedition(currentExpedition!.id); else actions.retreatFromManualDungeon(); setShowRecallConfirm(null); }} onCancel={() => setShowRecallConfirm(null)} />
        </div>
    );
};

export default DungeonTab;

import { useState, useMemo, useEffect } from 'react';
import { useGame } from '../../../context/GameContext';
import { DUNGEONS } from '../../../data/dungeons';
import { calculatePartyPower, calculateMercenaryPower } from '../../../utils/combatLogic';
import { Skull, Timer, Zap, ChevronRight, ChevronLeft, Lock, CheckCircle, Trophy, User, XCircle, Box, AlertCircle, Gamepad2, Ban, Layers, X, Search, Sword, LayoutList } from 'lucide-react';
import { getAssetUrl, formatDuration } from '../../../utils';
import AssaultNavigator from './AssaultNavigator';
import ConfirmationModal from '../../modals/ConfirmationModal';

const DungeonTab = () => {
    const { state, actions } = useGame();
    const { activeExpeditions, knownMercenaries, dungeonClearCounts, maxFloorReached, activeManualDungeon, showManualDungeonOverlay } = state;

    // View State
    const [view, setView] = useState<'LIST' | 'DETAIL'>('LIST');
    const [selectedDungeonId, setSelectedDungeonId] = useState<string | null>(null);
    const [selectedFloor, setSelectedFloor] = useState(1);
    const [party, setParty] = useState<string[]>([]);
    const [failedMercs, setFailedMercs] = useState<string[]>([]);
    const [lowHpMercs, setLowHpMercs] = useState<string[]>([]);
    const [failedPowerHighlight, setFailedPowerHighlight] = useState(false);
    const [showRecallConfirm, setShowRecallConfirm] = useState<'AUTO' | 'MANUAL' | null>(null);

    // Picker Modal State
    const [isPickerOpen, setIsPickerOpen] = useState(false);

    const selectedDungeon = useMemo(() => 
        DUNGEONS.find(d => d.id === selectedDungeonId) || DUNGEONS[0], 
    [selectedDungeonId]);

    const maxPartySize = selectedDungeon.maxPartySize || 4;
    const isOngoingManual = !!activeManualDungeon && activeManualDungeon.dungeonId === selectedDungeon.id;
    const currentExpedition = activeExpeditions.find(e => e.dungeonId === selectedDungeon.id);
    const hasActiveMission = !!currentExpedition || isOngoingManual;

    const isFloorCleared = useMemo(() => {
        const maxReached = maxFloorReached[selectedDungeon.id] || 1;
        if (selectedFloor < maxReached) return true;
        if (selectedFloor === selectedDungeon.maxFloors && (dungeonClearCounts[selectedDungeon.id] || 0) > 0) return true;
        return false;
    }, [selectedDungeon, selectedFloor, maxFloorReached, dungeonClearCounts]);

    const hiredMercs = useMemo(() => 
        knownMercenaries.filter(m => m.status === 'HIRED' || m.status === 'ON_EXPEDITION' || m.status === 'INJURED'), 
    [knownMercenaries]);

    // Candidates for the picker (Not already in party)
    const availableCandidates = useMemo(() => 
        hiredMercs.filter(m => !party.includes(m.id)),
    [hiredMercs, party]);

    const requiredPowerForFloor = useMemo(() => {
        const base = selectedDungeon.requiredPower;
        return Math.round(base * (1 + (selectedFloor - 1) * 0.25));
    }, [selectedDungeon, selectedFloor]);

    const energyCostForFloor = useMemo(() => {
        const base = selectedDungeon.energyCost;
        return base + (selectedFloor - 1) * 5;
    }, [selectedDungeon, selectedFloor]);

    const handleDungeonSelect = (id: string) => {
        const dungeon = DUNGEONS.find(d => d.id === id);
        if (!dungeon || dungeon.tier > state.stats.tierLevel + 1) {
            actions.showToast("This area is currently inaccessible.");
            return;
        }
        setSelectedDungeonId(id);
        setSelectedFloor(1);
        setParty([]);
        setView('DETAIL');
    };

    const handlePrevFloor = () => setSelectedFloor(prev => Math.max(1, prev - 1));
    const handleNextFloor = () => {
        const maxReached = maxFloorReached[selectedDungeon.id] || 1;
        if (selectedFloor >= selectedDungeon.maxFloors) return;
        if (selectedFloor >= maxReached) {
            actions.showToast("You must clear the current floor to descend deeper.");
            return;
        }
        setSelectedFloor(prev => Math.min(selectedDungeon.maxFloors, prev + 1));
    };

    const toggleMercenary = (mercId: string) => {
        if (party.includes(mercId)) {
            setParty(prev => prev.filter(id => id !== mercId));
        } else if (party.length < maxPartySize) {
            setParty(prev => [...prev, mercId]);
            setIsPickerOpen(false);
        }
    };

    const validateEntry = () => {
        if (party.length === 0) return false;
        const selectedMercs = knownMercenaries.filter(m => party.includes(m.id));

        const lowHpIds = selectedMercs.filter(m => (m.currentHp || 0) < 1).map(m => m.id);
        if (lowHpIds.length > 0) {
            setLowHpMercs(lowHpIds);
            setTimeout(() => setLowHpMercs([]), 2000);
            actions.showToast("Wounded members cannot be deployed.");
            return false;
        }

        const lowEnergyIds = selectedMercs.filter(m => (m.expeditionEnergy || 0) < energyCostForFloor).map(m => m.id);
        if (lowEnergyIds.length > 0) {
            setFailedMercs(lowEnergyIds);
            setTimeout(() => setFailedMercs([]), 2000);
            actions.showToast("Some squad members are too exhausted.");
            return false;
        }

        if (currentPartyPower < requiredPowerForFloor) {
            setFailedPowerHighlight(true);
            setTimeout(() => setFailedPowerHighlight(false), 2000);
            actions.showToast("Party power is insufficient for this floor.");
            return false;
        }
        return true;
    };

    const handleStartAutoExpedition = () => {
        if (!isFloorCleared) { actions.showToast("Manual clear required."); return; }
        if (isOngoingManual) return actions.showToast("Manual assault active.");
        if (!validateEntry()) return;
        actions.startExpedition(selectedDungeon.id, party);
    };

    const handleStartManualAssault = () => {
        if (isOngoingManual) { actions.toggleManualDungeonOverlay(true); return; }
        if (!validateEntry()) return;
        actions.startManualAssault(selectedDungeon.id, party, selectedFloor);
    };

    const currentPartyPower = useMemo(() => {
        const selectedMercs = knownMercenaries.filter(m => party.includes(m.id));
        return calculatePartyPower(selectedMercs);
    }, [party, knownMercenaries]);

    const [timeLeft, setTimeLeft] = useState<string>('');
    useEffect(() => {
        if (!currentExpedition || currentExpedition.status === 'COMPLETED') {
            setTimeLeft(currentExpedition?.status === 'COMPLETED' ? '00:00' : '');
            return;
        }
        const interval = setInterval(() => {
            const diff = currentExpedition.endTime - Date.now();
            if (diff <= 0) setTimeLeft('00:00');
            else setTimeLeft(formatDuration(diff));
        }, 1000);
        return () => clearInterval(interval);
    }, [currentExpedition]);

    // --- RENDER: LIST VIEW ---
    if (view === 'LIST') {
        return (
            <div className="h-full w-full bg-stone-950 flex flex-col p-4 md:p-8 animate-in fade-in duration-500 overflow-hidden">
                <div className="flex justify-between items-end border-b border-stone-800 pb-4 mb-6 shrink-0">
                    <div>
                        <h2 className="text-2xl md:text-4xl font-black text-amber-500 font-serif uppercase tracking-tighter">Tactical Deployment</h2>
                        <p className="text-stone-500 text-[10px] md:text-xs font-bold uppercase tracking-[0.2em] mt-1">Select Engagement Zone</p>
                    </div>
                    <div className="flex items-center gap-2 bg-stone-900 px-3 py-1.5 rounded-lg border border-stone-800 text-[10px] font-mono text-stone-500">
                        <LayoutList className="w-3.5 h-3.5" /> Sector Overview
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar pr-2 space-y-4">
                    {DUNGEONS.map(d => {
                        const isLocked = d.tier > state.stats.tierLevel + 1;
                        const maxReached = maxFloorReached[d.id] || 1;
                        const progressPercent = (maxReached / d.maxFloors) * 100;
                        return (
                            <button key={d.id} onClick={() => handleDungeonSelect(d.id)} className={`w-full group relative flex flex-col md:flex-row items-center gap-4 p-4 md:p-6 rounded-2xl border-2 transition-all overflow-hidden ${isLocked ? 'bg-stone-900 border-stone-800 opacity-50 grayscale' : 'bg-stone-900/40 border-stone-800 hover:border-amber-500 hover:bg-stone-800 shadow-xl active:scale-[0.99]'}`}>
                                <div className="w-20 h-20 md:w-32 md:h-32 bg-stone-950 rounded-xl border-2 border-stone-800 flex items-center justify-center text-4xl md:text-6xl shrink-0 shadow-inner group-hover:scale-105 transition-transform duration-500">
                                    {isLocked ? <Lock className="w-8 h-8 text-stone-700" /> : (d.id.includes('rat') ? '🐀' : d.id.includes('goblin') ? '👺' : d.id.includes('mine') ? '⛏️' : '🏰')}
                                </div>
                                <div className="flex-1 text-center md:text-left min-w-0">
                                    <div className="flex flex-col md:flex-row md:items-center gap-2 mb-1">
                                        <h3 className="text-lg md:text-2xl font-black text-stone-100 uppercase font-serif tracking-tight">{d.name}</h3>
                                        <span className={`w-fit mx-auto md:mx-0 px-2 py-0.5 rounded font-black text-[8px] md:text-[10px] uppercase border ${isLocked ? 'border-stone-700 text-stone-600' : 'border-amber-600/30 bg-amber-900/20 text-amber-500'}`}>Tier {d.tier}</span>
                                    </div>
                                    <p className="text-stone-500 text-[10px] md:text-sm line-clamp-2 italic mb-3">"{d.description}"</p>
                                    <div className="flex flex-wrap justify-center md:justify-start gap-4">
                                        <div className="flex items-center gap-2"><Layers className="w-3.5 h-3.5 text-stone-600" /><span className="text-[10px] md:text-xs font-black text-stone-400 uppercase">Progression: <span className="text-amber-500">{maxReached}/{d.maxFloors} Floors</span></span></div>
                                        <div className="flex items-center gap-2"><Skull className="w-3.5 h-3.5 text-stone-600" /><span className="text-[10px] md:text-xs font-black text-stone-400 uppercase">Threat: <span className="text-red-500">POW {d.requiredPower}</span></span></div>
                                    </div>
                                    <div className="mt-3 w-full h-1.5 bg-stone-950 rounded-full overflow-hidden border border-stone-800 shadow-inner"><div className="h-full bg-gradient-to-r from-amber-900 to-amber-500 transition-all duration-1000" style={{ width: `${progressPercent}%` }}></div></div>
                                </div>
                                <div className="absolute top-4 right-4 md:relative md:top-0 md:right-0">
                                    {isLocked ? <Lock className="w-6 h-6 text-stone-800" /> : <ChevronRight className="w-6 h-6 text-stone-700 group-hover:text-amber-500 group-hover:translate-x-1 transition-all" />}
                                </div>
                            </button>
                        );
                    })}
                </div>
            </div>
        );
    }

    // --- RENDER: DETAIL VIEW ---
    return (
        <div className="h-full w-full flex flex-col sm:flex-row bg-stone-950 text-stone-200 overflow-hidden font-sans relative">
            {(!!activeManualDungeon && showManualDungeonOverlay) && <AssaultNavigator />}

            {/* Left Info Section */}
            <div className="w-full sm:w-[40%] h-[35%] sm:h-full flex flex-col border-b sm:border-b-0 sm:border-r border-stone-800 bg-stone-900/50 relative overflow-hidden shrink-0 min-h-0">
                <div className="absolute inset-0 opacity-10 pointer-events-none"><img src={getAssetUrl('dungeon_bg.png')} className="w-full h-full object-cover grayscale" /></div>
                <div className="flex-1 flex flex-col items-center z-10 min-h-0">
                    <button onClick={() => setView('LIST')} className="absolute top-3 left-3 z-30 flex items-center gap-1.5 px-3 py-1.5 bg-stone-800 hover:bg-stone-700 rounded-lg border border-stone-700 text-stone-400 text-[10px] font-black uppercase transition-all shadow-xl active:scale-95"><ChevronLeft className="w-3.5 h-3.5" /> Back</button>
                    <div className="relative flex flex-col items-center pt-8 sm:pt-14 shrink-0 w-full">
                        <div className="h-12 sm:h-20 flex flex-col items-center justify-center text-center px-10 mb-1 sm:mb-2">
                            <h1 className="text-lg sm:text-2xl lg:text-3xl font-black text-white font-serif tracking-tighter uppercase leading-none">{selectedDungeon.name}</h1>
                            <div className="mt-1 px-3 py-0.5 rounded-full bg-amber-900/30 border border-amber-600/30 text-amber-500 text-[8px] font-black uppercase tracking-widest">Tier {selectedDungeon.tier}</div>
                        </div>
                        <div className="relative w-full flex items-center justify-center h-20 sm:h-44 mb-2 sm:mb-6">
                            <button onClick={handlePrevFloor} className={`absolute left-4 z-30 p-2 sm:p-5 rounded-full border transition-all active:scale-90 ${selectedFloor > 1 ? 'bg-stone-800 hover:bg-amber-600 border-stone-700 text-white' : 'bg-stone-900 border-stone-850 text-stone-800 opacity-20 cursor-not-allowed'}`}><ChevronLeft className="w-5 h-5 sm:w-10 sm:h-10" /></button>
                            <div className="relative group animate-in fade-in zoom-in duration-300">
                                <div className="w-16 h-16 sm:w-36 lg:w-44 sm:h-36 lg:h-44 bg-stone-900 rounded-2xl sm:rounded-[2rem] border-2 sm:border-4 border-stone-700 flex flex-col items-center justify-center relative shadow-2xl ring-4 ring-white/5">
                                     <div className="text-[8px] sm:text-[10px] font-black text-stone-600 uppercase">Floor</div>
                                     <div className="text-3xl sm:text-7xl lg:text-8xl font-black text-white font-mono leading-none">{selectedFloor}</div>
                                </div>
                                {selectedFloor === selectedDungeon.maxFloors && <div className="absolute -top-2 -right-2 px-2 py-0.5 bg-red-600 border border-red-400 rounded-lg text-white font-black text-[8px] sm:text-[10px] shadow-2xl rotate-12 z-40">BOSS</div>}
                            </div>
                            <button onClick={handleNextFloor} className={`absolute right-4 z-30 p-2 sm:p-5 rounded-full border transition-all active:scale-90 ${selectedFloor < selectedDungeon.maxFloors ? 'bg-stone-800 hover:bg-amber-600 border-stone-700 text-white' : 'bg-stone-900 border-stone-850 text-stone-800 opacity-20 cursor-not-allowed'}`}><ChevronRight className="w-5 h-5 sm:w-10 sm:h-10" /></button>
                        </div>
                    </div>
                    <div className="flex-1 overflow-y-auto custom-scrollbar p-1 sm:p-8 pt-0 z-10 flex flex-col items-center min-h-0 w-full">
                        <div className="bg-stone-950/40 p-2 sm:p-4 rounded-xl border border-stone-800/50 w-full max-w-[280px]">
                            <div className="flex items-center justify-center gap-1.5 mb-2"><Box className="w-3 h-3 text-stone-600" /><h4 className="text-[9px] sm:text-xs font-black text-stone-500 uppercase tracking-widest">Potential Rewards</h4></div>
                            <div className="flex wrap justify-center gap-2 sm:gap-3">
                                {selectedDungeon.rewards.map((reward, ridx) => (
                                    <div key={`${reward.itemId}-${ridx}`} className="w-8 h-8 md:w-12 md:h-12 bg-stone-900 border border-stone-800 rounded-lg flex items-center justify-center shadow-inner group">
                                        <img src={getAssetUrl(`${reward.itemId}.png`)} className="w-6 h-6 md:w-8 md:h-8 object-contain" onError={e=>e.currentTarget.style.display='none'} />
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Right Squad & Action Section */}
            <div className="flex-1 flex flex-col bg-stone-925 relative overflow-hidden min-h-0 min-w-0">
                {hasActiveMission ? (
                    <div className="flex-1 flex flex-col items-center justify-center p-6 sm:p-12 text-center animate-in fade-in duration-700">
                        <Trophy className={`w-12 h-12 sm:w-28 mb-8 ${currentExpedition?.status === 'COMPLETED' ? 'text-emerald-500 animate-bounce' : 'text-stone-800 opacity-30'}`} />
                        <h2 className="text-lg sm:text-4xl font-black text-stone-100 mb-2 uppercase tracking-tighter font-serif italic">Mission Underway</h2>
                        <div className="bg-stone-900/80 border-2 border-stone-800 px-10 py-5 rounded-2xl font-mono text-2xl sm:text-4xl font-black text-amber-50 shadow-2xl flex items-center gap-3 mb-8"><Timer className="w-8 h-8 animate-pulse text-amber-600" /><span>{timeLeft || '---'}</span></div>
                        <div className="flex gap-3">
                            {currentExpedition?.status === 'COMPLETED' ? (
                                <button onClick={() => actions.claimExpedition(currentExpedition.id)} className="px-10 py-4 bg-emerald-600 hover:bg-emerald-500 text-white font-black rounded-xl shadow-xl flex items-center gap-2 border-b-4 border-emerald-800 active:scale-95 transition-all uppercase tracking-widest"><CheckCircle className="w-5 h-5" /> Secure Loot</button>
                            ) : (
                                <button onClick={() => setShowRecallConfirm(isOngoingManual ? 'MANUAL' : 'AUTO')} className="px-6 py-3 bg-red-950/30 hover:bg-red-900/50 border border-red-900/50 rounded-xl text-red-500 font-black text-xs uppercase tracking-widest transition-all active:scale-95"><Ban className="w-4 h-4 mr-2 inline" /> Recall Squad</button>
                            )}
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 flex flex-col overflow-hidden">
                        <div className="p-2 sm:p-4 bg-stone-900/80 border-b border-stone-800 grid grid-cols-3 gap-2 sm:gap-4 shrink-0">
                            <div className="bg-stone-950 p-2 sm:p-4 rounded-xl border border-stone-800 flex flex-col items-center justify-center">
                                <span className="text-[8px] sm:text-[10px] text-stone-500 font-black uppercase mb-0.5">Time</span>
                                <div className="text-xs sm:text-xl font-black text-stone-200 font-mono">{selectedDungeon.durationMinutes}m</div>
                            </div>
                            <div className="bg-stone-950 p-2 sm:p-4 rounded-xl border border-stone-800 flex flex-col items-center justify-center">
                                <span className="text-[8px] sm:text-[10px] text-stone-500 font-black uppercase mb-0.5">Energy</span>
                                <div className="text-xs sm:text-xl font-black text-blue-400 font-mono">-{energyCostForFloor}</div>
                            </div>
                            <div className={`bg-stone-950 p-2 sm:p-4 rounded-xl border flex flex-col items-center justify-center transition-all ${failedPowerHighlight ? 'border-red-500 ring-2 ring-red-500/50 animate-shake-hard' : 'border-stone-800'}`}>
                                <span className="text-[8px] sm:text-[10px] text-stone-500 font-black uppercase mb-0.5">Req. Power</span>
                                <div className={`text-xs sm:text-xl font-black font-mono ${currentPartyPower >= requiredPowerForFloor ? 'text-emerald-400' : 'text-red-500'}`}>{currentPartyPower} / {requiredPowerForFloor}</div>
                            </div>
                        </div>

                        <div className="flex-1 flex flex-col items-center justify-center p-4 sm:p-8 min-h-0 overflow-hidden">
                            <div className="w-full max-w-xl space-y-4">
                                <div className="flex justify-between items-end px-2">
                                    <h3 className="text-[10px] sm:text-xs font-black text-stone-500 uppercase tracking-widest">Squad Assembly</h3>
                                    <span className="text-[10px] font-mono text-stone-600">{party.length} / {maxPartySize}</span>
                                </div>
                                {/* Updated grid-cols-4 for mobile and aspect-square for cells */}
                                <div className="grid grid-cols-4 gap-2 md:gap-4">
                                    {Array.from({ length: 4 }).map((_, idx) => {
                                        const isAvailable = idx < maxPartySize;
                                        const mercId = party[idx];
                                        const merc = knownMercenaries.find(m => m.id === mercId);
                                        const hasError = mercId && (failedMercs.includes(mercId) || lowHpMercs.includes(mercId));

                                        if (!isAvailable) return <div key={idx} className="aspect-square bg-stone-950/60 border-2 border-stone-900 rounded-xl md:rounded-2xl flex items-center justify-center grayscale"><Ban className="w-6 md:w-8 text-stone-800" /></div>;

                                        return (
                                            <div key={idx} className={`aspect-square bg-stone-900 border-2 rounded-xl md:rounded-2xl flex items-center justify-center relative shadow-2xl overflow-hidden group hover:bg-stone-850 transition-all ${hasError ? 'border-red-600 animate-shake-hard' : 'border-dashed border-stone-800'}`}>
                                                {!!merc ? (
                                                    <button onClick={() => toggleMercenary(merc.id)} className="w-full h-full flex flex-col items-center justify-center p-1 md:p-2 relative animate-in zoom-in-95">
                                                        <div className="text-3xl md:text-5xl group-hover:scale-110 transition-transform mb-0.5 md:mb-1">{merc.icon}</div>
                                                        <div className="text-[7px] md:text-xs font-black text-stone-200 truncate w-full text-center">{merc.name.split(' ')[0]}</div>
                                                        <div className="absolute top-1 right-1 md:top-2 md:right-2 opacity-0 group-hover:opacity-100 transition-opacity"><XCircle className="w-4 md:w-5 text-red-600" /></div>
                                                        {hasError && <div className="absolute inset-0 bg-red-900/40 backdrop-blur-[1px] flex items-center justify-center"><AlertCircle className="w-6 md:w-8 text-white" /></div>}
                                                    </button>
                                                ) : (
                                                    <button onClick={() => setIsPickerOpen(true)} className="w-full h-full flex flex-col items-center justify-center gap-1 md:gap-2 text-stone-700 hover:text-amber-500 hover:bg-stone-850 transition-all">
                                                        <User className="w-6 h-6 md:w-10 md:h-10 opacity-20" />
                                                        <span className="text-[6px] md:text-[8px] font-black uppercase tracking-tighter">Add</span>
                                                    </button>
                                                )}
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        </div>

                        <div className="p-4 sm:p-8 bg-stone-900/50 border-t border-stone-800 shrink-0">
                            <div className="grid grid-cols-2 gap-4 max-w-xl mx-auto">
                                <button onClick={handleStartAutoExpedition} disabled={party.length === 0 || isOngoingManual || !isFloorCleared} className={`flex flex-col items-center justify-center gap-1 py-3 sm:py-5 rounded-xl border-b-4 transition-all shadow-xl ${party.length > 0 && !isOngoingManual && isFloorCleared ? 'bg-indigo-700 hover:bg-indigo-600 border-indigo-900 text-white' : 'bg-stone-800 text-stone-600 border-stone-900 opacity-60'}`}>
                                    <div className="flex items-center gap-2">{!isFloorCleared ? <Lock className="w-4" /> : <Timer className="w-5" />}<span className="font-black uppercase text-xs sm:text-sm">Strategic Deploy</span></div>
                                    <span className="text-[7px] sm:text-[9px] font-bold opacity-60 uppercase">{isFloorCleared ? "Auto Expedition" : "Requires Manual Clear"}</span>
                                </button>
                                <button onClick={handleStartManualAssault} disabled={party.length === 0 && !isOngoingManual} className={`flex flex-col items-center justify-center gap-1 py-3 sm:py-5 rounded-xl border-b-4 transition-all shadow-xl ${party.length > 0 || isOngoingManual ? 'bg-amber-600 hover:bg-amber-500 border-amber-800 text-white' : 'bg-stone-800 text-stone-600 border-stone-900 opacity-60'}`}><div className="flex items-center gap-2"><Gamepad2 className="w-5" /><span className="font-black uppercase text-xs sm:text-sm">{isOngoingManual ? 'Resume' : 'Direct Assault'}</span></div><span className="text-[7px] sm:text-[9px] font-bold opacity-60 uppercase">Manual Exploration</span></button>
                            </div>
                        </div>
                    </div>
                )}
            </div>

            {/* UNIT PICKER MODAL */}
            {isPickerOpen && (
                <div className="fixed inset-0 z-[1000] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-in fade-in duration-200">
                    <div className="bg-stone-900 border-2 border-stone-700 rounded-3xl w-full max-w-2xl max-h-[80vh] flex flex-col shadow-2xl overflow-hidden animate-in zoom-in-95">
                        <div className="p-4 border-b border-stone-800 bg-stone-850 flex justify-between items-center shrink-0">
                            <div className="flex items-center gap-3">
                                <div className="bg-amber-900/30 p-2 rounded-xl border border-amber-700/50"><User className="w-5 h-5 text-amber-500" /></div>
                                <div>
                                    <h3 className="text-lg font-black text-stone-100 font-serif uppercase">Select Squad Member</h3>
                                    <p className="text-[10px] text-stone-500 font-black uppercase">Assign available units to the squad</p>
                                </div>
                            </div>
                            <button onClick={() => setIsPickerOpen(false)} className="p-2 hover:bg-stone-800 rounded-full text-stone-500 transition-colors"><X className="w-6 h-6" /></button>
                        </div>
                        <div className="flex-1 overflow-y-auto p-4 space-y-2 custom-scrollbar bg-stone-950/40">
                            {availableCandidates.length === 0 ? (
                                <div className="flex flex-col items-center justify-center py-20 opacity-20"><Search className="w-16 h-16 mb-4" /><p className="font-black uppercase text-sm tracking-widest">No candidates available</p></div>
                            ) : (
                                availableCandidates.map(merc => {
                                    const isBusy = activeExpeditions.some(e => e.partyIds.includes(merc.id)) || (activeManualDungeon?.partyIds.includes(merc.id));
                                    const power = calculateMercenaryPower(merc);
                                    const energy = merc.expeditionEnergy || 0;
                                    const hpPer = (merc.currentHp / merc.maxHp) * 100;

                                    return (
                                        <button key={merc.id} onClick={() => !isBusy && toggleMercenary(merc.id)} disabled={isBusy} className={`w-full flex items-center justify-between p-3 rounded-xl border transition-all ${isBusy ? 'bg-stone-950 border-stone-900 opacity-40 grayscale cursor-not-allowed' : 'bg-stone-800 border-stone-700 hover:border-amber-500 hover:bg-stone-750 shadow-lg'}`}>
                                            <div className="flex items-center gap-4 min-w-0">
                                                <div className="text-4xl">{merc.icon}</div>
                                                <div className="text-left">
                                                    <div className="font-black text-stone-100 text-sm md:text-base truncate">{merc.name}</div>
                                                    <div className="flex items-center gap-2 mt-0.5">
                                                        <span className="text-[9px] font-black text-stone-500 uppercase tracking-widest">{merc.job} • Lv.{merc.level}</span>
                                                        <div className="flex items-center gap-1 text-[10px] text-amber-500 font-mono font-bold border-l border-stone-700 pl-2"><Sword className="w-3 h-3" /> {power}</div>
                                                    </div>
                                                </div>
                                            </div>
                                            <div className="flex flex-col items-end gap-1.5">
                                                {isBusy ? <span className="text-[8px] font-black uppercase text-stone-600 bg-stone-900 px-2 py-0.5 rounded border border-white/5">On Mission</span> : (
                                                    <div className="flex flex-col items-end gap-1">
                                                        <div className="flex items-center gap-2">
                                                            <div className="w-16 h-1.5 bg-stone-950 rounded-full border border-stone-700 overflow-hidden"><div className={`h-full rounded-full ${energy >= energyCostForFloor ? 'bg-blue-500' : 'bg-red-600 animate-pulse'}`} style={{ width: `${energy}%` }} /></div>
                                                            <Zap className={`w-3 h-3 ${energy >= energyCostForFloor ? 'text-blue-400' : 'text-red-500 animate-pulse'}`} />
                                                        </div>
                                                        <div className="flex items-center gap-2">
                                                            <div className="w-16 h-1.5 bg-stone-950 rounded-full border border-stone-700 overflow-hidden"><div className={`h-full rounded-full ${hpPer < 30 ? 'bg-red-500 animate-pulse' : 'bg-red-600'}`} style={{ width: `${hpPer}%` }} /></div>
                                                            <span className="text-[8px] font-black text-stone-500 uppercase">HP</span>
                                                        </div>
                                                    </div>
                                                )}
                                            </div>
                                        </button>
                                    );
                                })
                            )}
                        </div>
                        <div className="p-4 bg-stone-900 border-t border-stone-800 text-center"><p className="text-[9px] text-stone-600 font-black uppercase tracking-widest">Squad Strength relies on matching equipment and attributes.</p></div>
                    </div>
                </div>
            )}

            <ConfirmationModal isOpen={!!showRecallConfirm} title="Abort Mission?" message="Recalling the squad now will forfeit all progress and potential loot. Continue?" confirmLabel="Confirm Recall" cancelLabel="Stay Deployed" isDanger onConfirm={() => { if(showRecallConfirm==='AUTO') actions.abortExpedition(currentExpedition!.id); else actions.retreatFromManualDungeon(); setShowRecallConfirm(null); }} onCancel={() => setShowRecallConfirm(null)} />
        </div>
    );
};

export default DungeonTab;

import { useState, useMemo, useEffect } from 'react';
import { useGame } from '../../../context/GameContext';
import { DUNGEONS } from '../../../data/dungeons';
import { calculatePartyPower, calculateMercenaryPower } from '../../../utils/combatLogic';
import { Skull, Timer, Zap, ChevronRight, ChevronLeft, Lock, CheckCircle, Trophy, User, XCircle, Box, AlertCircle, Gamepad2, Ban, Layers, X, Search, Sword, LayoutList } from 'lucide-react';
import { getAssetUrl, formatDuration } from '../../../utils';
import AssaultNavigator from './AssaultNavigator';
import ConfirmationModal from '../../modals/ConfirmationModal';

const DungeonTab = () => {
    const { state, actions } = useGame();
    const { activeExpeditions, knownMercenaries, dungeonClearCounts, maxFloorReached, activeManualDungeon, showManualDungeonOverlay } = state;

    // View State
    const [view, setView] = useState<'LIST' | 'DETAIL'>('LIST');
    const [selectedDungeonId, setSelectedDungeonId] = useState<string | null>(null);
    const [selectedFloor, setSelectedFloor] = useState(1);
    const [party, setParty] = useState<string[]>([]);
    const [failedMercs, setFailedMercs] = useState<string[]>([]);
    const [lowHpMercs, setLowHpMercs] = useState<string[]>([]);
    const [failedPowerHighlight, setFailedPowerHighlight] = useState(false);
    const [showRecallConfirm, setShowRecallConfirm] = useState<'AUTO' | 'MANUAL' | null>(null);

    // Picker Modal State
    const [isPickerOpen, setIsPickerOpen] = useState(false);

    const selectedDungeon = useMemo(() => 
        DUNGEONS.find(d => d.id === selectedDungeonId) || DUNGEONS[0], 
    [selectedDungeonId]);

    const maxPartySize = selectedDungeon.maxPartySize || 4;
    const isOngoingManual = !!activeManualDungeon && activeManualDungeon.dungeonId === selectedDungeon.id;
    const currentExpedition = activeExpeditions.find(e => e.dungeonId === selectedDungeon.id);
    const hasActiveMission = !!currentExpedition || isOngoingManual;

    const isFloorCleared = useMemo(() => {
        const maxReached = maxFloorReached[selectedDungeon.id] || 1;
        if (selectedFloor < maxReached) return true;
        if (selectedFloor === selectedDungeon.maxFloors && (dungeonClearCounts[selectedDungeon.id] || 0) > 0) return true;
        return false;
    }, [selectedDungeon, selectedFloor, maxFloorReached, dungeonClearCounts]);

    const hiredMercs = useMemo(() => 
        knownMercenaries.filter(m => m.status === 'HIRED' || m.status === 'ON_EXPEDITION' || m.status === 'INJURED'), 
    [knownMercenaries]);

    // Candidates for the picker (Not already in party)
    const availableCandidates = useMemo(() => 
        hiredMercs.filter(m => !party.includes(m.id)),
    [hiredMercs, party]);

    const requiredPowerForFloor = useMemo(() => {
        const base = selectedDungeon.requiredPower;
        return Math.round(base * (1 + (selectedFloor - 1) * 0.25));
    }, [selectedDungeon, selectedFloor]);

    const energyCostForFloor = useMemo(() => {
        const base = selectedDungeon.energyCost;
        return base + (selectedFloor - 1) * 5;
    }, [selectedDungeon, selectedFloor]);

    const handleDungeonSelect = (id: string) => {
        const dungeon = DUNGEONS.find(d => d.id === id);
        if (!dungeon || dungeon.tier > state.stats.tierLevel + 1) {
            actions.showToast("This area is currently inaccessible.");
            return;
        }
        setSelectedDungeonId(id);
        setSelectedFloor(1);
        setParty([]);
        setView('DETAIL');
    };

    const handlePrevFloor = () => setSelectedFloor(prev => Math.max(1, prev - 1));
    const handleNextFloor = () => {
        const maxReached = maxFloorReached[selectedDungeon.id] || 1;
        if (selectedFloor >= selectedDungeon.maxFloors) return;
        if (selectedFloor >= maxReached) {
            actions.showToast("You must clear the current floor to descend deeper.");
            return;
        }
        setSelectedFloor(prev => Math.min(selectedDungeon.maxFloors, prev + 1));
    };

    const toggleMercenary = (mercId: string) => {
        if (party.includes(mercId)) {
            setParty(prev => prev.filter(id => id !== mercId));
        } else if (party.length < maxPartySize) {
            setParty(prev => [...prev, mercId]);
            setIsPickerOpen(false);
        }
    };

    const validateEntry = () => {
        if (party.length === 0) return false;
        const selectedMercs = knownMercenaries.filter(m => party.includes(m.id));

        const lowHpIds = selectedMercs.filter(m => (m.currentHp || 0) < 1).map(m => m.id);
        if (lowHpIds.length > 0) {
            setLowHpMercs(lowHpIds);
            setTimeout(() => setLowHpMercs([]), 2000);
            actions.showToast("Wounded members cannot be deployed.");
            return false;
        }

        const lowEnergyIds = selectedMercs.filter(m => (m.expeditionEnergy || 0) < energyCostForFloor).map(m => m.id);
        if (lowEnergyIds.length > 0) {
            setFailedMercs(lowEnergyIds);
            setTimeout(() => setFailedMercs([]), 2000);
            actions.showToast("Some squad members are too exhausted.");
            return false;
        }

        if (currentPartyPower < requiredPowerForFloor) {
            setFailedPowerHighlight(true);
            setTimeout(() => setFailedPowerHighlight(false), 2000);
            actions.showToast("Party power is insufficient for this floor.");
            return false;
        }
        return true;
    };

    const handleStartAutoExpedition = () => {
        if (!isFloorCleared) { actions.showToast("Manual clear required."); return; }
        if (isOngoingManual) return actions.showToast("Manual assault active.");
        if (!validateEntry()) return;
        actions.startExpedition(selectedDungeon.id, party);
    };

    const handleStartManualAssault = () => {
        if (isOngoingManual) { actions.toggleManualDungeonOverlay(true); return; }
        if (!validateEntry()) return;
        actions.startManualAssault(selectedDungeon.id, party, selectedFloor);
    };

    const currentPartyPower = useMemo(() => {
        const selectedMercs = knownMercenaries.filter(m => party.includes(m.id));
        return calculatePartyPower(selectedMercs);
    }, [party, knownMercenaries]);

    const [timeLeft, setTimeLeft] = useState<string>('');
    useEffect(() => {
        if (!currentExpedition || currentExpedition.status === 'COMPLETED') {
            setTimeLeft(currentExpedition?.status === 'COMPLETED' ? '00:00' : '');
            return;
        }
        const interval = setInterval(() => {
            const diff = currentExpedition.endTime - Date.now();
            if (diff <= 0) setTimeLeft('00:00');
            else setTimeLeft(formatDuration(diff));
        }, 1000);
        return () => clearInterval(interval);
    }, [currentExpedition]);

    // --- RENDER: LIST VIEW ---
    if (view === 'LIST') {
        return (
            <div className="h-full w-full bg-stone-950 flex flex-col p-4 md:p-8 animate-in fade-in duration-500 overflow-hidden">
                <div className="flex justify-between items-end border-b border-stone-800 pb-4 mb-6 shrink-0">
                    <div>
                        <h2 className="text-2xl md:text-4xl font-black text-amber-500 font-serif uppercase tracking-tighter">Tactical Deployment</h2>
                        <p className="text-stone-500 text-[10px] md:text-xs font-bold uppercase tracking-[0.2em] mt-1">Select Engagement Zone</p>
                    </div>
                    <div className="flex items-center gap-2 bg-stone-900 px-3 py-1.5 rounded-lg border border-stone-800 text-[10px] font-mono text-stone-500">
                        <LayoutList className="w-3.5 h-3.5" /> Sector Overview
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar pr-2 space-y-4">
                    {DUNGEONS.map(d => {
                        const isLocked = d.tier > state.stats.tierLevel + 1;
                        const maxReached = maxFloorReached[d.id] || 1;
                        const progressPercent = (maxReached / d.maxFloors) * 100;
                        return (
                            <button key={d.id} onClick={() => handleDungeonSelect(d.id)} className={`w-full group relative flex flex-col md:flex-row items-center gap-4 p-4 md:p-6 rounded-2xl border-2 transition-all overflow-hidden ${isLocked ? 'bg-stone-900 border-stone-800 opacity-50 grayscale' : 'bg-stone-900/40 border-stone-800 hover:border-amber-500 hover:bg-stone-800 shadow-xl active:scale-[0.99]'}`}>
                                <div className="w-20 h-20 md:w-32 md:h-32 bg-stone-950 rounded-xl border-2 border-stone-800 flex items-center justify-center text-4xl md:text-6xl shrink-0 shadow-inner group-hover:scale-105 transition-transform duration-500">
                                    {isLocked ? <Lock className="w-8 h-8 text-stone-700" /> : (d.id.includes('rat') ? '🐀' : d.id.includes('goblin') ? '👺' : d.id.includes('mine') ? '⛏️' : '🏰')}
                                </div>
                                <div className="flex-1 text-center md:text-left min-w-0">
                                    <div className="flex flex-col md:flex-row md:items-center gap-2 mb-1">
                                        <h3 className="text-lg md:text-2xl font-black text-stone-100 uppercase font-serif tracking-tight">{d.name}</h3>
                                        <span className={`w-fit mx-auto md:mx-0 px-2 py-0.5 rounded font-black text-[8px] md:text-[10px] uppercase border ${isLocked ? 'border-stone-700 text-stone-600' : 'border-amber-600/30 bg-amber-900/20 text-amber-500'}`}>Tier {d.tier}</span>
                                    </div>
                                    <p className="text-stone-500 text-[10px] md:text-sm line-clamp-2 italic mb-3">"{d.description}"</p>
                                    <div className="flex flex-wrap justify-center md:justify-start gap-4">
                                        <div className="flex items-center gap-2"><Layers className="w-3.5 h-3.5 text-stone-600" /><span className="text-[10px] md:text-xs font-black text-stone-400 uppercase">Progression: <span className="text-amber-500">{maxReached}/{d.maxFloors} Floors</span></span></div>
                                        <div className="flex items-center gap-2"><Skull className="w-3.5 h-3.5 text-stone-600" /><span className="text-[10px] md:text-xs font-black text-stone-400 uppercase">Threat: <span className="text-red-500">POW {d.requiredPower}</span></span></div>
                                    </div>
                                    <div className="mt-3 w-full h-1.5 bg-stone-950 rounded-full overflow-hidden border border-stone-800 shadow-inner"><div className="h-full bg-gradient-to-r from-amber-900 to-amber-500 transition-all duration-1000" style={{ width: `${progressPercent}%` }}></div></div>
                                </div>
                                <div className="absolute top-4 right-4 md:relative md:top-0 md:right-0">
                                    {isLocked ? <Lock className="w-6 h-6 text-stone-800" /> : <ChevronRight className="w-6 h-6 text-stone-700 group-hover:text-amber-500 group-hover:translate-x-1 transition-all" />}
                                </div>
                            </button>
                        );
                    })}
                </div>
            </div>
        );
    }

    // --- RENDER: DETAIL VIEW ---
    return (
        <div className="h-full w-full flex flex-col sm:flex-row bg-stone-950 text-stone-200 overflow-hidden font-sans relative">
            {(!!activeManualDungeon && showManualDungeonOverlay) && <AssaultNavigator />}

            {/* Left Info Section */}
            <div className="w-full sm:w-[40%] h-[35%] sm:h-full flex flex-col border-b sm:border-b-0 sm:border-r border-stone-800 bg-stone-900/50 relative overflow-hidden shrink-0 min-h-0">
                <div className="absolute inset-0 opacity-10 pointer-events-none"><img src={getAssetUrl('dungeon_bg.png')} className="w-full h-full object-cover grayscale" /></div>
                <div className="flex-1 flex flex-col items-center z-10 min-h-0">
                    <button onClick={() => setView('LIST')} className="absolute top-3 left-3 z-30 flex items-center gap-1.5 px-3 py-1.5 bg-stone-800 hover:bg-stone-700 rounded-lg border border-stone-700 text-stone-400 text-[10px] font-black uppercase transition-all shadow-xl active:scale-95"><ChevronLeft className="w-3.5 h-3.5" /> Back</button>
                    <div className="relative flex flex-col items-center pt-8 sm:pt-14 shrink-0 w-full">
                        <div className="h-12 sm:h-20 flex flex-col items-center justify-center text-center px-10 mb-1 sm:mb-2">
                            <h1 className="text-lg sm:text-2xl lg:text-3xl font-black text-white font-serif tracking-tighter uppercase leading-none">{selectedDungeon.name}</h1>
                            <div className="mt-1 px-3 py-0.5 rounded-full bg-amber-900/30 border border-amber-600/30 text-amber-500 text-[8px] font-black uppercase tracking-widest">Tier {selectedDungeon.tier}</div>
                        </div>
                        <div className="relative w-full flex items-center justify-center h-20 sm:h-44 mb-2 sm:mb-6">
                            <button onClick={handlePrevFloor} className={`absolute left-4 z-30 p-2 sm:p-5 rounded-full border transition-all active:scale-90 ${selectedFloor > 1 ? 'bg-stone-800 hover:bg-amber-600 border-stone-700 text-white' : 'bg-stone-900 border-stone-850 text-stone-800 opacity-20 cursor-not-allowed'}`}><ChevronLeft className="w-5 h-5 sm:w-10 sm:h-10" /></button>
                            <div className="relative group animate-in fade-in zoom-in duration-300">
                                <div className="w-16 h-16 sm:w-36 lg:w-44 sm:h-36 lg:h-44 bg-stone-900 rounded-2xl sm:rounded-[2rem] border-2 sm:border-4 border-stone-700 flex flex-col items-center justify-center relative shadow-2xl ring-4 ring-white/5">
                                     <div className="text-[8px] sm:text-[10px] font-black text-stone-600 uppercase">Floor</div>
                                     <div className="text-3xl sm:text-7xl lg:text-8xl font-black text-white font-mono leading-none">{selectedFloor}</div>
                                </div>
                                {selectedFloor === selectedDungeon.maxFloors && <div className="absolute -top-2 -right-2 px-2 py-0.5 bg-red-600 border border-red-400 rounded-lg text-white font-black text-[8px] sm:text-[10px] shadow-2xl rotate-12 z-40">BOSS</div>}
                            </div>
                            <button onClick={handleNextFloor} className={`absolute right-4 z-30 p-2 sm:p-5 rounded-full border transition-all active:scale-90 ${selectedFloor < selectedDungeon.maxFloors ? 'bg-stone-800 hover:bg-amber-600 border-stone-700 text-white' : 'bg-stone-900 border-stone-850 text-stone-800 opacity-20 cursor-not-allowed'}`}><ChevronRight className="w-5 h-5 sm:w-10 sm:h-10" /></button>
                        </div>
                    </div>
                    <div className="flex-1 overflow-y-auto custom-scrollbar p-1 sm:p-8 pt-0 z-10 flex flex-col items-center min-h-0 w-full">
                        <div className="bg-stone-950/40 p-2 sm:p-4 rounded-xl border border-stone-800/50 w-full max-w-[280px]">
                            <div className="flex items-center justify-center gap-1.5 mb-2"><Box className="w-3 h-3 text-stone-600" /><h4 className="text-[9px] sm:text-xs font-black text-stone-500 uppercase tracking-widest">Potential Rewards</h4></div>
                            <div className="flex wrap justify-center gap-2 sm:gap-3">
                                {selectedDungeon.rewards.map((reward, ridx) => (
                                    <div key={`${reward.itemId}-${ridx}`} className="w-8 h-8 md:w-12 md:h-12 bg-stone-900 border border-stone-800 rounded-lg flex items-center justify-center shadow-inner group">
                                        <img src={getAssetUrl(`${reward.itemId}.png`)} className="w-6 h-6 md:w-8 md:h-8 object-contain" onError={e=>e.currentTarget.style.display='none'} />
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Right Squad & Action Section */}
            <div className="flex-1 flex flex-col bg-stone-925 relative overflow-hidden min-h-0 min-w-0">
                {hasActiveMission ? (
                    <div className="flex-1 flex flex-col items-center justify-center p-6 sm:p-12 text-center animate-in fade-in duration-700">
                        <Trophy className={`w-12 h-12 sm:w-28 mb-8 ${currentExpedition?.status === 'COMPLETED' ? 'text-emerald-500 animate-bounce' : 'text-stone-800 opacity-30'}`} />
                        <h2 className="text-lg sm:text-4xl font-black text-stone-100 mb-2 uppercase tracking-tighter font-serif italic">Mission Underway</h2>
                        <div className="bg-stone-900/80 border-2 border-stone-800 px-10 py-5 rounded-2xl font-mono text-2xl sm:text-4xl font-black text-amber-50 shadow-2xl flex items-center gap-3 mb-8"><Timer className="w-8 h-8 animate-pulse text-amber-600" /><span>{timeLeft || '---'}</span></div>
                        <div className="flex gap-3">
                            {currentExpedition?.status === 'COMPLETED' ? (
                                <button onClick={() => actions.claimExpedition(currentExpedition.id)} className="px-10 py-4 bg-emerald-600 hover:bg-emerald-500 text-white font-black rounded-xl shadow-xl flex items-center gap-2 border-b-4 border-emerald-800 active:scale-95 transition-all uppercase tracking-widest"><CheckCircle className="w-5 h-5" /> Secure Loot</button>
                            ) : (
                                <button onClick={() => setShowRecallConfirm(isOngoingManual ? 'MANUAL' : 'AUTO')} className="px-6 py-3 bg-red-950/30 hover:bg-red-900/50 border border-red-900/50 rounded-xl text-red-500 font-black text-xs uppercase tracking-widest transition-all active:scale-95"><Ban className="w-4 h-4 mr-2 inline" /> Recall Squad</button>
                            )}
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 flex flex-col overflow-hidden">
                        {/* Stats Bar */}
                        <div className="p-2 sm:p-4 bg-stone-900/80 border-b border-stone-800 grid grid-cols-3 gap-2 sm:gap-4 shrink-0">
                            <div className="bg-stone-950 p-2 sm:p-4 rounded-xl border border-stone-800 flex flex-col items-center justify-center">
                                <span className="text-[8px] sm:text-[10px] text-stone-500 font-black uppercase mb-0.5">Time</span>
                                <div className="text-xs sm:text-xl font-black text-stone-200 font-mono">{selectedDungeon.durationMinutes}m</div>
                            </div>
                            <div className="bg-stone-950 p-2 sm:p-4 rounded-xl border border-stone-800 flex flex-col items-center justify-center">
                                <span className="text-[8px] sm:text-[10px] text-stone-500 font-black uppercase mb-0.5">Energy</span>
                                <div className="text-xs sm:text-xl font-black text-blue-400 font-mono">-{energyCostForFloor}</div>
                            </div>
                            <div className={`bg-stone-950 p-2 sm:p-4 rounded-xl border flex flex-col items-center justify-center transition-all ${failedPowerHighlight ? 'border-red-500 ring-2 ring-red-500/50 animate-shake-hard' : 'border-stone-800'}`}>
                                <span className="text-[8px] sm:text-[10px] text-stone-500 font-black uppercase mb-0.5">Req. Power</span>
                                <div className={`text-xs sm:text-xl font-black font-mono ${currentPartyPower >= requiredPowerForFloor ? 'text-emerald-400' : 'text-red-500'}`}>{currentPartyPower} / {requiredPowerForFloor}</div>
                            </div>
                        </div>

                        {/* Squad Assembly Area - Optimized for tight height */}
                        <div className="flex-1 flex flex-col items-center justify-center p-4 sm:p-8 min-h-0 overflow-y-auto custom-scrollbar">
                            <div className="w-full max-w-xl h-fit">
                                <div className="flex justify-between items-end px-2 mb-2">
                                    <h3 className="text-[10px] sm:text-xs font-black text-stone-500 uppercase tracking-widest">Squad Assembly</h3>
                                    <span className="text-[10px] font-mono text-stone-600">{party.length} / {maxPartySize}</span>
                                </div>
                                <div className="grid grid-cols-4 gap-2 md:gap-4">
                                    {Array.from({ length: 4 }).map((_, idx) => {
                                        const isAvailable = idx < maxPartySize;
                                        const mercId = party[idx];
                                        const merc = knownMercenaries.find(m => m.id === mercId);
                                        const hasError = mercId && (failedMercs.includes(mercId) || lowHpMercs.includes(mercId));

                                        if (!isAvailable) return <div key={idx} className="aspect-square bg-stone-950/60 border-2 border-stone-900 rounded-xl md:rounded-2xl flex items-center justify-center grayscale"><Ban className="w-6 md:w-8 text-stone-800" /></div>;

                                        return (
                                            <div key={idx} className={`aspect-square bg-stone-900 border-2 rounded-xl md:rounded-2xl flex items-center justify-center relative shadow-2xl overflow-hidden group hover:bg-stone-850 transition-all ${hasError ? 'border-red-600 animate-shake-hard' : 'border-dashed border-stone-800'}`}>
                                                {!!merc ? (
                                                    <button onClick={() => toggleMercenary(merc.id)} className="w-full h-full flex flex-col items-center justify-center p-1 md:p-2 relative animate-in zoom-in-95">
                                                        <div className="text-3xl md:text-5xl group-hover:scale-110 transition-transform mb-0.5 md:mb-1">{merc.icon}</div>
                                                        <div className="text-[7px] md:text-xs font-black text-stone-200 truncate w-full text-center">{merc.name.split(' ')[0]}</div>
                                                        <div className="absolute top-1 right-1 md:top-2 md:right-2 opacity-0 group-hover:opacity-100 transition-opacity"><XCircle className="w-4 md:w-5 text-red-600" /></div>
                                                        {hasError && <div className="absolute inset-0 bg-red-900/40 backdrop-blur-[1px] flex items-center justify-center"><AlertCircle className="w-6 md:w-8 text-white" /></div>}
                                                    </button>
                                                ) : (
                                                    <button onClick={() => setIsPickerOpen(true)} className="w-full h-full flex flex-col items-center justify-center gap-1 md:gap-2 text-stone-700 hover:text-amber-500 hover:bg-stone-850 transition-all">
                                                        <User className="w-6 h-6 md:w-10 md:h-10 opacity-20" />
                                                        <span className="text-[6px] md:text-[8px] font-black uppercase tracking-tighter">Add</span>
                                                    </button>
                                                )}
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        </div>

                        {/* Action Buttons */}
                        <div className="p-4 sm:p-8 bg-stone-900/50 border-t border-stone-800 shrink-0">
                            <div className="grid grid-cols-2 gap-4 max-w-xl mx-auto">
                                <button onClick={handleStartAutoExpedition} disabled={party.length === 0 || isOngoingManual || !isFloorCleared} className={`flex flex-col items-center justify-center gap-1 py-3 sm:py-5 rounded-xl border-b-4 transition-all shadow-xl ${party.length > 0 && !isOngoingManual && isFloorCleared ? 'bg-indigo-700 hover:bg-indigo-600 border-indigo-900 text-white' : 'bg-stone-800 text-stone-600 border-stone-900 opacity-60'}`}>
                                    <div className="flex items-center gap-2">{!isFloorCleared ? <Lock className="w-4" /> : <Timer className="w-5" />}<span className="font-black uppercase text-xs sm:text-sm">Strategic Deploy</span></div>
                                    <span className="text-[7px] sm:text-[9px] font-bold opacity-60 uppercase">{isFloorCleared ? "Auto Expedition" : "Requires Manual Clear"}</span>
                                </button>
                                <button onClick={handleStartManualAssault} disabled={party.length === 0 && !isOngoingManual} className={`flex flex-col items-center justify-center gap-1 py-3 sm:py-5 rounded-xl border-b-4 transition-all shadow-xl ${party.length > 0 || isOngoingManual ? 'bg-amber-600 hover:bg-amber-500 border-amber-800 text-white' : 'bg-stone-800 text-stone-600 border-stone-900 opacity-60'}`}><div className="flex items-center gap-2"><Gamepad2 className="w-5" /><span className="font-black uppercase text-xs sm:text-sm">{isOngoingManual ? 'Resume' : 'Direct Assault'}</span></div><span className="text-[7px] sm:text-[9px] font-bold opacity-60 uppercase">Manual Exploration</span></button>
                            </div>
                        </div>
                    </div>
                )}
            </div>

            {/* UNIT PICKER MODAL */}
            {isPickerOpen && (
                <div className="fixed inset-0 z-[1000] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-in fade-in duration-200">
                    <div className="bg-stone-900 border-2 border-stone-700 rounded-3xl w-full max-w-2xl max-h-[80vh] flex flex-col shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
                        <div className="p-4 border-b border-stone-800 bg-stone-850 flex justify-between items-center shrink-0">
                            <div className="flex items-center gap-3">
                                <div className="bg-amber-900/30 p-2 rounded-xl border border-amber-700/50"><User className="w-5 h-5 text-amber-500" /></div>
                                <div>
                                    <h3 className="text-lg font-black text-stone-100 font-serif uppercase">Select Squad Member</h3>
                                    <p className="text-[10px] text-stone-500 font-black uppercase">Assign available units to the squad</p>
                                </div>
                            </div>
                            <button onClick={() => setIsPickerOpen(false)} className="p-2 hover:bg-stone-800 rounded-full text-stone-500 transition-colors"><X className="w-6 h-6" /></button>
                        </div>
                        <div className="flex-1 overflow-y-auto p-4 space-y-2 custom-scrollbar bg-stone-950/40">
                            {availableCandidates.length === 0 ? (
                                <div className="flex flex-col items-center justify-center py-20 opacity-20"><Search className="w-16 h-16 mb-4" /><p className="font-black uppercase text-sm tracking-widest">No candidates available</p></div>
                            ) : (
                                availableCandidates.map(merc => {
                                    const isBusy = activeExpeditions.some(e => e.partyIds.includes(merc.id)) || (activeManualDungeon?.partyIds.includes(merc.id));
                                    const power = calculateMercenaryPower(merc);
                                    const energy = merc.expeditionEnergy || 0;
                                    const hpPer = (merc.currentHp / merc.maxHp) * 100;

                                    return (
                                        <button key={merc.id} onClick={() => !isBusy && toggleMercenary(merc.id)} disabled={isBusy} className={`w-full flex items-center justify-between p-3 rounded-xl border transition-all ${isBusy ? 'bg-stone-950 border-stone-900 opacity-40 grayscale cursor-not-allowed' : 'bg-stone-800 border-stone-700 hover:border-amber-500 hover:bg-stone-750 shadow-lg'}`}>
                                            <div className="flex items-center gap-4 min-w-0">
                                                <div className="text-4xl">{merc.icon}</div>
                                                <div className="text-left">
                                                    <div className="font-black text-stone-100 text-sm md:text-base truncate">{merc.name}</div>
                                                    <div className="flex items-center gap-2 mt-0.5">
                                                        <span className="text-[9px] font-black text-stone-500 uppercase tracking-widest">{merc.job} • Lv.{merc.level}</span>
                                                        <div className="flex items-center gap-1 text-[10px] text-amber-500 font-mono font-bold border-l border-stone-700 pl-2"><Sword className="w-3 h-3" /> {power}</div>
                                                    </div>
                                                </div>
                                            </div>
                                            <div className="flex flex-col items-end gap-1.5">
                                                {isBusy ? <span className="text-[8px] font-black uppercase text-stone-600 bg-stone-900 px-2 py-0.5 rounded border border-white/5">On Mission</span> : (
                                                    <div className="flex flex-col items-end gap-1">
                                                        <div className="flex items-center gap-2">
                                                            <div className="w-16 h-1.5 bg-stone-950 rounded-full border border-stone-700 overflow-hidden"><div className={`h-full rounded-full ${energy >= energyCostForFloor ? 'bg-blue-500' : 'bg-red-600 animate-pulse'}`} style={{ width: `${energy}%` }} /></div>
                                                            <Zap className={`w-3 h-3 ${energy >= energyCostForFloor ? 'text-blue-400' : 'text-red-500 animate-pulse'}`} />
                                                        </div>
                                                        <div className="flex items-center gap-2">
                                                            <div className="w-16 h-1.5 bg-stone-950 rounded-full border border-stone-700 overflow-hidden"><div className={`h-full rounded-full ${hpPer < 30 ? 'bg-red-500 animate-pulse' : 'bg-red-600'}`} style={{ width: `${hpPer}%` }} /></div>
                                                            <span className="text-[8px] font-black text-stone-500 uppercase">HP</span>
                                                        </div>
                                                    </div>
                                                )}
                                            </div>
                                        </button>
                                    );
                                })
                            )}
                        </div>
                        <div className="p-4 bg-stone-900 border-t border-stone-800 text-center"><p className="text-[9px] text-stone-600 font-black uppercase tracking-widest">Squad Strength relies on matching equipment and attributes.</p></div>
                    </div>
                </div>
            )}

            <ConfirmationModal isOpen={!!showRecallConfirm} title="Abort Mission?" message="Recalling the squad now will forfeit all progress and potential loot. Continue?" confirmLabel="Confirm Recall" cancelLabel="Stay Deployed" isDanger onConfirm={() => { if(showRecallConfirm==='AUTO') actions.abortExpedition(currentExpedition!.id); else actions.retreatFromManualDungeon(); setShowRecallConfirm(null); }} onCancel={() => setShowRecallConfirm(null)} />
        </div>
    );
};

export default DungeonTab;

import { useState, useMemo, useEffect } from 'react';
import { useGame } from '../../../context/GameContext';
import { DUNGEONS } from '../../../data/dungeons';
import { calculatePartyPower, calculateMercenaryPower } from '../../../utils/combatLogic';
import { Skull, Timer, Zap, ChevronRight, ChevronLeft, Lock, CheckCircle, Trophy, User, XCircle, Box, AlertCircle, Gamepad2, Ban, Layers, X, Search, Sword, LayoutList, Users } from 'lucide-react';
import { getAssetUrl, formatDuration } from '../../../utils';
import AssaultNavigator from './AssaultNavigator';
import ConfirmationModal from '../../modals/ConfirmationModal';

const DungeonTab = () => {
    const { state, actions } = useGame();
    const { activeExpeditions, knownMercenaries, dungeonClearCounts, maxFloorReached, activeManualDungeon, showManualDungeonOverlay } = state;

    // View State
    const [view, setView] = useState<'LIST' | 'DETAIL'>('LIST');
    const [selectedDungeonId, setSelectedDungeonId] = useState<string | null>(null);
    const [selectedFloor, setSelectedFloor] = useState(1);
    const [party, setParty] = useState<string[]>([]);
    const [failedMercs, setFailedMercs] = useState<string[]>([]);
    const [lowHpMercs, setLowHpMercs] = useState<string[]>([]);
    const [failedPowerHighlight, setFailedPowerHighlight] = useState(false);
    const [showRecallConfirm, setShowRecallConfirm] = useState<'AUTO' | 'MANUAL' | null>(null);

    // Picker Modal State
    const [isPickerOpen, setIsPickerOpen] = useState(false);

    const selectedDungeon = useMemo(() => 
        DUNGEONS.find(d => d.id === selectedDungeonId) || DUNGEONS[0], 
    [selectedDungeonId]);

    const maxPartySize = selectedDungeon.maxPartySize || 4;
    const isOngoingManual = !!activeManualDungeon && activeManualDungeon.dungeonId === selectedDungeon.id;
    const currentExpedition = activeExpeditions.find(e => e.dungeonId === selectedDungeon.id);
    const hasActiveMission = !!currentExpedition || isOngoingManual;

    const isFloorCleared = useMemo(() => {
        const maxReached = maxFloorReached[selectedDungeon.id] || 1;
        if (selectedFloor < maxReached) return true;
        if (selectedFloor === selectedDungeon.maxFloors && (dungeonClearCounts[selectedDungeon.id] || 0) > 0) return true;
        return false;
    }, [selectedDungeon, selectedFloor, maxFloorReached, dungeonClearCounts]);

    const hiredMercs = useMemo(() => 
        knownMercenaries.filter(m => m.status === 'HIRED' || m.status === 'ON_EXPEDITION' || m.status === 'INJURED'), 
    [knownMercenaries]);

    // Candidates for the list/picker (Not already in party)
    const availableCandidates = useMemo(() => 
        hiredMercs.filter(m => !party.includes(m.id)),
    [hiredMercs, party]);

    const requiredPowerForFloor = useMemo(() => {
        const base = selectedDungeon.requiredPower;
        return Math.round(base * (1 + (selectedFloor - 1) * 0.25));
    }, [selectedDungeon, selectedFloor]);

    const energyCostForFloor = useMemo(() => {
        const base = selectedDungeon.energyCost;
        return base + (selectedFloor - 1) * 5;
    }, [selectedDungeon, selectedFloor]);

    const handleDungeonSelect = (id: string) => {
        const dungeon = DUNGEONS.find(d => d.id === id);
        if (!dungeon || dungeon.tier > state.stats.tierLevel + 1) {
            actions.showToast("This area is currently inaccessible.");
            return;
        }
        setSelectedDungeonId(id);
        setSelectedFloor(1);
        setParty([]);
        setView('DETAIL');
    };

    const handlePrevFloor = () => setSelectedFloor(prev => Math.max(1, prev - 1));
    const handleNextFloor = () => {
        const maxReached = maxFloorReached[selectedDungeon.id] || 1;
        if (selectedFloor >= selectedDungeon.maxFloors) return;
        if (selectedFloor >= maxReached) {
            actions.showToast("You must clear the current floor to descend deeper.");
            return;
        }
        setSelectedFloor(prev => Math.min(selectedDungeon.maxFloors, prev + 1));
    };

    const toggleMercenary = (mercId: string) => {
        if (party.includes(mercId)) {
            setParty(prev => prev.filter(id => id !== mercId));
        } else if (party.length < maxPartySize) {
            setParty(prev => [...prev, mercId]);
            setIsPickerOpen(false);
        }
    };

    const validateEntry = () => {
        if (party.length === 0) return false;
        const selectedMercs = knownMercenaries.filter(m => party.includes(m.id));

        const lowHpIds = selectedMercs.filter(m => (m.currentHp || 0) < 1).map(m => m.id);
        if (lowHpIds.length > 0) {
            setLowHpMercs(lowHpIds);
            setTimeout(() => setLowHpMercs([]), 2000);
            actions.showToast("Wounded members cannot be deployed.");
            return false;
        }

        const lowEnergyIds = selectedMercs.filter(m => (m.expeditionEnergy || 0) < energyCostForFloor).map(m => m.id);
        if (lowEnergyIds.length > 0) {
            setFailedMercs(lowEnergyIds);
            setTimeout(() => setFailedMercs([]), 2000);
            actions.showToast("Some squad members are too exhausted.");
            return false;
        }

        if (currentPartyPower < requiredPowerForFloor) {
            setFailedPowerHighlight(true);
            setTimeout(() => setFailedPowerHighlight(false), 2000);
            actions.showToast("Party power is insufficient for this floor.");
            return false;
        }
        return true;
    };

    const handleStartAutoExpedition = () => {
        if (!isFloorCleared) { actions.showToast("Manual clear required."); return; }
        if (isOngoingManual) return actions.showToast("Manual assault active.");
        if (!validateEntry()) return;
        actions.startExpedition(selectedDungeon.id, party);
    };

    const handleStartManualAssault = () => {
        if (isOngoingManual) { actions.toggleManualDungeonOverlay(true); return; }
        if (!validateEntry()) return;
        actions.startManualAssault(selectedDungeon.id, party, selectedFloor);
    };

    const currentPartyPower = useMemo(() => {
        const selectedMercs = knownMercenaries.filter(m => party.includes(m.id));
        return calculatePartyPower(selectedMercs);
    }, [party, knownMercenaries]);

    const [timeLeft, setTimeLeft] = useState<string>('');
    useEffect(() => {
        if (!currentExpedition || currentExpedition.status === 'COMPLETED') {
            setTimeLeft(currentExpedition?.status === 'COMPLETED' ? '00:00' : '');
            return;
        }
        const interval = setInterval(() => {
            const diff = currentExpedition.endTime - Date.now();
            if (diff <= 0) setTimeLeft('00:00');
            else setTimeLeft(formatDuration(diff));
        }, 1000);
        return () => clearInterval(interval);
    }, [currentExpedition]);

    // --- RENDER: LIST VIEW ---
    if (view === 'LIST') {
        return (
            <div className="h-full w-full bg-stone-950 flex flex-col p-4 md:p-8 animate-in fade-in duration-500 overflow-hidden">
                <div className="flex justify-between items-end border-b border-stone-800 pb-4 mb-6 shrink-0">
                    <div>
                        <h2 className="text-2xl md:text-4xl font-black text-amber-50 font-serif uppercase tracking-tighter">Tactical Deployment</h2>
                        <p className="text-stone-500 text-[10px] md:text-xs font-bold uppercase tracking-[0.2em] mt-1">Select Engagement Zone</p>
                    </div>
                    <div className="flex items-center gap-2 bg-stone-900 px-3 py-1.5 rounded-lg border border-stone-800 text-[10px] font-mono text-stone-500">
                        <LayoutList className="w-3.5 h-3.5" /> Sector Overview
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar pr-2 space-y-4">
                    {DUNGEONS.map(d => {
                        const isLocked = d.tier > state.stats.tierLevel + 1;
                        const maxReached = maxFloorReached[d.id] || 1;
                        const progressPercent = (maxReached / d.maxFloors) * 100;
                        return (
                            <button key={d.id} onClick={() => handleDungeonSelect(d.id)} className={`w-full group relative flex flex-col md:flex-row items-center gap-4 p-4 md:p-6 rounded-2xl border-2 transition-all overflow-hidden ${isLocked ? 'bg-stone-900 border-stone-800 opacity-50 grayscale' : 'bg-stone-900/40 border-stone-800 hover:border-amber-500 hover:bg-stone-800 shadow-xl active:scale-[0.99]'}`}>
                                <div className="w-20 h-20 md:w-32 md:h-32 bg-stone-950 rounded-xl border-2 border-stone-800 flex items-center justify-center text-4xl md:text-6xl shrink-0 shadow-inner group-hover:scale-105 transition-transform duration-500">
                                    {isLocked ? <Lock className="w-8 h-8 text-stone-700" /> : (d.id.includes('rat') ? '🐀' : d.id.includes('goblin') ? '👺' : d.id.includes('mine') ? '⛏️' : '🏰')}
                                </div>
                                <div className="flex-1 text-center md:text-left min-w-0">
                                    <div className="flex flex-col md:flex-row md:items-center gap-2 mb-1">
                                        <h3 className="text-lg md:text-2xl font-black text-stone-100 uppercase font-serif tracking-tight">{d.name}</h3>
                                        <span className={`w-fit mx-auto md:mx-0 px-2 py-0.5 rounded font-black text-[8px] md:text-[10px] uppercase border ${isLocked ? 'border-stone-700 text-stone-600' : 'border-amber-600/30 bg-amber-900/20 text-amber-500'}`}>Tier {d.tier}</span>
                                    </div>
                                    <p className="text-stone-500 text-[10px] md:text-sm line-clamp-2 italic mb-3">"{d.description}"</p>
                                    <div className="flex flex-wrap justify-center md:justify-start gap-4">
                                        <div className="flex items-center gap-2"><Layers className="w-3.5 h-3.5 text-stone-600" /><span className="text-[10px] md:text-xs font-black text-stone-400 uppercase">Progression: <span className="text-amber-500">{maxReached}/{d.maxFloors} Floors</span></span></div>
                                        <div className="flex items-center gap-2"><Skull className="w-3.5 h-3.5 text-stone-600" /><span className="text-[10px] md:text-xs font-black text-stone-400 uppercase">Threat: <span className="text-red-500">POW {d.requiredPower}</span></span></div>
                                    </div>
                                    <div className="mt-3 w-full h-1.5 bg-stone-950 rounded-full overflow-hidden border border-stone-800 shadow-inner"><div className="h-full bg-gradient-to-r from-amber-900 to-amber-500 transition-all duration-1000" style={{ width: `${progressPercent}%` }}></div></div>
                                </div>
                                <div className="absolute top-4 right-4 md:relative md:top-0 md:right-0">
                                    {isLocked ? <Lock className="w-6 h-6 text-stone-800" /> : <ChevronRight className="w-6 h-6 text-stone-700 group-hover:text-amber-500 group-hover:translate-x-1 transition-all" />}
                                </div>
                            </button>
                        );
                    })}
                </div>
            </div>
        );
    }

    // --- RENDER: DETAIL VIEW ---
    return (
        <div className="h-full w-full flex flex-col sm:flex-row bg-stone-950 text-stone-200 overflow-hidden font-sans relative">
            {(!!activeManualDungeon && showManualDungeonOverlay) && <AssaultNavigator />}

            {/* Left Info Section */}
            <div className="w-full sm:w-[40%] h-[35%] sm:h-full flex flex-col border-b sm:border-b-0 sm:border-r border-stone-800 bg-stone-900/50 relative overflow-hidden shrink-0 min-h-0">
                <div className="absolute inset-0 opacity-10 pointer-events-none"><img src={getAssetUrl('dungeon_bg.png')} className="w-full h-full object-cover grayscale" /></div>
                <div className="flex-1 flex flex-col items-center z-10 min-h-0">
                    <button onClick={() => setView('LIST')} className="absolute top-3 left-3 z-30 flex items-center gap-1.5 px-3 py-1.5 bg-stone-800 hover:bg-stone-700 rounded-lg border border-stone-700 text-stone-400 text-[10px] font-black uppercase transition-all shadow-xl active:scale-95"><ChevronLeft className="w-3.5 h-3.5" /> Back</button>
                    <div className="relative flex flex-col items-center pt-8 sm:pt-14 shrink-0 w-full">
                        <div className="h-12 sm:h-20 flex flex-col items-center justify-center text-center px-10 mb-1 sm:mb-2">
                            <h1 className="text-lg sm:text-2xl lg:text-3xl font-black text-white font-serif tracking-tighter uppercase leading-none">{selectedDungeon.name}</h1>
                            <div className="mt-1 px-3 py-0.5 rounded-full bg-amber-900/30 border border-amber-600/30 text-amber-500 text-[8px] font-black uppercase tracking-widest">Tier {selectedDungeon.tier}</div>
                        </div>
                        <div className="relative w-full flex items-center justify-center h-20 sm:h-44 mb-2 sm:mb-6">
                            <button onClick={handlePrevFloor} className={`absolute left-4 z-30 p-2 sm:p-5 rounded-full border transition-all active:scale-90 ${selectedFloor > 1 ? 'bg-stone-800 hover:bg-amber-600 border-stone-700 text-white' : 'bg-stone-900 border-stone-850 text-stone-800 opacity-20 cursor-not-allowed'}`}><ChevronLeft className="w-5 h-5 sm:w-10 sm:h-10" /></button>
                            <div className="relative group animate-in fade-in zoom-in duration-300">
                                <div className="w-16 h-16 sm:w-36 lg:w-44 sm:h-36 lg:h-44 bg-stone-900 rounded-2xl sm:rounded-[2rem] border-2 sm:border-4 border-stone-700 flex flex-col items-center justify-center relative shadow-2xl ring-4 ring-white/5">
                                     <div className="text-[8px] sm:text-[10px] font-black text-stone-600 uppercase">Floor</div>
                                     <div className="text-3xl sm:text-7xl lg:text-8xl font-black text-white font-mono leading-none">{selectedFloor}</div>
                                </div>
                                {selectedFloor === selectedDungeon.maxFloors && <div className="absolute -top-2 -right-2 px-2 py-0.5 bg-red-600 border border-red-400 rounded-lg text-white font-black text-[8px] sm:text-[10px] shadow-2xl rotate-12 z-40">BOSS</div>}
                            </div>
                            <button onClick={handleNextFloor} className={`absolute right-4 z-30 p-2 sm:p-5 rounded-full border transition-all active:scale-90 ${selectedFloor < selectedDungeon.maxFloors ? 'bg-stone-800 hover:bg-amber-600 border-stone-700 text-white' : 'bg-stone-900 border-stone-850 text-stone-800 opacity-20 cursor-not-allowed'}`}><ChevronRight className="w-5 h-5 sm:w-10 sm:h-10" /></button>
                        </div>
                    </div>
                    <div className="flex-1 overflow-y-auto custom-scrollbar p-1 sm:p-8 pt-0 z-10 flex flex-col items-center min-h-0 w-full">
                        <div className="bg-stone-950/40 p-2 sm:p-4 rounded-xl border border-stone-800/50 w-full max-w-[280px]">
                            <div className="flex items-center justify-center gap-1.5 mb-2"><Box className="w-3 h-3 text-stone-600" /><h4 className="text-[9px] sm:text-xs font-black text-stone-500 uppercase tracking-widest">Potential Rewards</h4></div>
                            <div className="flex wrap justify-center gap-2 sm:gap-3">
                                {selectedDungeon.rewards.map((reward, ridx) => (
                                    <div key={`${reward.itemId}-${ridx}`} className="w-8 h-8 md:w-12 md:h-12 bg-stone-900 border border-stone-800 rounded-lg flex items-center justify-center shadow-inner group">
                                        <img src={getAssetUrl(`${reward.itemId}.png`)} className="w-6 h-6 md:w-8 md:h-8 object-contain" onError={e=>e.currentTarget.style.display='none'} />
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Right Squad & Action Section */}
            <div className="flex-1 flex flex-col bg-stone-925 relative overflow-hidden min-h-0 min-w-0">
                {hasActiveMission ? (
                    <div className="flex-1 flex flex-col items-center justify-center p-6 sm:p-12 text-center animate-in fade-in duration-700">
                        <Trophy className={`w-12 h-12 sm:w-28 mb-8 ${currentExpedition?.status === 'COMPLETED' ? 'text-emerald-500 animate-bounce' : 'text-stone-800 opacity-30'}`} />
