                    </div>
                ) : (
                    <div className="flex-1 flex flex-col overflow-hidden">
                        {/* Stats Bar */}
                        <div className="p-2 sm:p-4 bg-stone-900/80 border-b border-stone-800 grid grid-cols-3 gap-2 sm:gap-4 shrink-0">
                            <div className="bg-stone-950 p-2 sm:p-4 rounded-xl border border-stone-800 flex flex-col items-center justify-center">
                                <span className="text-[8px] sm:text-[10px] text-stone-500 font-black uppercase mb-0.5">Time</span>
                                <div className="text-xs sm:text-xl font-black text-stone-200 font-mono">{selectedDungeon.durationMinutes}m</div>
                            </div>
                            <div className="bg-stone-950 p-2 sm:p-4 rounded-xl border border-stone-800 flex flex-col items-center justify-center">
                                <span className="text-[8px] sm:text-[10px] text-stone-500 font-black uppercase mb-0.5">Energy</span>
                                <div className="text-xs sm:text-xl font-black text-blue-400 font-mono">-{energyCostForFloor}</div>
                            </div>
                            <div className={`bg-stone-950 p-2 sm:p-4 rounded-xl border flex flex-col items-center justify-center transition-all ${failedPowerHighlight ? 'border-red-500 ring-2 ring-red-500/50 animate-shake-hard' : 'border-stone-800'}`}>
                                <span className="text-[8px] sm:text-[10px] text-stone-500 font-black uppercase mb-0.5">Req. Power</span>
                                <div className={`text-xs sm:text-xl font-black font-mono ${currentPartyPower >= requiredPowerForFloor ? 'text-emerald-400' : 'text-red-500'}`}>{currentPartyPower} / {requiredPowerForFloor}</div>
                            </div>
                        </div>

                        {/* Squad Assembly Area - Tightened height to match inner sub-div exactly */}
                        <div className="shrink-0 p-4 sm:p-6 bg-stone-900/20 border-b border-stone-800">
                            <div className="w-full max-w-xl mx-auto h-fit">
                                <div className="flex justify-between items-end px-2 mb-3">
                                    <h3 className="text-[10px] sm:text-xs font-black text-stone-500 uppercase tracking-widest">Squad Assembly</h3>
                                    <span className="text-[10px] font-mono text-stone-600">{party.length} / {maxPartySize}</span>
                                </div>
                                <div className="grid grid-cols-4 gap-2 md:gap-4">
                                    {Array.from({ length: 4 }).map((_, idx) => {
                                        const isAvailable = idx < maxPartySize;
                                        const mercId = party[idx];
                                        const merc = knownMercenaries.find(m => m.id === mercId);
                                        const hasError = mercId && (failedMercs.includes(mercId) || lowHpMercs.includes(mercId));

                                        if (!isAvailable) return <div key={idx} className="aspect-square bg-stone-950/60 border-2 border-stone-900 rounded-xl md:rounded-2xl flex items-center justify-center grayscale"><Ban className="w-6 md:w-8 text-stone-800" /></div>;

                                        return (
                                            <div key={idx} className={`aspect-square bg-stone-900 border-2 rounded-xl md:rounded-2xl flex items-center justify-center relative shadow-2xl overflow-hidden group hover:bg-stone-850 transition-all ${hasError ? 'border-red-600 animate-shake-hard' : 'border-dashed border-stone-800'}`}>
                                                {!!merc ? (
