                                                            <span className="text-[8px] font-black text-stone-500 uppercase tracking-widest">Lv.{merc.level}</span>
                                                            <div className="flex items-center gap-1 text-[9px] text-amber-500 font-mono font-bold border-l border-stone-700 pl-1.5"><Sword className="w-2.5 h-2.5" /> {power}</div>
                                                        </div>
