                    </div>
                ) : (
                    <div className="flex-1 flex flex-col overflow-hidden">
                        {/* Stats Bar - Condensed to one line */}
                        <div className="p-2.5 bg-stone-900/90 border-b border-stone-800 flex items-center justify-around shrink-0 gap-4">
                            <div className="flex items-center gap-1.5">
                                <Timer className="w-3.5 h-3.5 text-stone-500" />
                                <span className="text-[10px] md:text-sm font-mono font-black text-stone-200">{selectedDungeon.durationMinutes}m</span>
                            </div>
                            <div className="flex items-center gap-1.5">
                                <Zap className="w-3.5 h-3.5 text-blue-500" />
                                <span className="text-[10px] md:text-sm font-mono font-black text-blue-400">-{energyCostForFloor}</span>
                            </div>
                            <div className={`flex items-center gap-1.5 transition-all ${failedPowerHighlight ? 'animate-shake-hard' : ''}`}>
                                <Sword className={`w-3.5 h-3.5 ${currentPartyPower >= requiredPowerForFloor ? 'text-emerald-500' : 'text-red-500'}`} />
                                <span className={`text-[10px] md:text-sm font-mono font-black ${currentPartyPower >= requiredPowerForFloor ? 'text-emerald-400' : 'text-red-500'}`}>
                                    {currentPartyPower} <span className="text-stone-600">/ {requiredPowerForFloor}</span>
